def _format_utc_iso_text(value: datetime) -> str:
    value_utc = value.astimezone(timezone.utc).replace(microsecond=0)
    return value_utc.isoformat().replace("+00:00", "Z")


def _format_duration_compact(seconds: float | None) -> str:
    """Render a short elapsed/ETA label for the run monitor."""
    if seconds is None or not np.isfinite(float(seconds)) or float(seconds) < 0.0:
        return "--"
    total = int(round(float(seconds)))
    hours, rem = divmod(total, 3600)
    minutes, secs = divmod(rem, 60)
    if hours > 0:
        return f"{hours:d}:{minutes:02d}:{secs:02d}"
    return f"{minutes:02d}:{secs:02d}"


def _format_bytes_compact(value: Any) -> str:
    try:
        numeric = float(value)
    except Exception:
        return "--"
    if not np.isfinite(numeric) or numeric < 0.0:
        return "--"
    units = ("B", "KB", "MB", "GB", "TB")
    unit_index = 0
    while numeric >= 1024.0 and unit_index < (len(units) - 1):
        numeric /= 1024.0
        unit_index += 1
    if unit_index == 0:
        return f"{int(numeric)} {units[unit_index]}"
    if numeric >= 100.0:
        return f"{numeric:.0f} {units[unit_index]}"
    if numeric >= 10.0:
        return f"{numeric:.1f} {units[unit_index]}"
    return f"{numeric:.2f} {units[unit_index]}"


def _parse_utc_iso_text(text: str) -> datetime:
    value = str(text).strip()
    if not value:
        raise ValueError("UTC timestamp is required.")
    try:
        parsed = datetime.fromisoformat(value.replace("Z", "+00:00"))
    except ValueError as exc:
        raise ValueError(f"Invalid UTC timestamp {text!r}.") from exc
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc).replace(microsecond=0)


def _utc_iso_text_to_qdatetime(text: str) -> QtCore.QDateTime:
    parsed = _parse_utc_iso_text(text)
    return QtCore.QDateTime(
        QtCore.QDate(parsed.year, parsed.month, parsed.day),
        QtCore.QTime(parsed.hour, parsed.minute, parsed.second),
        _UTC_TIMEZONE,
    )


def _qdatetime_to_utc_iso_text(value: QtCore.QDateTime) -> str:
    return _format_utc_iso_text(
        datetime.fromtimestamp(int(value.toSecsSinceEpoch()), tz=timezone.utc)
    )


def _build_painted_icon(
    size: int,
    draw_fn: Callable[[QtGui.QPainter, QtCore.QRectF], None],
) -> QtGui.QIcon:
    pixmap = QtGui.QPixmap(size, size)
    pixmap.fill(QtCore.Qt.transparent)
    painter = QtGui.QPainter(pixmap)
    painter.setRenderHint(QtGui.QPainter.Antialiasing, True)
    draw_fn(painter, QtCore.QRectF(0.0, 0.0, float(size), float(size)))
    painter.end()
    return QtGui.QIcon(pixmap)


def _load_gui_svg_icon(name: str) -> QtGui.QIcon:
    cached = _GUI_ICON_CACHE.get(name)
    if cached is not None:
        return cached
    filename = _GUI_ICON_FILES.get(name)
    if not filename:
        return QtGui.QIcon()
    path = _DATA_ASSET_DIR / filename
    icon = QtGui.QIcon(str(path)) if path.exists() else QtGui.QIcon()
    _GUI_ICON_CACHE[name] = icon
    return icon


def _brand_mark_pixmap(size: int) -> QtGui.QPixmap:
    icon = _load_gui_svg_icon("brand_mark")
    if icon.isNull():
        icon = _load_app_icon()
    return icon.pixmap(int(size), int(size))


def _build_pin_icon(*, color: str = "#dbeafe", pinned: bool = False) -> QtGui.QIcon:
    """Create a bold pin icon for the collapsible side rails."""

    icon = _load_gui_svg_icon("control_pinned" if pinned else "control_pin")
    if not icon.isNull():
        return icon

    def _draw(painter: QtGui.QPainter, rect: QtCore.QRectF) -> None:
        accent = QtGui.QColor(color)
        core = QtGui.QColor("#07111f")
        painter.translate(rect.center())
        painter.rotate(-22 if pinned else -10)
        painter.translate(-rect.center())
        pen = QtGui.QPen(accent)
        pen.setWidthF(2.0)
        pen.setCapStyle(QtCore.Qt.RoundCap)
        pen.setJoinStyle(QtCore.Qt.RoundJoin)
        painter.setPen(pen)
        painter.setBrush(accent if pinned else QtGui.QColor(core))
        head = QtGui.QPolygonF(
            [
                QtCore.QPointF(10.0, 3.4),
                QtCore.QPointF(15.8, 9.2),
                QtCore.QPointF(10.0, 15.0),
                QtCore.QPointF(4.2, 9.2),
            ]
        )
        painter.drawPolygon(head)
        painter.drawLine(QtCore.QPointF(10.0, 12.4), QtCore.QPointF(10.0, 19.4))
        painter.drawLine(QtCore.QPointF(10.0, 19.4), QtCore.QPointF(8.0, 21.8))

    return _build_painted_icon(24, _draw)


