def _build_workspace_icon(kind: str) -> QtGui.QIcon:
    """Create cohesive workspace navigation icons."""

    icon = _load_gui_svg_icon(f"workspace_{str(kind).strip().lower()}")
    if not icon.isNull():
        return icon

    def _draw(painter: QtGui.QPainter, rect: QtCore.QRectF) -> None:
        painter.setPen(QtCore.Qt.NoPen)
        glow = QtGui.QRadialGradient(rect.center(), rect.width() * 0.48)
        glow.setColorAt(0.0, QtGui.QColor(59, 130, 246, 58))
        glow.setColorAt(1.0, QtGui.QColor(59, 130, 246, 0))
        painter.setBrush(glow)
        painter.drawEllipse(QtCore.QRectF(2.0, 2.0, rect.width() - 4.0, rect.height() - 4.0))

        primary = QtGui.QPen(QtGui.QColor("#e0f2fe"))
        primary.setWidthF(1.8)
        primary.setCapStyle(QtCore.Qt.RoundCap)
        primary.setJoinStyle(QtCore.Qt.RoundJoin)
        accent_pen = QtGui.QPen(QtGui.QColor("#38bdf8"))
        accent_pen.setWidthF(1.8)
        accent_pen.setCapStyle(QtCore.Qt.RoundCap)
        accent_pen.setJoinStyle(QtCore.Qt.RoundJoin)

        if kind == "home":
            painter.setPen(primary)
            painter.setBrush(QtGui.QColor(14, 165, 233, 36))
            roof = QtGui.QPolygonF(
                [
                    QtCore.QPointF(4.5, 11.0),
                    QtCore.QPointF(12.0, 4.5),
                    QtCore.QPointF(19.5, 11.0),
                ]
            )
            painter.drawPolyline(roof)
            painter.drawRoundedRect(QtCore.QRectF(6.4, 10.8, 11.2, 8.0), 2.4, 2.4)
            painter.drawLine(QtCore.QPointF(11.9, 12.3), QtCore.QPointF(11.9, 18.5))
            painter.setPen(accent_pen)
            painter.drawLine(QtCore.QPointF(7.2, 19.2), QtCore.QPointF(16.8, 19.2))
            return

        if kind == "simulation":
            painter.setPen(primary)
            painter.drawEllipse(QtCore.QRectF(4.0, 6.2, 16.0, 11.6))
            painter.drawArc(QtCore.QRectF(6.0, 3.8, 12.0, 16.4), 20 * 16, 140 * 16)
            painter.setBrush(QtGui.QColor("#38bdf8"))
            painter.setPen(QtCore.Qt.NoPen)
            painter.drawEllipse(QtCore.QRectF(10.0, 10.0, 4.0, 4.0))
            painter.drawRoundedRect(QtCore.QRectF(15.8, 5.4, 3.6, 3.6), 1.0, 1.0)
            painter.setPen(accent_pen)
            painter.drawLine(QtCore.QPointF(17.6, 9.0), QtCore.QPointF(15.2, 11.2))
            painter.drawLine(QtCore.QPointF(17.6, 9.0), QtCore.QPointF(19.8, 11.0))
            return

        if kind == "postprocess":
            painter.setPen(primary)
            dome = QtCore.QRectF(4.5, 7.0, 15.0, 10.2)
            painter.drawArc(dome, 0, 180 * 16)
            painter.drawLine(QtCore.QPointF(4.8, 12.1), QtCore.QPointF(19.2, 12.1))
            painter.drawArc(QtCore.QRectF(6.8, 8.2, 10.4, 8.0), 0, 180 * 16)
            painter.drawLine(QtCore.QPointF(12.0, 7.1), QtCore.QPointF(12.0, 17.0))
            painter.setPen(accent_pen)
            painter.drawArc(QtCore.QRectF(6.2, 4.5, 13.2, 10.8), 205 * 16, 105 * 16)
            painter.setBrush(QtGui.QColor("#38bdf8"))
            painter.setPen(QtCore.Qt.NoPen)
            painter.drawEllipse(QtCore.QRectF(16.1, 6.0, 3.4, 3.4))
            painter.drawEllipse(QtCore.QRectF(8.1, 13.6, 2.8, 2.8))
            painter.setPen(QtGui.QPen(QtGui.QColor("#7dd3fc"), 1.3))
            painter.drawLine(QtCore.QPointF(17.8, 8.8), QtCore.QPointF(15.2, 10.6))
            return

        painter.setPen(primary)
        painter.drawEllipse(QtCore.QRectF(5.0, 5.0, 14.0, 14.0))

    return _build_painted_icon(24, _draw)


