class BusyOverlay(QtWidgets.QFrame):
    """Simple translucent overlay used to lock a recalculating pane."""

    def __init__(self, parent: QtWidgets.QWidget | None = None) -> None:
        super().__init__(parent)
        self.setObjectName("busyOverlay")
        self.setVisible(False)
        self.setStyleSheet(
            "#busyOverlay {"
            "background: rgba(15, 23, 42, 170);"
            "border: 1px solid rgba(148, 163, 184, 120);"
            "border-radius: 10px;"
            "}"
        )
        layout = QtWidgets.QVBoxLayout(self)
        layout.setContentsMargins(16, 16, 16, 16)
        layout.setSpacing(8)
        layout.addStretch(1)

        self._label = QtWidgets.QLabel("Working...", self)
        self._label.setAlignment(QtCore.Qt.AlignCenter)
        self._label.setStyleSheet("color: white; font-weight: 600;")
        layout.addWidget(self._label)

        self._sub_label = QtWidgets.QLabel("", self)
        self._sub_label.setAlignment(QtCore.Qt.AlignCenter)
        self._sub_label.setWordWrap(True)
        self._sub_label.setStyleSheet("color: #cbd5e1;")
        layout.addWidget(self._sub_label)

        self._progress = QtWidgets.QProgressBar(self)
        self._progress.setTextVisible(True)
        self._progress.hide()
        layout.addWidget(self._progress)

        layout.addStretch(1)
        if parent is not None:
            parent.installEventFilter(self)

    def eventFilter(self, watched: QtCore.QObject, event: QtCore.QEvent) -> bool:
        if watched is self.parent() and event.type() in {
            QtCore.QEvent.Resize,
            QtCore.QEvent.Show,
            QtCore.QEvent.Move,
        }:
            self._reposition()
        return super().eventFilter(watched, event)

    def _reposition(self) -> None:
        parent = self.parentWidget()
        if parent is None:
            return
        self.setGeometry(parent.rect().adjusted(8, 8, -8, -8))
        self.raise_()

    def show_busy(self, title: str, detail: str = "") -> None:
        self._label.setText(str(title))
        self._sub_label.setText(str(detail))
        self._reposition()
        self.show()
        self.raise_()

    def set_progress_indeterminate(self) -> None:
        self._progress.setRange(0, 0)
        self._progress.show()

    def set_progress_value(self, current: int, total: int) -> None:
        total_use = max(int(total), 1)
        current_use = min(max(int(current), 0), total_use)
        self._progress.setRange(0, total_use)
        self._progress.setValue(current_use)
        self._progress.show()

    def hide_busy(self) -> None:
        self._progress.hide()
        self.hide()


class SimulationTabWidget(QtWidgets.QTabWidget):
    """QTabWidget that preserves inner-page addressing for wrapped simulation tabs."""

    def __init__(self, parent: QtWidgets.QWidget | None = None) -> None:
        super().__init__(parent)
        self._inner_to_wrapper: dict[QtWidgets.QWidget, QtWidgets.QWidget] = {}
        self._wrapper_to_public: dict[QtWidgets.QWidget, QtWidgets.QWidget] = {}

    def register_page_wrapper(
        self,
        inner_page: QtWidgets.QWidget,
        wrapper: QtWidgets.QWidget,
        *,
        expose_inner_as_current: bool = True,
    ) -> None:
        self._inner_to_wrapper[inner_page] = wrapper
        if expose_inner_as_current:
            self._wrapper_to_public[wrapper] = inner_page
        else:
            self._wrapper_to_public.pop(wrapper, None)

    def setCurrentWidget(self, widget: QtWidgets.QWidget) -> None:  # type: ignore[override]
        super().setCurrentWidget(self._inner_to_wrapper.get(widget, widget))

    def indexOf(self, widget: QtWidgets.QWidget) -> int:  # type: ignore[override]
        return super().indexOf(self._inner_to_wrapper.get(widget, widget))

    def currentWidget(self) -> QtWidgets.QWidget | None:  # type: ignore[override]
        current = super().currentWidget()
        if current is None:
            return None
        return self._wrapper_to_public.get(current, current)


@dataclass(slots=True)
class ControlHelpDefinition:
    """User-facing help metadata for one exposed control."""

    title: str
    summary: str
    details: str = ""
    layer: str = "Basic"


class HelpPopover(QtWidgets.QWidget):
    """Dismissible anchored help popover for hybrid hover/click help.

    Uses a manual ``paintEvent`` to draw a fully opaque rounded-rect
    background so the popup reliably occludes content behind it on all
    platforms.
    """

    _BG_TOP = QtGui.QColor(37, 61, 92)       # #253d5c
    _BG_BOT = QtGui.QColor(28, 50, 80)       # #1c3250
    _BORDER = QtGui.QColor(100, 170, 255, 220)
    _RADIUS = 14.0

    def __init__(self, parent: QtWidgets.QWidget | None = None) -> None:
        super().__init__(parent, QtCore.Qt.ToolTip)
        self.setObjectName("helpPopover")
        self.setWindowFlags(
            QtCore.Qt.ToolTip
            | QtCore.Qt.FramelessWindowHint
            | QtCore.Qt.NoDropShadowWindowHint
        )
        self.setAttribute(QtCore.Qt.WA_ShowWithoutActivating, True)
        self.setAttribute(QtCore.Qt.WA_TransparentForMouseEvents, False)
        # WA_TranslucentBackground is needed so the OS window region
        # respects the rounded corners (no opaque rectangular halo).
        self.setAttribute(QtCore.Qt.WA_TranslucentBackground, True)
        self.hide()
        self._anchor_widget: QtWidgets.QWidget | None = None
        self._show_anim: QtCore.QPropertyAnimation | None = None
        self._hide_anim: QtCore.QPropertyAnimation | None = None
        self._timer = QtCore.QTimer(self)
        self._timer.setSingleShot(True)
        self._timer.timeout.connect(self.dismiss)
        layout = QtWidgets.QVBoxLayout(self)
        layout.setContentsMargins(18, 14, 18, 14)
        layout.setSpacing(6)
        title_row = QtWidgets.QHBoxLayout()
        title_row.setContentsMargins(0, 0, 0, 0)
        title_row.setSpacing(8)
        self._title_label = QtWidgets.QLabel(self)
        self._title_label.setStyleSheet(
            "background: transparent; font-weight: 700; color: #f8fafc;"
        )
        self._layer_label = QtWidgets.QLabel(self)
        self._layer_label.setStyleSheet(
            "background: rgba(59, 130, 246, 0.22); color: #bfdbfe;"
            " border-radius: 999px; padding: 2px 8px; font-size: 11px; font-weight: 700;"
        )
        title_row.addWidget(self._title_label, stretch=1)
        title_row.addWidget(self._layer_label, 0, QtCore.Qt.AlignRight)
        self._body_label = QtWidgets.QLabel(self)
        self._body_label.setWordWrap(True)
        self._body_label.setTextFormat(QtCore.Qt.RichText)
        self._body_label.setStyleSheet("background: transparent; color: #dbeafe;")
        layout.addLayout(title_row)
        layout.addWidget(self._body_label)

    def paintEvent(self, event: QtGui.QPaintEvent) -> None:
        """Draw the opaque rounded-rect background and border manually."""
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.Antialiasing, True)
        r = self.rect().adjusted(1, 1, -1, -1)
        path = QtGui.QPainterPath()
        path.addRoundedRect(QtCore.QRectF(r), self._RADIUS, self._RADIUS)
        # Gradient fill — fully opaque
        grad = QtGui.QLinearGradient(0, 0, 0, float(r.height()))
        grad.setColorAt(0.0, self._BG_TOP)
        grad.setColorAt(1.0, self._BG_BOT)
        p.fillPath(path, QtGui.QBrush(grad))
        # Border
        p.setPen(QtGui.QPen(self._BORDER, 1.5))
        p.drawPath(path)
        p.end()

    def show_for_widget(self, widget: QtWidgets.QWidget, help_def: ControlHelpDefinition) -> None:
        self._anchor_widget = widget
        self._title_label.setText(str(help_def.title))
        self._layer_label.setText(str(help_def.layer))
        body_html = (
            f"<p style='margin:0 0 6px 0; text-align:justify;'>"
            f"<b>Quick orientation.</b> {help_def.summary}</p>"
        )
        if help_def.details:
            body_html += str(help_def.details)
        self._body_label.setText(body_html)
        self.adjustSize()
        screen = QtGui.QGuiApplication.screenAt(widget.mapToGlobal(widget.rect().center()))
        available = (
            screen.availableGeometry()
            if screen is not None
            else QtWidgets.QApplication.primaryScreen().availableGeometry()
        )
        anchor = widget.mapToGlobal(QtCore.QPoint(widget.width() + 12, 0))
        x = min(anchor.x(), available.right() - self.width() - 12)
        x = max(available.left() + 12, x)
        y = widget.mapToGlobal(QtCore.QPoint(0, 0)).y()
        y = min(y, available.bottom() - self.height() - 12)
        y = max(available.top() + 12, y)
        self.move(x, y)
        # Animated show: fade in
        self.setWindowOpacity(0.0)
        self.show()
        self.raise_()
        self._stop_anim(self._show_anim)
        self._stop_anim(self._hide_anim)
        anim = QtCore.QPropertyAnimation(self, b"windowOpacity", self)
        anim.setDuration(180)
        anim.setEasingCurve(QtCore.QEasingCurve.OutCubic)
        anim.setStartValue(0.0)
        anim.setEndValue(1.0)
        anim.finished.connect(lambda: setattr(self, "_show_anim", None))
        self._show_anim = anim
        anim.start(QtCore.QAbstractAnimation.DeleteWhenStopped)
        self._timer.start(_HELP_POPOVER_TIMEOUT_MS)

    @staticmethod
    def _stop_anim(anim: QtCore.QPropertyAnimation | None) -> None:
        """Safely stop an animation that may already be deleted by Qt."""
        if anim is None:
            return
        try:
            anim.stop()
        except RuntimeError:
            pass

    def dismiss(self) -> None:
        """Animated hide: fade out then hide."""
        self._stop_anim(self._show_anim)
        self._stop_anim(self._hide_anim)
        anim = QtCore.QPropertyAnimation(self, b"windowOpacity", self)
        anim.setDuration(140)
        anim.setEasingCurve(QtCore.QEasingCurve.InCubic)
        anim.setStartValue(self.windowOpacity())
        anim.setEndValue(0.0)
        anim.finished.connect(self.hide)
        anim.finished.connect(lambda: setattr(self, "_hide_anim", None))
        self._hide_anim = anim
        anim.start(QtCore.QAbstractAnimation.DeleteWhenStopped)

    def hideEvent(self, event: QtGui.QHideEvent) -> None:
        self._timer.stop()
        self._anchor_widget = None
        super().hideEvent(event)


class RunMonitorWidget(QtWidgets.QFrame):
    """Structured GUI monitor for simulation progress and writer telemetry."""

    open_result_requested = QtCore.Signal(str)

    def __init__(self, parent: QtWidgets.QWidget | None = None) -> None:
        super().__init__(parent)
        self._last_result_filename: str | None = None
        self._last_event: dict[str, Any] | None = None
        self._detail_mode = "step"
        self._detail_current: int | None = None
