@dataclass(slots=True)
class RasStationConfig:
    """GUI-editable RAS-station definition."""

    longitude_deg: float | None = None
    latitude_deg: float | None = None
    elevation_m: float | None = None
    receiver_band_start_mhz: float | None = None
    receiver_band_stop_mhz: float | None = None
    receiver_response_mode: str | None = None
    receiver_custom_mask_points: list[list[float]] | None = None
    ras_reference_mode: str | None = None
    ras_reference_point_count: int | None = None

    def to_json_dict(self) -> dict[str, Any]:
        """Return a JSON-native RAS-station dictionary."""
        return {
            "longitude_deg": None if self.longitude_deg is None else float(self.longitude_deg),
            "latitude_deg": None if self.latitude_deg is None else float(self.latitude_deg),
            "elevation_m": None if self.elevation_m is None else float(self.elevation_m),
            "receiver_band_start_mhz": (
                None if self.receiver_band_start_mhz is None else float(self.receiver_band_start_mhz)
            ),
            "receiver_band_stop_mhz": (
                None if self.receiver_band_stop_mhz is None else float(self.receiver_band_stop_mhz)
            ),
            "receiver_response_mode": (
                None if self.receiver_response_mode is None else str(self.receiver_response_mode)
            ),
            "receiver_custom_mask_points": (
                None
                if self.receiver_custom_mask_points is None
                else [
                    [float(point[0]), float(point[1])]
                    for point in self.receiver_custom_mask_points
                ]
            ),
            "ras_reference_mode": (
                None if self.ras_reference_mode is None else str(self.ras_reference_mode)
            ),
            "ras_reference_point_count": (
                None
                if self.ras_reference_point_count is None
                else int(self.ras_reference_point_count)
            ),
        }

    @classmethod
    def from_json_dict(cls, payload: dict[str, Any]) -> "RasStationConfig":
        """Build a RAS-station configuration from persisted JSON data."""
        defaults = _default_ras_station_config()
        receiver_custom_mask_points = payload.get("receiver_custom_mask_points")
        normalized_receiver_points = None
        if not _is_gui_optional_scalar_missing(receiver_custom_mask_points):
            normalized_receiver_points = [
                [float(point[0]), float(point[1])]
                for point in list(receiver_custom_mask_points)
            ]
        return cls(
            longitude_deg=(
                None if payload["longitude_deg"] is None else float(payload["longitude_deg"])
            ),
            latitude_deg=(
                None if payload["latitude_deg"] is None else float(payload["latitude_deg"])
            ),
            elevation_m=None if payload["elevation_m"] is None else float(payload["elevation_m"]),
            receiver_band_start_mhz=(
                None
                if payload.get("receiver_band_start_mhz", defaults.receiver_band_start_mhz) is None
                else float(
                    payload.get(
                        "receiver_band_start_mhz",
                        defaults.receiver_band_start_mhz,
                    )
                )
            ),
            receiver_band_stop_mhz=(
                None
                if payload.get("receiver_band_stop_mhz", defaults.receiver_band_stop_mhz) is None
                else float(
                    payload.get(
                        "receiver_band_stop_mhz",
                        defaults.receiver_band_stop_mhz,
                    )
                )
            ),
            receiver_response_mode=(
                None
                if _is_gui_optional_scalar_missing(
                    payload.get("receiver_response_mode", defaults.receiver_response_mode)
                )
                else str(
                    payload.get(
                        "receiver_response_mode",
                        defaults.receiver_response_mode,
                    )
                )
            ),
            receiver_custom_mask_points=normalized_receiver_points,
            ras_reference_mode=(
                None
                if _is_gui_optional_scalar_missing(
                    payload.get("ras_reference_mode", defaults.ras_reference_mode)
                )
                else str(payload.get("ras_reference_mode", defaults.ras_reference_mode))
            ),
            ras_reference_point_count=(
                None
                if payload.get(
                    "ras_reference_point_count",
                    defaults.ras_reference_point_count,
                )
                is None
                else int(
                    payload.get(
                        "ras_reference_point_count",
                        defaults.ras_reference_point_count,
                    )
                )
            ),
        )

    def to_observer(self) -> Any:
        """Return a ``cysgp4.PyObserver`` for the current RAS station."""
        if not _has_complete_ras_station_config(self):
            raise ValueError("RAS-station geometry is incomplete.")
        return cysgp4.PyObserver(
            float(self.longitude_deg),
            float(self.latitude_deg),
            float(self.elevation_m) / 1000.0,
        )


