@dataclass(slots=True)
class SatelliteSystemConfig:
    """One satellite system's complete per-system configuration.

    Each satellite system has its own constellation geometry, antenna model,
    service parameters, spectrum plan, boresight avoidance, hexgrid geometry
    (cell spacing, geography masks), and contour analysis settings.
    """

    system_name: str = "System 1"
    system_color: str = "#22c55e"
    belts: list[BeltConfig] = field(default_factory=list)
    satellite_antennas: SatelliteAntennasConfig = field(default_factory=SatelliteAntennasConfig)
    service: ServiceConfig = field(default_factory=_blank_service_config)
    spectrum: SpectrumConfig = field(default_factory=_blank_spectrum_config)
    boresight: BoresightConfig = field(default_factory=BoresightConfig)
    hexgrid: "HexgridConfig" = field(default_factory=lambda: _default_hexgrid_config())
    grid_analysis: "GridAnalysisConfig" = field(default_factory=lambda: _default_grid_analysis_config())
    derived_state: dict[str, Any] = field(default_factory=dict)

    def to_json_dict(self) -> dict[str, Any]:
        d = {
            "system_name": str(self.system_name),
            "system_color": str(self.system_color),
            "constellation": {"belts": [b.to_json_dict() for b in self.belts]},
            "satellite_antennas": self.satellite_antennas.to_json_dict(),
            "service": self.service.to_json_dict(),
            "spectrum": self.spectrum.to_json_dict(),
            "boresight": self.boresight.to_json_dict(),
            "hexgrid": self.hexgrid.to_json_dict(),
            "grid_analysis": self.grid_analysis.to_json_dict(),
        }
        if self.derived_state:
            d["derived_state"] = _serialize_derived_state(self.derived_state)
        return d

    @classmethod
    def from_json_dict(cls, payload: dict[str, Any]) -> "SatelliteSystemConfig":
        belts_raw = payload.get("constellation", {}).get("belts", [])
        return cls(
            system_name=str(payload.get("system_name", "System 1")),
            system_color=str(payload.get("system_color", "#22c55e")),
            belts=[BeltConfig.from_json_dict(b) for b in belts_raw],
            satellite_antennas=SatelliteAntennasConfig.from_json_dict(
                payload.get("satellite_antennas") or {}
            ),
            service=ServiceConfig.from_json_dict(payload.get("service") or {}),
            spectrum=SpectrumConfig.from_json_dict(payload.get("spectrum") or {}),
            boresight=BoresightConfig.from_json_dict(payload.get("boresight") or {}),
            hexgrid=HexgridConfig.from_json_dict(
                payload["hexgrid"]
            ) if "hexgrid" in payload else _default_hexgrid_config(),
            grid_analysis=GridAnalysisConfig.from_json_dict(
                payload["grid_analysis"]
            ) if "grid_analysis" in payload else _default_grid_analysis_config(),
            derived_state=_deserialize_derived_state(payload.get("derived_state", {})),
        )


def _serialize_derived_state(state: dict[str, Any]) -> dict[str, Any]:
    """Serialize per-system derived state (signatures are tuples → lists)."""
    out: dict[str, Any] = {}
    for key, value in state.items():
        if key == "_hexgrid_preview_cached_result":
            continue  # too large / not serializable
        if key == "_grid_actual_label_text":
            out[key] = str(value) if value is not None else None
            continue
        if isinstance(value, tuple):
            out[key] = list(value)
        elif isinstance(value, (int, float, str, bool, type(None))):
            out[key] = value
        # skip non-serializable values
    return out


def _deep_lists_to_tuples(value: Any) -> Any:
    """Recursively convert all lists to tuples (for hashable signature comparison)."""
    if isinstance(value, list):
        return tuple(_deep_lists_to_tuples(item) for item in value)
    return value


def _deserialize_derived_state(payload: dict[str, Any] | None) -> dict[str, Any]:
    """Deserialize per-system derived state (lists → tuples for signatures)."""
    if not payload:
        return {}
    out: dict[str, Any] = {}
    for key, value in payload.items():
        out[key] = _deep_lists_to_tuples(value)
    return out


