@dataclass(slots=True)
class SystemOutputGroup:
    """One output accumulation group: a named subset of systems."""

    name: str
    system_indices: list[int]  # indices into ScepterProjectState.systems
    enabled: bool = True

    def to_json_dict(self) -> dict[str, Any]:
        return {
            "name": str(self.name),
            "system_indices": list(int(i) for i in self.system_indices),
            "enabled": bool(self.enabled),
        }

    @classmethod
    def from_json_dict(cls, payload: dict[str, Any]) -> "SystemOutputGroup":
        return cls(
            name=str(payload.get("name", "")),
            system_indices=[int(i) for i in payload.get("system_indices", [])],
            enabled=bool(payload.get("enabled", True)),
        )


def _default_output_system_groups(
    n_systems: int,
    system_names: list[str] | None = None,
) -> list[SystemOutputGroup]:
    """Generate default output groups: one per system + combined."""
    names = system_names or [f"System {i+1}" for i in range(n_systems)]
    groups: list[SystemOutputGroup] = []
    for i in range(n_systems):
        groups.append(SystemOutputGroup(name=names[i], system_indices=[i], enabled=True))
    if n_systems > 1:
        groups.append(SystemOutputGroup(
            name="Combined",
            system_indices=list(range(n_systems)),
            enabled=True,
        ))
    return groups


@dataclass(slots=True)
class ScepterProjectState:
    """Persistent GUI state containing constellation, station, and analyzer settings.

    All per-system data lives in ``systems``.  Shared fields
    (``ras_station``, ``ras_antenna``, ``runtime``) are at the top level.
    Legacy flat fields have been removed — use ``active_system()`` instead.
    """

    # --- Per-system ---
    systems: list[SatelliteSystemConfig] = field(default_factory=list)

    # --- Shared fields ---
    ras_station: RasStationConfig | None = None
    ras_antenna: RasAntennaConfig = field(default_factory=RasAntennaConfig)
    runtime: RuntimeConfig = field(default_factory=_default_runtime_config)
    output_system_groups: list[SystemOutputGroup] = field(default_factory=list)

    # --- Active system index (not persisted) ---
    _active_index: int = 0

    def active_system(self, index: int | None = None) -> SatelliteSystemConfig:
        """Return the per-system config at the given index.

        When *index* is ``None`` (the default), uses the internally tracked
        active-system index — set by :meth:`current_state` from the GUI's
        ``_active_system_index``.  If the ``systems`` list is empty, returns
        a blank default system.
        """
        idx = self._active_index if index is None else index
        if self.systems and 0 <= idx < len(self.systems):
            return self.systems[idx]
        return SatelliteSystemConfig()

    def to_json_dict(self) -> dict[str, Any]:
        """Serialize the state into the persisted JSON document shape."""
        systems_out = self.systems or [SatelliteSystemConfig()]
        return {
            "schema_version": GUI_CONFIG_SCHEMA_VERSION,
            "systems": [s.to_json_dict() for s in systems_out],
            "ras_station": (
                None if self.ras_station is None else self.ras_station.to_json_dict()
            ),
            "ras_antenna": self.ras_antenna.to_json_dict(),
            "runtime": self.runtime.to_json_dict(),
            "output_system_groups": [g.to_json_dict() for g in (self.output_system_groups or [])],
        }

    @classmethod
    def from_json_dict(cls, payload: dict[str, Any]) -> "ScepterProjectState":
        """Load persistent GUI state from a JSON document."""
        schema_version = int(payload["schema_version"])
        if schema_version != GUI_CONFIG_SCHEMA_VERSION:
            raise ValueError(
                f"Unsupported GUI config schema_version={schema_version}; "
                f"expected {GUI_CONFIG_SCHEMA_VERSION}."
            )
        systems_raw = payload.get("systems", [])
        systems_out = [SatelliteSystemConfig.from_json_dict(s) for s in systems_raw]
        ras_payload = payload.get("ras_station")
        ras_station_out = (
            None if ras_payload is None
            else RasStationConfig.from_json_dict(ras_payload)
        )
        ras_antenna_out = RasAntennaConfig.from_json_dict(
            payload.get("ras_antenna", {})
        )
        runtime_out = RuntimeConfig.from_json_dict(payload.get("runtime", {}))
        output_groups_out = [
            SystemOutputGroup.from_json_dict(g)
            for g in payload.get("output_system_groups", [])
        ]
        return cls(
            systems=systems_out,
            ras_station=ras_station_out,
            ras_antenna=ras_antenna_out,
            runtime=runtime_out,
            output_system_groups=output_groups_out,
        )


