    def _refresh_grid_layout(self) -> None:
        available = self._available_scroll_width(self.grid_tab)
        if available <= 0:
            return
        threshold = (
            self.grid_inputs_group.sizeHint().width()
            + self.grid_actions_group.sizeHint().width()
            + self.grid_results_group.sizeHint().width()
            + (self._grid_top_layout.spacing() * 2)
            + 56
        )
        self._set_box_layout_stacked(self._grid_top_layout, available < threshold)
        if hasattr(self, "_grid_action_button_layout"):
            self._set_grid_widgets_columns(
                self._grid_action_button_layout,
                self._grid_action_buttons,
                columns=2 if available >= 760 else 1,
            )

    def _refresh_hexgrid_layout(self) -> None:
        available = self._available_scroll_width(self.hexgrid_tab)
        if available <= 0:
            return
        threshold = (
            self.geography_group.sizeHint().width()
            + self.boresight_group.sizeHint().width()
            + self._hexgrid_body_layout.spacing()
            + 48
        )
        self._set_box_layout_stacked(self._hexgrid_body_layout, available < threshold)
        if hasattr(self, "_hexgrid_button_layout"):
            if available >= 900:
                self._hexgrid_button_layout.addWidget(self.hexgrid_preview_status_label, 0, 0)
                self._hexgrid_button_layout.addWidget(self.apply_hexgrid_button, 0, 1)
                self._hexgrid_button_layout.addWidget(self.refresh_hexgrid_button, 0, 2)
                self._hexgrid_button_layout.setColumnStretch(0, 1)
                self._hexgrid_button_layout.setColumnStretch(1, 0)
                self._hexgrid_button_layout.setColumnStretch(2, 0)
            else:
                self._hexgrid_button_layout.addWidget(self.hexgrid_preview_status_label, 0, 0, 1, 2)
                self._hexgrid_button_layout.addWidget(self.apply_hexgrid_button, 1, 0)
                if available >= 620:
                    self._hexgrid_button_layout.addWidget(self.refresh_hexgrid_button, 1, 1)
                else:
                    self._hexgrid_button_layout.addWidget(self.refresh_hexgrid_button, 2, 0)
                self._hexgrid_button_layout.setColumnStretch(0, 1)
                self._hexgrid_button_layout.setColumnStretch(1, 1 if available >= 620 else 0)
                self._hexgrid_button_layout.setColumnStretch(2, 0)

    def _refresh_runtime_layout(self) -> None:
        available = self._available_scroll_width(self.runtime_page)
        if available <= 0:
            return
        runtime_top_widgets = (
            self.runtime_simulation_group,
            self.runtime_context_group,
            self.runtime_memory_group,
            self.runtime_advanced_group,
        )
        row_one = runtime_top_widgets[0].sizeHint().width() + runtime_top_widgets[1].sizeHint().width()
        row_two = runtime_top_widgets[2].sizeHint().width() + runtime_top_widgets[3].sizeHint().width()
        threshold = max(row_one, row_two) + self._runtime_top_grid.horizontalSpacing() + 48
        self._set_grid_widgets_columns(
            self._runtime_top_grid,
            runtime_top_widgets,
            columns=2 if available >= threshold else 1,
        )
        advanced_threshold = (
            self.runtime_gpu_group.sizeHint().width()
            + self.runtime_writer_group.sizeHint().width()
            + self._runtime_advanced_split.spacing()
            + 48
        )
        self._set_box_layout_stacked(self._runtime_advanced_split, available < advanced_threshold)
        if hasattr(self, "_runtime_button_layout"):
            self._set_grid_widgets_columns(
                self._runtime_button_layout,
                self._runtime_action_buttons,
                columns=3 if available >= 920 else 2 if available >= 620 else 1,
            )

    def _refresh_postprocess_layout(self) -> None:
        available = (
            max(int(self.postprocess_workspace.viewport().width()), 0)
            if isinstance(self.postprocess_workspace, QtWidgets.QScrollArea)
            else max(int(self.postprocess_widget.width()), 0)
        )
        if available <= 0:
            return
        self.postprocess_widget.setMinimumWidth(
            _POSTPROCESS_LEFT_CARD_MIN_WIDTH + _POSTPROCESS_CENTER_CARD_MIN_WIDTH + _POSTPROCESS_RIGHT_CARD_MIN_WIDTH + 48
        )
        if available < 1240:
            left_width = _POSTPROCESS_LEFT_CARD_MIN_WIDTH
            right_width = _POSTPROCESS_RIGHT_CARD_MIN_WIDTH
        else:
            left_width = max(_POSTPROCESS_LEFT_CARD_MIN_WIDTH, min(292, int(available * 0.17)))
            right_width = max(_POSTPROCESS_RIGHT_CARD_MIN_WIDTH, min(392, int(available * 0.22)))
        center_width = max(
            _POSTPROCESS_CENTER_CARD_MIN_WIDTH,
            int(available - left_width - right_width - 34),
        )
        sizes = [int(left_width), int(center_width), int(right_width)]
        self.postprocess_widget._main_splitter.setSizes(sizes)

    def _refresh_workspace_nav_layout(self) -> None:
        self._apply_scale_aware_ui_metrics()
        expanded = bool(self._workspace_nav_expanded)
        self.workspace_nav.setProperty("collapsed", not expanded)
        self.workspace_nav.style().unpolish(self.workspace_nav)
        self.workspace_nav.style().polish(self.workspace_nav)
        self._workspace_nav_brand_text_container.setVisible(expanded)
        self._workspace_nav_brand_label.setVisible(expanded)
        self._workspace_nav_tag_label.setVisible(expanded)
        nav_margin = 16 if expanded else 10
        self._workspace_nav_layout.setContentsMargins(nav_margin, 18, nav_margin, 18)
        self._workspace_nav_layout.setSpacing(12 if expanded else 10)
        self._workspace_nav_header_layout.setSpacing(10 if expanded else 0)
        self._workspace_nav_utility_layout.setSpacing(8 if expanded else 10)
        self._workspace_nav_utility_layout.setAlignment(QtCore.Qt.AlignTop | QtCore.Qt.AlignHCenter)
        button_spacing = 8 if expanded else 10
        self._workspace_nav_button_row.setSpacing(button_spacing)
        nav_width = max(int(self._workspace_nav_current_width) - (2 * nav_margin), 0)
        horizontal_button_width = (2 * _CONTROL_BUTTON_MIN_SIZE) + button_spacing + 8
        use_horizontal_button_row = expanded and nav_width >= horizontal_button_width
        self._workspace_nav_button_row.setDirection(
            QtWidgets.QBoxLayout.LeftToRight if use_horizontal_button_row else QtWidgets.QBoxLayout.TopToBottom
        )
        self._workspace_nav_button_row.setAlignment(QtCore.Qt.AlignTop | QtCore.Qt.AlignHCenter)
        if hasattr(self, "_appearance_shell_label"):
            self._appearance_shell_label.setVisible(True)
            self._appearance_shell_label.setAlignment(
                QtCore.Qt.AlignLeft | QtCore.Qt.AlignVCenter
                if expanded
                else QtCore.Qt.AlignHCenter | QtCore.Qt.AlignVCenter
            )
        if hasattr(self, "_appearance_shell_container"):
            self._appearance_shell_container.setVisible(True)
            self._appearance_shell_container.setMinimumWidth(0)
            self._appearance_shell_container.setMaximumWidth(nav_width)
            self._appearance_shell_container.setFixedWidth(max(nav_width, _CONTROL_BUTTON_MIN_SIZE))
        if hasattr(self, "appearance_mode_combo"):
            combo_width = max(int(self._workspace_nav_current_width) - (2 * nav_margin), _CONTROL_BUTTON_MIN_SIZE)
            self.appearance_mode_combo.setMinimumWidth(0)
            self.appearance_mode_combo.setMaximumWidth(combo_width)
            self.appearance_mode_combo.setFixedWidth(combo_width)
        self._workspace_nav_brand_left_spacer.changeSize(
            0,
            0,
            QtWidgets.QSizePolicy.Fixed if expanded else QtWidgets.QSizePolicy.Expanding,
            QtWidgets.QSizePolicy.Minimum,
        )
        self._workspace_nav_brand_right_spacer.changeSize(
            0,
            0,
            QtWidgets.QSizePolicy.Expanding,
            QtWidgets.QSizePolicy.Minimum,
        )
        self._workspace_nav_header_layout.invalidate()
        for button, label in (
            (self.nav_home_button, "Home"),
            (self.nav_simulation_button, "Simulation"),
            (self.nav_postprocess_button, "Postprocess"),
        ):
            button.setProperty("navCollapsed", not expanded)
            button.style().unpolish(button)
            button.style().polish(button)
            button.setText(label if expanded else "")
            button.setToolTip(label)

    def _add_bottom_safe_area(self, layout: QtWidgets.QBoxLayout, *, height: int = 22) -> None:
        spacer_parent = layout.parentWidget() or self
        spacer = QtWidgets.QWidget(spacer_parent)
        spacer.setObjectName("pageSafeArea")
        spacer.setFixedHeight(int(height))
        spacer.setSizePolicy(QtWidgets.QSizePolicy.Preferred, QtWidgets.QSizePolicy.Fixed)
        layout.addWidget(spacer)

