    def _show_help_for(self, widget: QtWidgets.QWidget | None) -> bool:
        if widget is None:
            return False
        help_def = self._help_registry.get(widget)
        if help_def is None:
            return False
        self._help_popover.show_for_widget(widget, help_def)
        return True

    def _compact_panel_text(self, text: str, max_chars: int = 120) -> str:
        compact = " ".join(str(text or "").split())
        if len(compact) <= max_chars:
            return compact
        return compact[: max_chars - 1].rstrip() + "…"

    def _set_persistent_status_bar_message(self, text: str) -> None:
        message = str(text or "Ready")
        self._persistent_status_bar_message = message
        if self._status_bar_context_source is None:
            self.statusBar().showMessage(message)

    def _show_status_bar_context(self, source: QtWidgets.QWidget, text: str) -> None:
        self._status_bar_context_source = source
        self.statusBar().showMessage(str(text or self._persistent_status_bar_message or "Ready"))

    def _clear_status_bar_context(self, source: QtWidgets.QWidget | None = None) -> None:
        if source is not None and self._status_bar_context_source is not source:
            return
        self._status_bar_context_source = None
        self.statusBar().showMessage(self._persistent_status_bar_message or "Ready")

    def _help_status_targets_for_widget(self, widget: QtWidgets.QWidget) -> list[QtWidgets.QWidget]:
        targets: list[QtWidgets.QWidget] = [widget]
        help_button = self._help_buttons.get(widget)
        if help_button is not None:
            targets.append(help_button)
            container = help_button.parentWidget()
            if container is not None:
                targets.append(container)
        label_widget = self._form_label_for_widget(widget)
        if label_widget is not None:
            targets.append(label_widget)
        return [target for target in targets if isinstance(target, QtWidgets.QWidget)]

    def _form_label_for_widget(self, widget: QtWidgets.QWidget) -> QtWidgets.QLabel | None:
        help_button = self._help_buttons.get(widget)
        field_target = help_button.parentWidget() if help_button is not None else widget
        for form_layout in self.findChildren(QtWidgets.QFormLayout):
            label_widget = form_layout.labelForField(field_target)
            if label_widget is None and field_target is not widget:
                label_widget = form_layout.labelForField(widget)
            if isinstance(label_widget, QtWidgets.QLabel):
                return label_widget
        return None

    def _set_form_row_visible(
        self,
        form_layout: QtWidgets.QFormLayout,
        field_widget: QtWidgets.QWidget,
        visible: bool,
    ) -> None:
        # The field_widget may be wrapped in a _helpful_widget container.
        # Walk up to find the widget that the form layout actually knows about.
        target = field_widget
        label_widget = form_layout.labelForField(target)
        if label_widget is None:
            # Try the parent (the _helpful_widget container)
            parent = field_widget.parentWidget()
            if parent is not None and form_layout.labelForField(parent) is not None:
                target = parent
                label_widget = form_layout.labelForField(target)
        if label_widget is not None:
            label_widget.setVisible(bool(visible))
        target.setVisible(bool(visible))

    def _show_help_for_focused_widget(self) -> None:
        focus_widget = QtWidgets.QApplication.focusWidget()
        if isinstance(focus_widget, QtWidgets.QWidget):
            self._show_help_for(focus_widget)

    def _highlight_widget(self, widget: QtWidgets.QWidget | None) -> None:
        if widget is None:
            return
        self._clear_highlight_target()
        self._highlight_target_widget = widget
        widget.setProperty("spotlight", True)
        widget.style().unpolish(widget)
        widget.style().polish(widget)
        self._highlight_reset_timer.start(1600)

    def _clear_highlight_target(self) -> None:
        widget = self._highlight_target_widget
        if widget is None:
            return
        widget.setProperty("spotlight", False)
        widget.style().unpolish(widget)
        widget.style().polish(widget)
        self._highlight_target_widget = None

    def _refresh_help_mode_highlights(self) -> None:
        # Help-highlight mode has been removed; this is now a no-op.
        pass

    def _simulation_page_for_target(self, target: QtWidgets.QWidget | None) -> QtWidgets.QWidget | None:
        widget = target
        while isinstance(widget, QtWidgets.QWidget):
            if self.tab_widget.indexOf(widget) >= 0:
                if isinstance(widget, QtWidgets.QScrollArea):
                    return self._simulation_page_by_wrapper.get(widget, widget)
                return widget
            widget = widget.parentWidget()
        return None

    def _select_simulation_page(self, target: QtWidgets.QWidget | None) -> None:
        page = self._simulation_page_for_target(target)
        if page is None:
            return
        tab_target = self._simulation_tab_container_for_page(page)
        index = self.tab_widget.indexOf(tab_target) if tab_target is not None else -1
        if index < 0:
            return
        self.tab_widget.setCurrentIndex(index)
        item = self.simulation_page_list.item(index)
        if item is not None:
            blocker = QtCore.QSignalBlocker(self.simulation_page_list)
            self.simulation_page_list.setCurrentRow(index)
            del blocker

    def _commit_visible_editors(self) -> None:
        focus = QtWidgets.QApplication.focusWidget()
        current_page = self.tab_widget.currentWidget()
        if (
            isinstance(focus, QtWidgets.QWidget)
            and isinstance(current_page, QtWidgets.QWidget)
            and current_page.isAncestorOf(focus)
        ):
            focus.clearFocus()
        QtWidgets.QApplication.processEvents(QtCore.QEventLoop.ExcludeUserInputEvents)

