    def _build_actions(self) -> None:
        self.menuBar().setNativeMenuBar(False)
        self.menuBar().setAttribute(QtCore.Qt.WA_StyledBackground, True)
        self.menuBar().setAutoFillBackground(True)
        file_menu = self.menuBar().addMenu("&File")
        self.action_new = QtGui.QAction("New Configuration", self)
        self.action_load = QtGui.QAction("Load Configuration...", self)
        self.action_save = QtGui.QAction("Save Configuration", self)
        self.action_save_as = QtGui.QAction("Save Configuration As...", self)
        self.action_open_result = QtGui.QAction("Open Result File...", self)
        file_menu.addAction(self.action_new)
        file_menu.addAction(self.action_load)
        file_menu.addAction(self.action_open_result)
        file_menu.addSeparator()
        file_menu.addAction(self.action_save)
        file_menu.addAction(self.action_save_as)
        tools_menu = self.menuBar().addMenu("&Tools")
        self.action_testing_suite = QtGui.QAction("Testing Suite...", self)
        tools_menu.addAction(self.action_testing_suite)
        help_menu = self.menuBar().addMenu("&Help")
        self.action_about = QtGui.QAction("About SCEPTer", self)
        help_menu.addAction(self.action_about)
        for menu in (file_menu, tools_menu, help_menu):
            menu.setAttribute(QtCore.Qt.WA_StyledBackground, True)
            if sys.platform != "win32":
                menu.setAttribute(QtCore.Qt.WA_TranslucentBackground, True)
                menu.setWindowFlag(QtCore.Qt.NoDropShadowWindowHint, True)

    def _about_dialog_text(self) -> str:
        return appinfo.ABOUT_TEXT

    def _show_about_dialog(self) -> None:
        QtWidgets.QMessageBox.information(
            self,
            appinfo.ABOUT_TITLE,
            self._about_dialog_text(),
        )

    def _show_testing_suite(self) -> None:
        dialog = TestingSuiteDialog(self)
        dialog.exec()

    def _build_home_workspace(self) -> QtWidgets.QScrollArea:
        page = QtWidgets.QWidget(self)
        page.setObjectName("homeScrollPage")
        page.setAttribute(QtCore.Qt.WA_StyledBackground, True)
        layout = QtWidgets.QVBoxLayout(page)
        layout.setContentsMargins(18, 18, 18, 18)
        layout.setSpacing(14)

        hero = QtWidgets.QFrame(self)
        hero.setObjectName("heroCard")
        hero_layout = QtWidgets.QVBoxLayout(hero)
        hero_layout.setContentsMargins(22, 20, 22, 20)
        hero_layout.setSpacing(8)
        hero_title = QtWidgets.QLabel("SCEPTer control room", self)
        hero_title.setObjectName("workspaceHeading")
        hero_subtitle = QtWidgets.QLabel(
            "Create simulation configs, run structured GPU workflows, inspect HDF5 outputs, and jump straight into postprocess plots.",
            self,
        )
        hero_subtitle.setWordWrap(True)
        hero_subtitle.setObjectName("workspaceSubheading")
        hero_layout.addWidget(hero_title)
        hero_layout.addWidget(hero_subtitle)
        hero_buttons = QtWidgets.QGridLayout()
        hero_buttons.setContentsMargins(0, 4, 0, 0)
        hero_buttons.setHorizontalSpacing(10)
        hero_buttons.setVerticalSpacing(10)
        self._home_hero_button_layout = hero_buttons
        self.home_new_button = QtWidgets.QPushButton("New Simulation", self)
        self.home_open_config_button = QtWidgets.QPushButton("Open Simulation Config", self)
        self.home_open_result_button = QtWidgets.QPushButton("Open Result File", self)
        self.home_open_viewer_button = QtWidgets.QPushButton("Open 3D Viewer", self)
        self._home_hero_buttons = (
            self.home_new_button,
            self.home_open_config_button,
            self.home_open_result_button,
            self.home_open_viewer_button,
        )
        self._set_grid_widgets_columns(
            self._home_hero_button_layout,
            self._home_hero_buttons,
            columns=4,
        )
        hero_layout.addLayout(hero_buttons)
        layout.addWidget(hero)

        body = QtWidgets.QBoxLayout(QtWidgets.QBoxLayout.LeftToRight)
        self._home_body_layout = body
        body.setSpacing(14)
        left_card = QtWidgets.QFrame(self)
        left_card.setObjectName("shellCard")
        self._home_recent_configs_card = left_card
        left_layout = QtWidgets.QVBoxLayout(left_card)
        left_layout.setContentsMargins(16, 16, 16, 16)
        left_layout.setSpacing(10)
        left_layout.addWidget(QtWidgets.QLabel("Recent simulation configs", self))
        self.home_recent_configs = QtWidgets.QListWidget(self)
        left_layout.addWidget(self.home_recent_configs, stretch=1)
        body.addWidget(left_card, stretch=1)

        right_card = QtWidgets.QFrame(self)
        right_card.setObjectName("shellCard")
        self._home_recent_results_card = right_card
        right_layout = QtWidgets.QVBoxLayout(right_card)
        right_layout.setContentsMargins(16, 16, 16, 16)
        right_layout.setSpacing(10)
        right_layout.addWidget(QtWidgets.QLabel("Recent result files", self))
        self.home_recent_results = QtWidgets.QListWidget(self)
        right_layout.addWidget(self.home_recent_results, stretch=1)
        body.addWidget(right_card, stretch=1)
        layout.addLayout(body, stretch=1)
        self._add_bottom_safe_area(layout)

        area = QtWidgets.QScrollArea(self)
        area.setWidgetResizable(True)
        area.setFrameShape(QtWidgets.QFrame.NoFrame)
        area.setObjectName("homeScrollArea")
        area.setAttribute(QtCore.Qt.WA_StyledBackground, True)
        area.setWidget(page)
        area.viewport().setObjectName("homeScrollViewport")
        area.viewport().setAttribute(QtCore.Qt.WA_StyledBackground, True)
        return area

    def _build_postprocess_workspace(self) -> QtWidgets.QScrollArea:
        area = QtWidgets.QScrollArea(self)
        area.setWidgetResizable(True)
        area.setFrameShape(QtWidgets.QFrame.NoFrame)
        area.setObjectName("postprocessScrollArea")
        area.setAttribute(QtCore.Qt.WA_StyledBackground, True)
        widget = PostprocessStudioWidget(self)
        widget.setObjectName("postprocessScrollPage")
        widget.setAttribute(QtCore.Qt.WA_StyledBackground, True)
        area.setWidget(widget)
        area.viewport().setObjectName("postprocessScrollViewport")
        area.viewport().setAttribute(QtCore.Qt.WA_StyledBackground, True)
        self.postprocess_widget = widget
        return area

