    def _on_help_mode_toggled(self, enabled: bool) -> None:
        self._help_mode_enabled = bool(enabled)
        self._refresh_help_mode_highlights()
        self._set_persistent_status_bar_message(
            "Highlight mode is on: highlighted controls can be clicked for detailed help."
            if enabled
            else self.statusBar().currentMessage() or "Ready"
        )
        if not enabled:
            self._help_popover.hide()

    def event(self, event: QtCore.QEvent) -> bool:
        if event.type() in {
            QtCore.QEvent.ScreenChangeInternal,
            QtCore.QEvent.ApplicationFontChange,
            QtCore.QEvent.FontChange,
            QtCore.QEvent.StyleChange,
            QtCore.QEvent.ApplicationPaletteChange,
            QtCore.QEvent.PaletteChange,
            QtCore.QEvent.PolishRequest,
        }:
            self._schedule_responsive_layout_refresh()
        if event.type() in {
            QtCore.QEvent.ApplicationPaletteChange,
            QtCore.QEvent.PaletteChange,
            QtCore.QEvent.StyleChange,
        }:
            self._schedule_system_theme_refresh()
        return super().event(event)

    def changeEvent(self, event: QtCore.QEvent) -> None:
        super().changeEvent(event)
        if event.type() in {
            QtCore.QEvent.FontChange,
            QtCore.QEvent.StyleChange,
            QtCore.QEvent.PaletteChange,
        }:
            self._schedule_responsive_layout_refresh()

    def eventFilter(self, watched: object, event: QtCore.QEvent) -> bool:
        if not isinstance(watched, QtCore.QObject):
            return False
        if isinstance(watched, QtWidgets.QWidget) and watched in self._status_help_targets:
            if event.type() in {QtCore.QEvent.Enter, QtCore.QEvent.FocusIn}:
                self._show_status_bar_context(watched, self._status_help_targets[watched])
            elif event.type() in {QtCore.QEvent.Leave, QtCore.QEvent.FocusOut}:
                self._clear_status_bar_context(watched)
        if hasattr(self, "belt_table") and watched is self.belt_table.horizontalHeader():
            if event.type() == QtCore.QEvent.ToolTip and isinstance(event, QtGui.QHelpEvent):
                section = self.belt_table.horizontalHeader().logicalIndexAt(event.pos())
                if section >= 0:
                    tip = self._belt_model.headerData(
                        section,
                        QtCore.Qt.Horizontal,
                        QtCore.Qt.ToolTipRole,
                    )
                    if tip:
                        QtWidgets.QToolTip.showText(event.globalPos(), str(tip), self.belt_table.horizontalHeader())
                        return True
        if self._help_mode_enabled and isinstance(watched, QtWidgets.QWidget):
            if event.type() == QtCore.QEvent.MouseButtonPress and watched in self._help_registry:
                self._help_popover.show_for_widget(watched, self._help_registry[watched])
                return True
        if self._help_popover.isVisible() and event.type() in {
            QtCore.QEvent.MouseButtonPress,
            QtCore.QEvent.FocusIn,
        }:
            if isinstance(watched, QtWidgets.QWidget):
                within_popover = (
                    watched is self._help_popover
                    or self._help_popover.isAncestorOf(watched)
                )
                if not within_popover:
                    self._help_popover.hide()
            else:
                self._help_popover.hide()
        if event.type() in {
            QtCore.QEvent.Enter,
            QtCore.QEvent.Leave,
            QtCore.QEvent.MouseButtonPress,
            QtCore.QEvent.FocusIn,
            QtCore.QEvent.FocusOut,
            QtCore.QEvent.WindowActivate,
        }:
            QtCore.QTimer.singleShot(0, self._restart_side_pane_auto_hide_timer)
            QtCore.QTimer.singleShot(0, self._restart_workspace_nav_auto_hide_timer)
        app = QtWidgets.QApplication.instance()
        is_global_theme_event = watched is app and event.type() in {
            QtCore.QEvent.FontChange,
            QtCore.QEvent.ApplicationFontChange,
            QtCore.QEvent.StyleChange,
            QtCore.QEvent.ApplicationPaletteChange,
            QtCore.QEvent.PaletteChange,
            QtCore.QEvent.ScreenChangeInternal,
        }
        if is_global_theme_event:
            QtCore.QTimer.singleShot(0, self._schedule_responsive_layout_refresh)
        if watched is app and event.type() in {
            QtCore.QEvent.ApplicationPaletteChange,
            QtCore.QEvent.PaletteChange,
            QtCore.QEvent.StyleChange,
        }:
            self._schedule_system_theme_refresh()
        return super().eventFilter(watched, event)

    def resizeEvent(self, event: QtGui.QResizeEvent) -> None:
        super().resizeEvent(event)
        self._schedule_responsive_layout_refresh()

    def changeEvent(self, event: QtCore.QEvent) -> None:
        super().changeEvent(event)
        if event.type() in {
            QtCore.QEvent.FontChange,
            QtCore.QEvent.ApplicationFontChange,
            QtCore.QEvent.StyleChange,
            QtCore.QEvent.PaletteChange,
        }:
            self._schedule_responsive_layout_refresh()
            self._schedule_system_theme_refresh()

    def _schedule_system_theme_refresh(self) -> None:
        if self._selected_appearance_mode() != "system" or self._system_theme_refresh_pending:
            return
        self._system_theme_refresh_pending = True
        QtCore.QTimer.singleShot(0, self._refresh_system_theme)

    def _refresh_system_theme(self) -> None:
        self._system_theme_refresh_pending = False
        if (
            self._selected_appearance_mode() != "system"
            or self._system_theme_refresh_in_progress
        ):
            return
        system_palette = self._system_application_palette()
        signature = self._current_system_theme_signature(palette=system_palette)
        if signature == self._last_applied_system_theme_signature:
            return
        self._system_theme_refresh_in_progress = True
        try:
            self._default_application_palette = QtGui.QPalette(system_palette)
            self._apply_visual_style()
            self._repolish_shell_theme_surfaces()
            self._restyle_detached_preview_windows()
            self._schedule_responsive_layout_refresh()
            QtCore.QTimer.singleShot(0, self._stabilize_visible_geometry)
            self._last_applied_system_theme_signature = signature
        finally:
            self._system_theme_refresh_in_progress = False

    def _show_belt_columns_help(self) -> None:
        if not hasattr(self, "belt_columns_help_button"):
            return
        help_def = self._help_registry.get(self.belt_columns_help_button)
        if help_def is not None:
            self._help_popover.show_for_widget(self.belt_columns_help_button, help_def)

    def _page_status(
        self,
        *,
        ready: bool,
        kind: str,
        title: str,
        message: str,
        target: QtWidgets.QWidget,
        action: str,
        review_pending: bool = False,
    ) -> dict[str, Any]:
        return {
            "ready": bool(ready),
            "kind": str(kind),
            "title": str(title),
            "message": str(message),
            "target": target,
            "action": str(action),
            "review_pending": bool(review_pending),
        }

    def _ras_station_status(self, state: ScepterProjectState) -> dict[str, Any]:
        receiver_ready, receiver_message = _validate_ras_receiver_config(state.ras_station)
        ras_ready = (
            _has_complete_ras_station_config(state.ras_station)
            and _has_valid_ras_antenna_config(state.ras_antenna)
            and receiver_ready
        )
        return self._page_status(
            ready=bool(ras_ready),
            kind="ready" if ras_ready else "warning",
            title="RAS station is configured" if ras_ready else "Complete the RAS station",
            message=(
                "Station coordinates, local receive antenna inputs, and the RAS receiver response are ready."
                if ras_ready
                else (
                    "Set longitude, latitude, elevation, antenna diameter, a valid operational elevation range, "
                    f"and the RAS receiver band. {receiver_message}"
                )
            ),
            target=self.ras_tab,
            action="Open RAS station",
        )

    def _orbitals_status(self, state: ScepterProjectState) -> dict[str, Any]:
        s0 = state.active_system()
        orbitals_ready = False
        orbitals_message = "Add at least one valid orbital belt."
        if len(s0.belts) >= 1:
            try:
                build_constellation_from_state(state)
            except Exception as exc:
                orbitals_message = str(exc)
            else:
                orbitals_ready = True
                orbitals_message = "Constellation belts are ready."
        return self._page_status(
            ready=bool(orbitals_ready),
            kind="ready" if orbitals_ready else "warning",
            title="Satellite orbitals are configured"
            if orbitals_ready
            else "Add a constellation belt",
            message=orbitals_message,
            target=self.constellation_tab,
            action="Open satellite orbitals",
        )

    def _satellite_antennas_status(self, state: ScepterProjectState) -> dict[str, Any]:
        sat_ant_ready = _has_valid_satellite_antenna_config(state.active_system().satellite_antennas)
        return self._page_status(
            ready=bool(sat_ant_ready),
            kind="ready" if sat_ant_ready else "warning",
            title="Satellite antenna is configured"
            if sat_ant_ready
            else "Finish satellite antenna inputs",
            message=(
                "The satellite-system antenna model is ready for contours and simulation."
                if sat_ant_ready
                else "Select a satellite antenna model and complete its required parameters."
            ),
            target=self.antennas_tab,
            action="Open satellite antennas",
        )

    def _service_status(self, state: ScepterProjectState) -> dict[str, Any]:
        s0 = state.active_system()
        try:
            power_input = _require_service_power_input(state)
            power_summary = _service_power_input_summary(power_input, uemr_mode=uemr_active)
        except ValueError:
            power_summary = None
        uemr_active = _system_is_uemr(s0)
        service_ready = _has_valid_service_config(s0.service, uemr_mode=uemr_active)
        if service_ready:
            if uemr_active:
                ready_msg = f"{power_summary} is ready."
            else:
                ready_msg = (
                    "Nco, Nbeam, selection, "
                    f"{_service_cell_activity_mode_label(str(s0.service.cell_activity_mode or _DEFAULT_SERVICE_CELL_ACTIVITY_MODE))} activity, "
                    f"and {power_summary} are ready."
                )
        else:
            if uemr_active:
                ready_msg = (
                    "Set one finite service power definition (Ptx or EIRP) on "
                    "the Service tab. UEMR mode ignores Nco/Nbeam/selection "
                    "strategy/cell activity and channel bandwidth (the kernel "
                    "uses the service band width automatically)."
                )
            else:
                ready_msg = (
                    "Set valid Nco, Nbeam, selection strategy, activity factor, "
                    "channel bandwidth, and one finite service power definition, "
                    "or apply the service defaults."
                )
        return self._page_status(
            ready=bool(service_ready),
            kind="ready" if service_ready else "warning",
            title="Service and demand inputs are configured"
            if service_ready
            else "Complete service and demand inputs",
            message=ready_msg,
            target=self.service_tab,
            action="Open service and demand",
        )

    def _spectrum_status(self, state: ScepterProjectState) -> dict[str, Any]:
        s0 = state.active_system()
        try:
            spectrum_plan = _normalize_spectrum_config(
                s0.service,
                s0.spectrum,
                state.ras_station,
            )
            spectrum_summary = _spectrum_summary_text(spectrum_plan)
            ready = True
        except Exception as exc:
            spectrum_summary = str(exc)
            ready = False
        return self._page_status(
            ready=bool(ready),
            kind="ready" if ready else "warning",
            title="Spectrum and reuse plan is configured"
            if ready
            else "Complete spectrum and reuse inputs",
            message=(
                spectrum_summary
                if ready
                else "Set a valid service band, reuse factor, and transmitter unwanted-emission mask, then use Edit Spectrum to choose the simulated channels. The RAS receiver band is defined on the RAS Station tab."
            ),
            target=self.spectrum_tab,
            action="Open spectrum and reuse",
        )

    def _contours_status(self, state: ScepterProjectState) -> dict[str, Any]:
        contour_ready = self._contour_is_current(state)
        effective_cell_km = self._effective_hexgrid_cell_size_km(state)
        return self._page_status(
            ready=bool(contour_ready),
            kind="ready" if contour_ready else "warning",
            title="Contour spacing is ready" if contour_ready else "Refresh contour spacing",
            message=(
                f"Effective cell spacing is locked at {float(effective_cell_km or 0.0):g} km."
                if contour_ready
                else (
                    f"Stored contour spacing remains visible at {float(effective_cell_km or 0.0):g} km, but it is stale. "
                    "Rerun the analyser or use a valid override before preparing the active hexgrid."
                    if effective_cell_km is not None
                    else "Run the analyser or enable a cell-size override before preparing the active hexgrid."
                )
            ),
            target=self.grid_tab,
            action="Open contour analysis",
        )

    def _coverage_boresight_status(self, state: ScepterProjectState) -> dict[str, Any]:
        preview_ready = self._hexgrid_visual_is_current(state)
        return self._page_status(
            ready=bool(preview_ready),
            kind="ready" if preview_ready else "warning",
            title="Hexgrid settings are current"
            if preview_ready
            else "Apply or preview the coverage and boresight settings",
            message=(
                "The current geography, RAS exclusion, and boresight settings are committed for this run."
                if preview_ready
                else self._hexgrid_status_message(state)
            ),
            target=self.hexgrid_tab,
            action="Open coverage and boresight",
        )

    def _review_run_status(self, state: ScepterProjectState) -> dict[str, Any]:
        run_ready, run_message = self._run_readiness_payload(state)
        run_completed = bool(
            self._run_in_progress or self._review_run_state in {"completed", "stopped"}
        )
        if self._run_in_progress:
            run_title = "Simulation is running"
            run_message_text = "The run is active. Use the structured monitor below to track iteration, writer, and flush progress."
        elif self._review_run_state == "completed":
            run_title = "Simulation finished"
            run_message_text = "The last run completed and the result file is ready for postprocess."
            if getattr(self, "_final_elapsed_s", None) is not None:
                run_message_text += (
                    f" Total elapsed time: {_format_duration_compact(float(self._final_elapsed_s))}."
                )
        elif self._review_run_state == "stopped":
            run_title = "Simulation stopped cleanly"
            run_message_text = "The last run stopped with flushed partial results that can still be inspected."
            if getattr(self, "_final_elapsed_s", None) is not None:
                run_message_text += (
                    f" Elapsed before stop: {_format_duration_compact(float(self._final_elapsed_s))}."
                )
        else:
            run_title = "Review parameters and outputs" if run_ready else "Resolve run preflight blockers"
            run_message_text = (
                "Runtime, outputs, checkpoints, and storage are ready. Review the settings below before launching the run."
                if run_ready
                else run_message
            )
        return self._page_status(
            ready=bool(run_completed),
            review_pending=bool(run_ready and not run_completed),
            kind="ready" if (run_ready or run_completed) else "warning",
            title=run_title,
            message=run_message_text,
            target=getattr(self, "runtime_run_group", self.runtime_tab),
            action="Open review and run",
        )

    def _simulation_page_statuses(
        self,
        state: ScepterProjectState,
        *,
        status_payloads: Mapping[str, Mapping[str, Any]] | None = None,
    ) -> dict[str, dict[str, Any]]:
        """Return the shared workflow-status model for banners, guidance, and snapshot."""
        payloads = (
            self._simulation_page_status_payloads(state)
            if status_payloads is None
            else {
                str(label): dict(payload)
                for label, payload in status_payloads.items()
            }
        )
        target_map = {
            "RAS Station": self.ras_tab,
            "Satellite Orbitals": self.constellation_tab,
            "Satellite Antennas": self.antennas_tab,
            "Service & Demand": self.service_tab,
            "Spectrum & Reuse": self.spectrum_tab,
            "Coverage & Contours": self.grid_tab,
            "Coverage & Boresight": self.hexgrid_tab,
            "Review & Run": getattr(self, "runtime_run_group", self.runtime_tab),
        }
        return {
            label: {
                **dict(payloads[label]),
                "target": target_map[label],
            }
            for label in _WORKFLOW_STATUS_ORDER
            if label in payloads
        }

    def _workflow_status_request(self, state: ScepterProjectState) -> dict[str, Any]:
        run_ready, run_message = self._run_readiness_payload(state)
        return {
            "contour_is_current": bool(self._contour_is_current(state)),
            "effective_cell_km": self._effective_hexgrid_cell_size_km(state),
            "hexgrid_is_current": bool(self._hexgrid_is_current(state)),
            "hexgrid_status_message": self._hexgrid_status_message(state),
            "run_ready": bool(run_ready),
            "run_message": str(run_message),
            "run_in_progress": bool(self._run_in_progress),
            "review_run_state": self._review_run_state,
            "spectrum_explicitly_configured": bool(
                self._workflow_has_explicit_spectrum_inputs()
            ),
        }

    def _simulation_page_status_payloads(
        self,
        state: ScepterProjectState,
    ) -> dict[str, dict[str, Any]]:
        return _compute_workflow_status_payloads(
            state,
            **self._workflow_status_request(state),
        )

    def _update_simulation_page_indicators(
        self,
        state: ScepterProjectState,
        *,
        statuses: Mapping[str, Mapping[str, Any]] | None = None,
    ) -> None:
        statuses_use = (
            self._simulation_page_statuses(state)
            if statuses is None
            else {
                str(label): dict(status)
                for label, status in statuses.items()
            }
        )
        icon_ready = self.style().standardIcon(QtWidgets.QStyle.SP_DialogApplyButton)
        icon_warning = self.style().standardIcon(QtWidgets.QStyle.SP_MessageBoxWarning)
        icon_review = self.style().standardIcon(QtWidgets.QStyle.SP_MessageBoxInformation)
        # In UEMR mode we rename "Spectrum & Reuse" -> "Spectrum" and
        # "Service & Demand" -> "Service" at the tab-widget level, but the
        # status-payload dict is keyed by the ORIGINAL tab names. Map the
        # renamed labels back so the lookup doesn't silently miss.
        _uemr_label_aliases = {
            "Spectrum": "Spectrum & Reuse",
            "Service": "Service & Demand",
        }
        for tab_index in range(self.tab_widget.count()):
            label = self.tab_widget.tabText(tab_index)
            status = statuses_use.get(label)
            if status is None and label in _uemr_label_aliases:
                status = statuses_use.get(_uemr_label_aliases[label])
            item = self.simulation_page_list.item(tab_index)
            if status is None or item is None:
                continue
            review_pending = bool(status.get("review_pending"))
            item.setIcon(
                icon_ready
                if bool(status["ready"])
                else (icon_review if review_pending else icon_warning)
            )
            item.setData(QtCore.Qt.UserRole + 1, bool(status["ready"]))
            item.setToolTip(str(status["message"]))

        banner_map = {
            "RAS Station": self.ras_notice_banner,
            "Satellite Orbitals": self.constellation_notice_banner,
            "Satellite Antennas": self.antennas_notice_banner,
            "Service & Demand": self.service_notice_banner,
            "Spectrum & Reuse": self.spectrum_notice_banner,
            "Coverage & Contours": self.grid_notice_banner,
            "Coverage & Boresight": self.hexgrid_notice_banner,
            "Review & Run": self.runtime_notice_banner,
        }
        for label, banner in banner_map.items():
            status = statuses_use[label]
            banner.show_message(str(status["message"]), kind=str(status["kind"]))

    def _update_snapshot_panel(
        self,
        state: ScepterProjectState,
        *,
        statuses: Mapping[str, Mapping[str, Any]] | None = None,
    ) -> None:
        # Defensive guard: if any of the snapshot widgets the body
        # below touches has had its C++ side destroyed, skip the
        # update rather than dereferencing a dangling wrapper. This
        # path has been observed to crash with a native access
        # violation on Windows when the Qt test-suite cached-window
        # pattern races a parent teardown. ``shiboken6.isValid`` is
        # the canonical PySide6 alive-check.
        try:
            import shiboken6 as _shiboken  # type: ignore[import-not-found]
        except Exception:
            _shiboken = None  # pragma: no cover — non-PySide build
        if _shiboken is not None:
            for _w in (
                getattr(self, "snapshot_step_list", None),
                getattr(self, "snapshot_title_label", None),
                getattr(self, "snapshot_detail_label", None),
                getattr(self, "snapshot_overview_label", None),
                getattr(self, "snapshot_chip", None),
            ):
                if _w is not None and not _shiboken.isValid(_w):
                    return
        try:
            self._update_snapshot_panel_body(state, statuses=statuses)
        except Exception:
            # Swallow any Python-level error so a stale widget
            # reference can't poison subsequent tests or propagate
            # from a background refresh into the run's exit code.
            # Native crashes still bypass this — they're guarded by
            # the shiboken.isValid check above.
            return

    def _update_snapshot_panel_body(
        self,
        state: ScepterProjectState,
        *,
        statuses: Mapping[str, Mapping[str, Any]] | None = None,
    ) -> None:
        statuses_use = (
            self._simulation_page_statuses(state)
            if statuses is None
            else {
                str(label): dict(status)
                for label, status in statuses.items()
            }
        )
        ordered_labels = list(_WORKFLOW_STATUS_ORDER)
        ready_count = 0
        outstanding_labels: list[str] = []
        for label in ordered_labels:
            status = statuses_use[label]
            if bool(status["ready"]) or bool(status.get("review_pending")):
                ready_count += 1
            else:
                outstanding_labels.append(label)

        guidance_kind, guidance_title, guidance_detail, _, guidance_action = self._guidance_payload(
            state,
            statuses=statuses_use,
        )
        review_pending = bool(statuses_use["Review & Run"].get("review_pending"))
        if self._run_in_progress:
            chip_text = "Running"
            chip_kind = "ready"
            title = "Simulation is running"
            detail = "The workflow is complete enough to run. Use the monitor below for live iteration and writer progress."
        elif self._review_run_state == "completed":
            chip_text = "Completed"
            chip_kind = "ready"
            title = "Latest run completed"
            detail = "The result file is ready to inspect in Postprocess or to rerun with adjusted parameters."
        elif self._review_run_state == "stopped":
            chip_text = "Stopped"
            chip_kind = "review"
            title = "Latest run stopped cleanly"
            detail = "Partial results were flushed and can still be opened in Postprocess."
        elif ready_count <= 0:
            chip_text = "Getting started"
            chip_kind = "progress"
            title = "Start filling the workflow"
            detail = (
                f"Guidance next: {guidance_title}. {guidance_detail}"
                if guidance_title
                else "The snapshot follows each simulation step and highlights the next useful action without blocking you."
            )
        elif review_pending:
            chip_text = "Ready for review"
            chip_kind = "review"
            title = "All setup steps are in place"
            detail = "Guidance next: Review runtime, output families, and storage choices before launching the run."
        else:
            chip_text = "In progress"
            chip_kind = "warning"
            title = f"{ready_count}/{len(ordered_labels)} workflow steps are ready"
            detail = (
                f"Guidance next: {guidance_title}. {guidance_detail}"
                if guidance_title
                else (
                    f"Next focus: {statuses_use[outstanding_labels[0]]['title']}."
                    if outstanding_labels
                    else "Keep refining the setup or review outputs before running."
                )
            )
        self._set_assistant_chip_state(
            self.snapshot_chip,
            text=chip_text,
            state_kind=chip_kind,
        )
        self.snapshot_title_label.setText(title)
        self.snapshot_detail_label.setText(detail)
        self.snapshot_overview_label.setText(
            self._compact_panel_text(
                f"Workflow {ready_count}/{len(ordered_labels)} ready. Guidance next: {guidance_title}.",
                max_chars=140,
            )
        )

        icon_ready = self.style().standardIcon(QtWidgets.QStyle.SP_DialogApplyButton)
        icon_warning = self.style().standardIcon(QtWidgets.QStyle.SP_MessageBoxWarning)
        icon_review = self.style().standardIcon(QtWidgets.QStyle.SP_MessageBoxInformation)
        self.snapshot_step_list.clear()
        def _block_state_text(label: str) -> str:
            status = statuses_use[label]
            if bool(status["ready"]):
                return "Ready"
            if bool(status.get("review_pending")):
                return "Ready for review"
            return "Needs attention"

        def _format_optional(value: Any, suffix: str = "") -> str:
            if value is None:
                return "unset"
            try:
                numeric = float(value)
            except Exception:
                return f"{value}{suffix}"
            if not np.isfinite(numeric):
                return "unset"
            return f"{numeric:g}{suffix}"

        s0 = state.active_system()
        ras_cfg = state.ras_station
        ras_ant = state.ras_antenna
        try:
            power_input_summary = _service_power_input_summary(_require_service_power_input(state))
        except ValueError:
            power_input_summary = "power input incomplete"
        contour_state = statuses_use["Coverage & Contours"]
        hexgrid_state = statuses_use["Coverage & Boresight"]
        shared_frequency_text = (
            f"{float(s0.satellite_antennas.frequency_mhz):g} MHz"
            if s0.satellite_antennas.frequency_mhz is not None
            else "unset"
        )
        contour_value = self._effective_hexgrid_cell_size_km(state)
        boresight_enabled = bool(getattr(s0.hexgrid, "boresight_avoidance_enabled", False))
        block_lines = {
            "RAS Station": (
                f"{_block_state_text('RAS Station')} | "
                f"lon {_format_optional(getattr(ras_cfg, 'longitude_deg', None), ' deg')}, "
                f"lat {_format_optional(getattr(ras_cfg, 'latitude_deg', None), ' deg')}, "
                f"diameter {_format_optional(getattr(ras_ant, 'antenna_diameter_m', None) if ras_ant is not None else None, ' m')}, "
                f"RX {_format_optional(getattr(ras_cfg, 'receiver_band_start_mhz', None), ' MHz')}"
                f" to {_format_optional(getattr(ras_cfg, 'receiver_band_stop_mhz', None), ' MHz')}"
            ),
            "Satellite Orbitals": (
                f"{_block_state_text('Satellite Orbitals')} | {len(s0.belts)} belt(s) configured"
            ),
            "Satellite Antennas": (
                f"{_block_state_text('Satellite Antennas')} | "
                f"model {str(s0.satellite_antennas.antenna_model or 'unset')}, "
                f"RF {shared_frequency_text}"
            ),
            "Service & Demand": (
                f"{_block_state_text('Service & Demand')} | "
                f"Nco {_format_optional(s0.service.nco)}, "
                f"Nbeam {_format_optional(s0.service.nbeam)}, "
                f"{power_input_summary}"
            ),
            "Spectrum & Reuse": (
                f"{_block_state_text('Spectrum & Reuse')} | "
                f"reuse {('F' + str(int(s0.spectrum.reuse_factor))) if s0.spectrum.reuse_factor is not None else 'unset'}, "
                f"service {_format_optional(s0.spectrum.service_band_start_mhz, ' MHz')}"
                f" to {_format_optional(s0.spectrum.service_band_stop_mhz, ' MHz')}"
            ),
            "Coverage & Contours": (
                f"{_block_state_text('Coverage & Contours')} | "
                + (
                    f"spacing {float(contour_value):g} km {'current' if contour_state['ready'] else 'stale'}"
                    if contour_value is not None
                    else "no contour spacing stored yet"
                )
            ),
            "Coverage & Boresight": (
                f"{_block_state_text('Coverage & Boresight')} | "
                f"mask {s0.hexgrid.geography_mask_mode}, "
                f"boresight {'on' if boresight_enabled else 'off'}, "
                f"{'current' if hexgrid_state['ready'] else 'not committed'}"
            ),
            "Review & Run": (
                f"{_block_state_text('Review & Run')} | "
                + (
                    "latest run completed"
                    if self._review_run_state == "completed"
                    else (
                        "latest run stopped cleanly"
                        if self._review_run_state == "stopped"
                        else (
                            "runtime/output review ready"
                            if review_pending
                            else "preflight still needs attention"
                        )
                    )
                )
            ),
        }
        for label in ordered_labels:
            status = statuses_use[label]
            step_item = QtWidgets.QListWidgetItem(
                self._compact_panel_text(f"{label}: {block_lines[label]}", max_chars=135),
                self.snapshot_step_list,
            )
            step_item.setData(QtCore.Qt.UserRole, label)
            step_item.setToolTip(str(status["message"]))
            review_pending_step = bool(status.get("review_pending"))
            step_item.setIcon(
                icon_ready
                if bool(status["ready"])
                else (icon_review if review_pending_step else icon_warning)
            )
        if self.snapshot_step_list.count() > 0:
            row_height = max(self.snapshot_step_list.sizeHintForRow(0), 24)
            visible_rows = min(self.snapshot_step_list.count(), 6)
            preferred_height = (
                row_height * visible_rows
                + (self.snapshot_step_list.frameWidth() * 2)
                + 6
            )
            self.snapshot_step_list.setMinimumHeight(
                min(preferred_height, max(row_height * 2, 72))
            )
            self.snapshot_step_list.setMaximumHeight(max(preferred_height, 96))
        else:
            self.snapshot_step_list.setMinimumHeight(72)
            self.snapshot_step_list.setMaximumHeight(96)

    def _guidance_payload(
        self,
        state: ScepterProjectState,
        *,
        statuses: Mapping[str, Mapping[str, Any]] | None = None,
    ) -> tuple[str, str, str, QtWidgets.QWidget | None, str]:
        statuses_use = (
            self._simulation_page_statuses(state)
            if statuses is None
            else {
                str(label): dict(status)
                for label, status in statuses.items()
            }
        )
        ordered_labels = [
            "RAS Station",
            "Satellite Orbitals",
            "Satellite Antennas",
            "Service & Demand",
            "Coverage & Contours",
            "Coverage & Boresight",
            "Review & Run",
        ]
        for label in ordered_labels:
            status = statuses_use[label]
            if not bool(status["ready"]):
                return (
                    str(status["kind"]),
                    str(status["title"]),
                    str(status["message"]),
                    status["target"],
                    str(status["action"]),
                )
        ready_status = statuses_use["Review & Run"]
        return (
            "ready",
            str(ready_status["title"]),
            str(ready_status["message"]),
            ready_status["target"],
            "Review outputs and run",
        )

    def _update_guidance_panel(
        self,
        state: ScepterProjectState,
        *,
        statuses: Mapping[str, Mapping[str, Any]] | None = None,
    ) -> None:
        kind, title, detail, target, action = self._guidance_payload(
            state,
            statuses=statuses,
        )
        self._guidance_target = target
        self.guidance_action_button.setText(action)
        self._set_assistant_chip_state(
            self.guidance_chip,
            text="Ready" if kind == "ready" else "Needs attention",
            state_kind="ready" if kind == "ready" else "warning",
        )
        self.guidance_title_label.setText(title)
        self.guidance_detail_label.setText(self._compact_panel_text(detail, max_chars=125))

    def _set_assistant_chip_state(
        self,
        chip: QtWidgets.QLabel,
        *,
        text: str,
        state_kind: str,
    ) -> None:
        chip.setText(str(text))
        chip.setProperty("stateKind", str(state_kind))
        chip.style().unpolish(chip)
        chip.style().polish(chip)
        chip.update()

    def _apply_workflow_status_payloads(
        self,
        state: ScepterProjectState,
        status_payloads: Mapping[str, Mapping[str, Any]],
    ) -> None:
        statuses = self._simulation_page_statuses(state, status_payloads=status_payloads)
        self._update_snapshot_panel(state, statuses=statuses)
        self._update_guidance_panel(state, statuses=statuses)
        self._update_simulation_page_indicators(state, statuses=statuses)

    def _schedule_async_workflow_summary_refresh(self) -> None:
        if self._state_load_in_progress:
            return
        state_snapshot = self.current_state()
        request = self._workflow_status_request(state_snapshot)
        self._workflow_summary_generation += 1
        generation = int(self._workflow_summary_generation)

        def _worker() -> None:
            try:
                payloads = _compute_workflow_status_payloads(
                    state_snapshot,
                    **request,
                )
                result = {
                    "state": state_snapshot,
                    "payloads": payloads,
                    "error": None,
                }
            except Exception as exc:  # pragma: no cover - defensive
                result = {
                    "state": state_snapshot,
                    "payloads": None,
                    "error": str(exc),
                }
            self._workflow_summary_emitter.completed.emit(generation, result)

        threading.Thread(
            target=_worker,
            name=f"scepter-summary-{generation}",
            daemon=True,
        ).start()

    @QtCore.Slot(int, object)
    def _on_workflow_summary_completed(self, generation: int, result: object) -> None:
        if int(generation) != int(self._workflow_summary_generation):
            return
        if not isinstance(result, Mapping):
            return
        error_message = result.get("error")
        if error_message:
            self.statusBar().showMessage(
                f"Workflow summary refresh failed: {error_message}",
                5000,
            )
            return
        state_snapshot = result.get("state")
        status_payloads = result.get("payloads")
        if not isinstance(state_snapshot, ScepterProjectState) or not isinstance(status_payloads, Mapping):
            return
        self._apply_workflow_status_payloads(state_snapshot, status_payloads)

    def _jump_to_guidance_target(self) -> None:
        target = getattr(self, "_guidance_target", None)
        if target is None:
            return
        self._set_workspace(_WORKSPACE_SIMULATION)
        page = self._simulation_page_for_target(target)
        idx = self.tab_widget.indexOf(page) if page is not None else -1
        # Don't navigate to a tab that has been hidden (e.g. coverage tabs
        # under UEMR). Fall through silently instead of popping a blank
        # page into view.
        if idx >= 0 and self.tab_widget.tabBar().isTabVisible(idx):
            self.tab_widget.setCurrentIndex(idx)
        self._highlight_widget(target if isinstance(target, QtWidgets.QWidget) else page)

    def open_result_file(self) -> None:
        filename, _ = QtWidgets.QFileDialog.getOpenFileName(
            self,
            "Open Result File",
            str(Path.cwd()),
            "HDF5 files (*.h5 *.hdf5);;All files (*.*)",
        )
        if filename:
            self._open_result_in_postprocess(filename)

    def _open_result_in_postprocess(self, filename: str) -> None:
        try:
            self.postprocess_widget.open_result_file(filename)
        except Exception as exc:
            _show_exception_warning(self, "Open result failed", "Couldn't open the selected result file.", exc)
            return
        self._remember_recent_result(filename)
        self._set_workspace(_WORKSPACE_POSTPROCESS)

    def _open_recent_config_item(self, item: QtWidgets.QListWidgetItem) -> None:
        path = str(item.data(QtCore.Qt.UserRole) or "")
        if not path:
            return
        try:
            state = load_project_state(path)
        except Exception as exc:
            _show_exception_warning(self, "Load failed", "Couldn't load the recent project file.", exc)
            return
        self._current_path = Path(path)
        self._dirty = False
        self._load_state_into_widgets(state)
        self._remember_recent_config(path)
        self._set_workspace(_WORKSPACE_SIMULATION)
        self._update_window_title()

    def _open_recent_result_item(self, item: QtWidgets.QListWidgetItem) -> None:
        path = str(item.data(QtCore.Qt.UserRole) or "")
        if path:
            self._open_result_in_postprocess(path)


