    def _update_window_title(self) -> None:
        filename = self._current_path.name if self._current_path is not None else "Untitled"
        self.setWindowTitle(
            appinfo.format_gui_window_title(filename, dirty=self._dirty)
        )

    def _selected_belt_row(self) -> int:
        selection = self.belt_table.selectionModel()
        if selection is None or not selection.hasSelection():
            return -1
        rows = selection.selectedRows()
        return int(rows[0].row()) if rows else -1

    def _shared_frequency_value_or_none(self) -> float | None:
        widget = getattr(self, "frequency_spin", None)
        if isinstance(widget, OptionalNumericEdit):
            value = widget.value_or_none()
            if value is not None:
                return float(value)
        return None

    def _set_shared_frequency_widgets(self, value: float | None) -> None:
        widget = getattr(self, "frequency_spin", None)
        if isinstance(widget, OptionalNumericEdit):
            blocker = QtCore.QSignalBlocker(widget)
            widget.set_value(value)
            del blocker

    def _has_valid_cell_size_override(self, state: ScepterProjectState) -> bool:
        ga = state.active_system().grid_analysis
        value = ga.cell_size_override_km
        return bool(
            ga.cell_size_override_enabled
            and value is not None
            and np.isfinite(float(value))
            and float(value) > 0.0
        )

    def _analyser_signature(
        self,
        state: ScepterProjectState,
    ) -> tuple[Any, ...] | None:
        s0 = state.active_system()
        if len(s0.belts) < 1:
            return None
        sa = s0.satellite_antennas
        if not _has_valid_satellite_antenna_config(sa):
            return None
        antenna_model = str(sa.antenna_model or "")
        ga = s0.grid_analysis
        return (
            tuple(json.dumps(belt.to_json_dict(), sort_keys=True) for belt in s0.belts),
            round(float(sa.frequency_mhz), 9),
            bool(sa.derive_pattern_wavelength_from_frequency),
            None
            if sa.pattern_wavelength_cm is None
            else round(float(sa.pattern_wavelength_cm), 9),
            antenna_model,
            json.dumps(sa.rec12.to_json_dict(), sort_keys=True),
            json.dumps(sa.rec14.to_json_dict(), sort_keys=True),
            str(ga.indicative_footprint_drop),
            str(ga.spacing_drop),
            str(ga.leading_metric),
            str(ga.cell_spacing_rule),
        )

    def _contour_is_current(self, state: ScepterProjectState) -> bool:
        if self._has_valid_cell_size_override(state):
            return True
        analyser_signature = self._analyser_signature(state)
        return bool(
            analyser_signature is not None
            and self._last_analyser_selected_cell_km is not None
            and analyser_signature == self._last_analyser_signature
        )

    def _current_runtime_output_families(self) -> dict[str, dict[str, Any]]:
        """Collect the per-family output widget state into canonical runtime configs."""
        runtime_output_families = _default_output_families_config()
        for family_name, widgets in self.runtime_output_family_widgets.items():
            family_config = dict(runtime_output_families[family_name])
            mode_widget = widgets.get("mode")
            if isinstance(mode_widget, QtWidgets.QComboBox):
                family_config["mode"] = str(
                    mode_widget.currentData() or family_config.get("mode", "none")
                )
            range_widget = widgets.get("range_mode")
            if isinstance(range_widget, QtWidgets.QComboBox):
                family_config["range_mode"] = str(
                    range_widget.currentData() or family_config.get("range_mode", "dynamic")
                )
            for field_name, widget in widgets.items():
                if field_name in {"mode", "range_mode"}:
                    continue
                if isinstance(widget, OptionalNumericEdit):
                    family_config[field_name] = widget.value_or_none()
            runtime_output_families[family_name] = family_config
        return runtime_output_families

    def _current_ras_station_config(self) -> RasStationConfig | None:
        receiver_response_mode = (
            None
            if self.ras_receiver_response_mode_combo.currentData() in {None, ""}
            else str(self.ras_receiver_response_mode_combo.currentData())
        )
        ras_reference_mode = (
            None
            if self.spectrum_ras_reference_combo.currentData() in {None, ""}
            else str(self.spectrum_ras_reference_combo.currentData())
        )
        ras_station = RasStationConfig(
            longitude_deg=self.longitude_spin.value_or_none(),
            latitude_deg=self.latitude_spin.value_or_none(),
            elevation_m=self.elevation_spin.value_or_none(),
            receiver_band_start_mhz=self.spectrum_ras_band_start_edit.value_or_none(),
            receiver_band_stop_mhz=self.spectrum_ras_band_stop_edit.value_or_none(),
            receiver_response_mode=receiver_response_mode,
            receiver_custom_mask_points=getattr(self, "_ras_receiver_custom_mask_points", None),
            ras_reference_mode=ras_reference_mode,
            ras_reference_point_count=(
                None
                if ras_reference_mode is None
                else (
                    1
                    if self.spectrum_ras_reference_combo.currentData() != "n_point"
                    else int(self.spectrum_ras_reference_points_spin.value())
                )
            ),
        )
        return ras_station if _has_any_ras_station_value(ras_station) else None

    def _selected_service_power_quantity(self) -> str:
        return str(
            self.service_power_quantity_combo.currentData()
            or _DEFAULT_SERVICE_POWER_INPUT_QUANTITY
        )

    def _selected_service_power_basis(self) -> str:
        return str(
            self.service_power_basis_combo.currentData()
            or _DEFAULT_SERVICE_POWER_INPUT_BASIS
        )

    def _selected_service_power_editor(self) -> OptionalNumericEdit:
        return self._service_power_editors[
            (self._selected_service_power_quantity(), self._selected_service_power_basis())
        ]

    def _set_combo_to_data(self, combo: QtWidgets.QComboBox, value: Any) -> None:
        idx = combo.findData(value)
        if idx >= 0:
            combo.setCurrentIndex(idx)

    def _populate_gpu_device_combo(self) -> None:
        """Detect available CUDA devices and populate the GPU device selector.

        Falls back to a single "Default (GPU 0)" entry when CUDA is not
        available or device enumeration fails.  Each item stores the
        integer device ID as ``userData`` (or ``None`` for "auto").
        """
        combo = self.runtime_gpu_device_combo
        combo.clear()
        combo.addItem("Auto (default GPU)", userData=None)
        try:
            from numba import cuda as _cuda
            if _cuda.is_available():
                devices = _cuda.gpus
                for i, dev in enumerate(devices):
                    try:
                        ctx = dev.get_primary_context()
                        ctx.push()
                        d = _cuda.get_current_device()
                        name = getattr(d, "name", f"GPU {i}")
                        if isinstance(name, bytes):
                            name = name.decode("utf-8", "replace")
                        mem_info = dev.get_primary_context().get_memory_info()
                        vram_gb = mem_info[1] / (1024 ** 3)
                        label = f"[{i}] {name} ({vram_gb:.1f} GB)"
                        ctx.pop()
                    except Exception:
                        label = f"[{i}] GPU {i}"
                    combo.addItem(label, userData=int(i))
                # Hide the entire row when there's only one GPU
                # (the "Auto" entry is sufficient).
                if len(devices) <= 1:
                    self._gpu_device_single_gpu = True
                else:
                    self._gpu_device_single_gpu = False
        except Exception:
            pass

    def _sync_surface_pfd_cap_controls(self) -> None:
        """Reflect the cap checkbox state on the limit edit + mode combo.

        Shows or hides the entire cap-fields container (limit input +
        cap mode dropdown + info note) based on the checkbox state.
        Also picks the per-MHz vs per-channel edit to match the current
        service power basis, updates the limit label unit, and toggles
        the Review & Run "Surface-PFD cap stats" reporting row.
        """
        enabled = bool(self._surface_pfd_cap_group.isChecked())
        self._surface_pfd_cap_fields.setVisible(enabled)
        # Keep the stacked MHz/channel edit in sync with power basis so
        # the same numerical unit is used across the two controls.
        basis = self._selected_service_power_basis()
        target_index = 0 if basis == "per_mhz" else 1
        self._max_surface_pfd_value_stack.setCurrentIndex(target_index)
        # Update the limit label to show the active unit.
        if basis == "per_mhz":
            self._max_surface_pfd_limit_label.setText("Limit [dBW/m\u00b2/MHz]")
        else:
            self._max_surface_pfd_limit_label.setText("Limit [dBW/m\u00b2/channel]")
        # Review & Run reporting row — only show when cap is on.
        if hasattr(self, "runtime_surface_pfd_stats_checkbox"):
            self.runtime_surface_pfd_stats_checkbox.setVisible(enabled)
            self._runtime_surface_pfd_stats_row_label.setVisible(enabled)
            if not enabled:
                # Uncheck on hide so the next save doesn't leave a stale
                # stats flag in the project.  User can re-enable after
                # toggling the cap back on.
                if self.runtime_surface_pfd_stats_checkbox.isChecked():
                    self.runtime_surface_pfd_stats_checkbox.setChecked(False)

    def _on_max_surface_pfd_toggle_changed(self, *_args: object) -> None:
        self._sync_surface_pfd_cap_controls()
        self._on_state_changed()

    def _sync_service_power_controls(self) -> None:
        quantity = self._selected_service_power_quantity()
        basis = self._selected_service_power_basis()
        self._update_service_power_help_metadata()
        self.service_power_mode_note.clear()
        self.service_power_mode_note.hide()
        # Keep the surface-PFD cap edit in sync with the selected basis
        # (per_mhz ↔ per_channel) whenever the power basis changes.
        if hasattr(self, "max_surface_pfd_enable_check"):
            self._sync_surface_pfd_cap_controls()
        # Auto-fill the newly-selected basis editor from the other basis'
        # value. Without this, a user who flips "per MHz → per channel"
        # after entering a Ptx value sees an empty field and the
        # validator reports "service incomplete" even though their input
        # is fully determined. This matches the conversion-safe semantics
        # in ``scenario.normalize_direct_epfd_power_input``.
        bw_raw = self.service_bandwidth_edit.value_or_none()
        try:
            bw_mhz = float(bw_raw) if bw_raw is not None else None
        except Exception:
            bw_mhz = None
        if bw_mhz is not None and np.isfinite(bw_mhz) and bw_mhz > 0.0:
            editor_map = {
                (q, b): w for q, b, w in self._service_power_editor_order
            }
            active_widget = editor_map.get((quantity, basis))
            other_basis = "per_channel" if basis == "per_mhz" else "per_mhz"
            other_widget = editor_map.get((quantity, other_basis))
            if active_widget is not None and other_widget is not None:
                active_val = active_widget.value_or_none()
                other_val = other_widget.value_or_none()
                active_empty = active_val is None or not np.isfinite(float(active_val))
                other_has = other_val is not None and np.isfinite(float(other_val))
                if active_empty and other_has:
                    try:
                        from scepter.scenario import convert_direct_epfd_power_basis_db
                        converted = convert_direct_epfd_power_basis_db(
                            float(other_val),
                            bandwidth_mhz=float(bw_mhz),
                            from_basis=other_basis,
                            to_basis=basis,
                        )
                        blocker = QtCore.QSignalBlocker(active_widget)
                        active_widget.set_value(round(float(converted), 6))
                        del blocker
                    except Exception:
                        pass
        for idx, (editor_quantity, editor_basis, _widget) in enumerate(
            self._service_power_editor_order
        ):
            if editor_quantity == quantity and editor_basis == basis:
                self.service_power_value_stack.setCurrentIndex(idx)
                break
        # Power variation visibility and labelling
        var_mode = str(self.service_power_variation_combo.currentData() or "fixed")
        is_target_pfd = quantity == "target_pfd"
        # UEMR mode forces a fixed power value (no stochastic variation) —
        # keep variation widgets hidden regardless of quantity.
        _uemr_active_here = False
        try:
            _uemr_active_here = _system_is_uemr(self.current_state().active_system())
        except Exception:
            pass
        show_variation = (not is_target_pfd) and (not _uemr_active_here)
        is_range = show_variation and var_mode != "fixed"
        unit = _service_power_value_unit(quantity, basis)
        qty_label = _service_power_quantity_label(quantity)
        self._power_variation_label.setVisible(show_variation)
        self._power_variation_widget.setVisible(show_variation)
        if is_range:
            # Range mode: hide the single-value row, show min/max
            self.service_power_value_label.setVisible(False)
            self._power_value_widget.setVisible(False)
            self._power_range_min_label.setText(f"{qty_label} min [{unit}]")
            self._power_range_max_label.setText(f"{qty_label} max [{unit}]")
            self._power_range_min_label.setVisible(True)
            self._power_range_min_widget.setVisible(True)
            self._power_range_max_label.setVisible(True)
            self._power_range_max_widget.setVisible(True)
        else:
            # Fixed mode: show the single-value row, hide min/max
            self.service_power_value_label.setText(f"{qty_label} [{unit}]")
            self.service_power_value_label.setVisible(True)
            self._power_value_widget.setVisible(True)
            self._power_range_min_label.setVisible(False)
            self._power_range_min_widget.setVisible(False)
            self._power_range_max_label.setVisible(False)
            self._power_range_max_widget.setVisible(False)

        try:
            power_input = _normalize_service_config_power_input(self._current_service_config())
        except Exception:
            if _uemr_active_here:
                self.service_power_equivalent_label.setText(
                    f"Enter a finite {qty_label} value for the selected basis. "
                    "UEMR mode uses the service band width automatically — no "
                    "separate channel bandwidth is needed."
                )
            else:
                self.service_power_equivalent_label.setText(
                    "Enter a positive channel bandwidth and a finite value for the selected power quantity/basis."
                )
            return
        complementary_basis = "per_channel" if basis == "per_mhz" else "per_mhz"
        complementary_key = f"{quantity}_dbw_mhz"
        if quantity == "target_pfd":
            complementary_key = (
                "target_pfd_dbw_m2_channel"
                if complementary_basis == "per_channel"
                else "target_pfd_dbw_m2_mhz"
            )
        elif quantity == "satellite_ptx":
            complementary_key = (
                "satellite_ptx_dbw_channel"
                if complementary_basis == "per_channel"
                else "satellite_ptx_dbw_mhz"
            )
        elif quantity == "satellite_eirp":
            complementary_key = (
                "satellite_eirp_dbw_channel"
                if complementary_basis == "per_channel"
                else "satellite_eirp_dbw_mhz"
            )
        complementary_value = power_input.get(complementary_key)
        if complementary_value is None or not np.isfinite(float(complementary_value)):
            self.service_power_equivalent_label.setText(
                "Equivalent value unavailable for the current service power definition."
            )
            return
        self.service_power_equivalent_label.setText(
            f"Equivalent {_service_power_quantity_label(quantity)} {_service_power_basis_label(complementary_basis)}: "
            f"{float(complementary_value):.2f} {_service_power_value_unit(quantity, complementary_basis)}."
        )

    def _selected_appearance_mode(self) -> str:
        return str(self.appearance_mode_combo.currentData() or _DEFAULT_APPEARANCE_MODE)

    def _refresh_reuse_factor_highlights(self, plan: Mapping[str, Any] | None) -> None:
        exact_fit_factors = set()
        if isinstance(plan, Mapping):
            exact_fit_factors = {
                int(value) for value in plan.get("zero_leftover_reuse_factors", ())
            }
        for idx in range(self.spectrum_reuse_factor_combo.count()):
            value = self.spectrum_reuse_factor_combo.itemData(idx)
            if value in {None, ""}:
                self.spectrum_reuse_factor_combo.setItemText(idx, "Select reuse scheme...")
                self.spectrum_reuse_factor_combo.setItemData(idx, None, QtCore.Qt.ForegroundRole)
                self.spectrum_reuse_factor_combo.setItemData(
                    idx,
                    self.spectrum_reuse_factor_combo.font(),
                    QtCore.Qt.FontRole,
                )
                self.spectrum_reuse_factor_combo.setItemData(
                    idx,
                    "Choose a reuse scheme after the service band and channel bandwidth are known.",
                    QtCore.Qt.ToolTipRole,
                )
                continue
            label_text = f"F{int(value)}"
            if int(value) in exact_fit_factors:
                label_text += "  exact fit"
                font = self.spectrum_reuse_factor_combo.font()
                font.setBold(True)
                self.spectrum_reuse_factor_combo.setItemData(idx, font, QtCore.Qt.FontRole)
                self.spectrum_reuse_factor_combo.setItemData(
                    idx,
                    QtGui.QBrush(QtGui.QColor("#15803d")),
                    QtCore.Qt.ForegroundRole,
                )
                self.spectrum_reuse_factor_combo.setItemData(
                    idx,
                    "This reuse factor leaves no unused spectrum with the current service band and channel bandwidth.",
                    QtCore.Qt.ToolTipRole,
                )
            else:
                self.spectrum_reuse_factor_combo.setItemData(
                    idx,
                    self.spectrum_reuse_factor_combo.font(),
                    QtCore.Qt.FontRole,
                )
                self.spectrum_reuse_factor_combo.setItemData(idx, None, QtCore.Qt.ForegroundRole)
                self.spectrum_reuse_factor_combo.setItemData(
                    idx,
                    "This reuse factor leaves some spectrum unused for the current service band and channel bandwidth.",
                    QtCore.Qt.ToolTipRole,
                )
            self.spectrum_reuse_factor_combo.setItemText(idx, label_text)

    def _sync_spectrum_controls(self) -> None:
        service_cfg = self._current_service_config()
        spectrum_cfg = self._current_explicit_spectrum_config()
        ras_cfg = self._current_ras_station_config()
        partial_plan = _partial_spectrum_band_plan(service_cfg, spectrum_cfg)
        spectrum_has_explicit_inputs = self._workflow_has_explicit_spectrum_inputs()
        level_rank = _COMPLEXITY_RANK.get(
            str(self.complexity_mode_combo.currentData() or "Advanced"),
            1,
        )
        reuse_factor = (
            None
            if spectrum_cfg.reuse_factor is None
            else max(1, int(spectrum_cfg.reuse_factor))
        )
        if reuse_factor is None:
            blocker = QtCore.QSignalBlocker(self.spectrum_anchor_slot_spin)
            self._rebuild_anchor_slot_items(reuse_factor=1)
            del blocker
        else:
            self._rebuild_anchor_slot_items(reuse_factor=int(reuse_factor))
        tx_mode = str(spectrum_cfg.tx_reference_mode or "")
        ras_mode = str(
            (None if ras_cfg is None else ras_cfg.ras_reference_mode)
            or _DEFAULT_SPECTRUM_RAS_REFERENCE_MODE
        )
        receiver_mode = str(
            (None if ras_cfg is None else ras_cfg.receiver_response_mode)
            or _DEFAULT_RAS_RECEIVER_RESPONSE_MODE
        )
        if tx_mode != "n_point" and self.spectrum_tx_reference_points_spin.value() != 1:
            blocker = QtCore.QSignalBlocker(self.spectrum_tx_reference_points_spin)
            self.spectrum_tx_reference_points_spin.setValue(1)
            del blocker
        if ras_mode != "n_point" and self.spectrum_ras_reference_points_spin.value() != 1:
            blocker = QtCore.QSignalBlocker(self.spectrum_ras_reference_points_spin)
            self.spectrum_ras_reference_points_spin.setValue(1)
            del blocker
        show_expert = level_rank >= _COMPLEXITY_RANK["Expert"]
        self._set_form_row_visible(
            self._spectrum_reference_form,
            self.spectrum_tx_reference_points_field,
            show_expert and tx_mode == "n_point",
        )
        self._set_form_row_visible(
            self._ras_receiver_form,
            self.spectrum_ras_reference_points_field,
            ras_mode == "n_point",
        )
        mask_is_custom = str(spectrum_cfg.unwanted_emission_mask_preset) == "custom"
        self.edit_custom_mask_button.setEnabled(mask_is_custom)
        self.spectrum_anchor_slot_spin.setEnabled(reuse_factor is not None)
        self.spectrum_power_policy_combo.setEnabled(reuse_factor is not None)
        self.show_reuse_scheme_button.setEnabled(
            spectrum_has_explicit_inputs and reuse_factor is not None
        )
        receiver_ready, receiver_message = _validate_ras_receiver_config(ras_cfg)
        receiver_button_ready, _ = _validate_ras_receiver_band(ras_cfg)
        self.ras_receiver_response_tool_button.setEnabled(bool(receiver_button_ready))
        self.ras_receiver_response_tool_button.setText(
            "Edit Receiver Response"
            if receiver_mode == "custom"
            else "Preview Receiver Response"
        )
        self.ras_receiver_summary_label.setText(
            (
                f"RAS receiver band {float(ras_cfg.receiver_band_start_mhz):.3f} to "
                f"{float(ras_cfg.receiver_band_stop_mhz):.3f} MHz | "
                f"response {receiver_mode} | "
                f"reference {ras_mode}. Edit Spectrum on Spectrum & Reuse controls the Tx-side overlap view."
            )
            if receiver_ready and ras_cfg is not None
            else (
                "RAS receiver response uses the RAS receiver band defined here. "
                "Set the receiver band and response mode to preview or edit the receive-side response here. "
                "Tx spectrum editing stays on Spectrum & Reuse."
                if ras_cfg is None
                else f"Receiver response needs attention: {receiver_message}"
            )
        )
        if not spectrum_has_explicit_inputs:
            self._refresh_reuse_factor_highlights(partial_plan)
            uemr_active_here = False
            try:
                uemr_active_here = _system_is_uemr(self.current_state().active_system())
            except Exception:
                pass
            if uemr_active_here:
                self.spectrum_summary_label.setText(
                    "Spectrum inputs are blank. In UEMR mode, set the service band "
                    "(defines the transmitter's intended operating band) and the "
                    "transmit unwanted-emission mask here, then define the RAS "
                    "receiver band on the RAS Station tab."
                )
                self.spectrum_zero_leftover_label.setText("")
                self.spectrum_leakage_summary_label.setText(
                    "Set a valid service band, transmitter mask, channel bandwidth, "
                    "and a valid RAS receiver band on the RAS Station tab to preview "
                    "leakage."
                )
            else:
                self.spectrum_summary_label.setText(
                    "Spectrum inputs are blank. Enter the service band and reuse settings here, then define the RAS receiver band on the RAS Station tab, or apply the spectrum defaults."
                )
                if partial_plan is None:
                    self.spectrum_zero_leftover_label.setText(
                        "Exact-fit reuse highlighting appears once the service band and channel bandwidth are valid."
                    )
                else:
                    exact_fit_factors = tuple(
                        int(value) for value in partial_plan["zero_leftover_reuse_factors"]
                    )
                    if exact_fit_factors:
                        self.spectrum_zero_leftover_label.setText(
                            "Exact-fit reuse factors for the current band plan: "
                            + ", ".join(f"F{value}" for value in exact_fit_factors)
                            + "."
                        )
                    else:
                        self.spectrum_zero_leftover_label.setText(
                            "No supported reuse factor uses the full configured service band without leftover spectrum."
                        )
                self.spectrum_leakage_summary_label.setText(
                    "Set a valid service band, reuse scheme, transmitter mask, channel bandwidth, and a valid RAS receiver band on the RAS Station tab to preview leakage."
                )
            self.spectrum_mask_summary_label.setText(
                "Leakage preview becomes available once the spectrum plan validates."
            )
            self.spectrum_split_denominator_combo.setEnabled(False)
            self.preview_spectrum_plot_button.setEnabled(False)
            self._refresh_open_spectrum_editor_window(spectrum_plan=None)
            return
        try:
            plan = _normalize_spectrum_config(service_cfg, spectrum_cfg, ras_cfg)
        except Exception as exc:
            # UEMR fallback: the full normalize requires RAS receiver band,
            # which is optional for UEMR. When the system is UEMR and the
            # service band + mask preset are valid, enable the Edit Spectrum
            # button anyway so the user can still preview UEMR integration
            # into the RAS receiver band once the receiver band is set.
            try:
                _uemr_active_here = _system_is_uemr(self.current_state().active_system())
            except Exception:
                _uemr_active_here = False
            if (
                _uemr_active_here
                and spectrum_cfg.service_band_start_mhz is not None
                and spectrum_cfg.service_band_stop_mhz is not None
                and float(spectrum_cfg.service_band_stop_mhz)
                    > float(spectrum_cfg.service_band_start_mhz)
                and spectrum_cfg.unwanted_emission_mask_preset
            ):
                self.preview_spectrum_plot_button.setEnabled(True)
            self._refresh_reuse_factor_highlights(partial_plan)
            self.spectrum_summary_label.setText(
                _spectrum_summary_text(partial_plan)
                + " Define the RAS receiver band on the RAS Station tab to enable leakage preview."
                if partial_plan is not None
                else f"Spectrum plan error: {exc}"
            )
            if partial_plan is None:
                self.spectrum_zero_leftover_label.setText(
                    "Exact-fit reuse highlighting appears once the service band and channel bandwidth are valid."
                )
            else:
                exact_fit_factors = tuple(
                    int(value) for value in partial_plan["zero_leftover_reuse_factors"]
                )
                if exact_fit_factors:
                    self.spectrum_zero_leftover_label.setText(
                        "Exact-fit reuse factors for the current band plan: "
                        + ", ".join(f"F{value}" for value in exact_fit_factors)
                        + "."
                    )
                else:
                    self.spectrum_zero_leftover_label.setText(
                        "No supported reuse factor uses the full configured service band without leftover spectrum."
                    )
            self.spectrum_mask_summary_label.setText(
                "Leakage preview becomes available once the spectrum plan validates."
            )
            self.spectrum_leakage_summary_label.setText(
                "Set a valid service band, reuse scheme, transmitter mask, channel bandwidth, and a valid RAS receiver band on the RAS Station tab to preview leakage."
            )
            self.spectrum_split_denominator_combo.setEnabled(False)
            # Preserve the UEMR-enable above: only disable when UEMR is NOT
            # active with valid service band + mask.
            _uemr_can_edit = False
            try:
                _uemr_can_edit = (
                    _system_is_uemr(self.current_state().active_system())
                    and spectrum_cfg.service_band_start_mhz is not None
                    and spectrum_cfg.service_band_stop_mhz is not None
                    and float(spectrum_cfg.service_band_stop_mhz)
                        > float(spectrum_cfg.service_band_start_mhz)
                    and bool(spectrum_cfg.unwanted_emission_mask_preset)
                )
            except Exception:
                pass
            if not _uemr_can_edit:
                self.preview_spectrum_plot_button.setEnabled(False)
            self._refresh_open_spectrum_editor_window(spectrum_plan=None)
            return
        self._refresh_reuse_factor_highlights(plan)
        split_denominator_relevant = (
            int(plan["channel_groups_per_cell"]) > 1
            and str(plan["multi_group_power_policy"]) == "split_total_cell_power"
            and str(
                service_cfg.cell_activity_mode or _DEFAULT_SERVICE_CELL_ACTIVITY_MODE
            )
            == "per_channel"
        )
        self.spectrum_split_denominator_combo.setEnabled(show_expert and split_denominator_relevant)
        # Edit Spectrum requires a mask preset — otherwise the dialog has
        # no envelope to display. A missing preset is a valid "not yet
        # configured" state, not an enable-the-button state.
        self.preview_spectrum_plot_button.setEnabled(
            bool(spectrum_cfg.unwanted_emission_mask_preset)
        )
        # UEMR mode bypasses the beam/channel/reuse concepts; show a
        # UEMR-appropriate summary instead of the directive "N channels /
        # cluster=X / exact-fit reuse" line (which references beams).
        _uemr_active_summary = False
        try:
            _uemr_active_summary = _system_is_uemr(self.current_state().active_system())
        except Exception:
            pass
        if _uemr_active_summary:
            try:
                _sb_start = float(spectrum_cfg.service_band_start_mhz)
                _sb_stop = float(spectrum_cfg.service_band_stop_mhz)
                _mp = str(spectrum_cfg.unwanted_emission_mask_preset or "n/a")
                self.spectrum_summary_label.setText(
                    f"UEMR: service band {_sb_start:.3f}–{_sb_stop:.3f} MHz "
                    f"({_sb_stop - _sb_start:.3f} MHz wide) | transmit mask {_mp}."
                )
            except Exception:
                self.spectrum_summary_label.setText("UEMR spectrum inputs are ready.")
        else:
            self.spectrum_summary_label.setText(_spectrum_summary_text(plan))
        exact_fit_factors = tuple(int(value) for value in plan["zero_leftover_reuse_factors"])
        if exact_fit_factors:
            self.spectrum_zero_leftover_label.setText(
                "Exact-fit reuse factors for the current band plan: "
                + ", ".join(f"F{value}" for value in exact_fit_factors)
                + "."
            )
        else:
            self.spectrum_zero_leftover_label.setText(
                "No supported reuse factor uses the full configured service band without leftover spectrum."
            )
        mask_name = str(plan["unwanted_emission_mask_preset"])
        split_note = (
            "Split denominator active: "
            + (
                "divide across active groups."
                if str(plan["split_total_group_denominator_mode"]) == "active_groups"
                else "divide across configured groups."
            )
            if split_denominator_relevant
            else "Split denominator applies only for per-channel activity with split-total cell power and more than one group per cell."
        )
        self.spectrum_mask_summary_label.setText(
            f"Mask {mask_name} | cutoff {float(plan['spectral_integration_cutoff_mhz']):.3f} MHz | "
            f"Tx ref {str(plan['tx_reference_mode'])} | RAS ref {str(plan['ras_reference_mode'])}. "
            f"{split_note}"
        )
        zero_warning_text = _spectrum_zero_leakage_warning_text(plan)
        simulated_leakage_text = _spectrum_leakage_summary_text(
            plan,
            active_channel_indices=_occupied_channel_indices_from_plan(plan),
        )
        self.spectrum_leakage_summary_label.setText(
            simulated_leakage_text
            if zero_warning_text is None
            else f"{zero_warning_text} {simulated_leakage_text}"
        )
        self._refresh_open_spectrum_editor_window(spectrum_plan=plan)

    def _current_antennas_form_config(self) -> AntennasConfig | None:
        selected_model_raw = self.antenna_model_combo.currentData()
        selected_model = None if selected_model_raw is None else str(selected_model_raw)
        antennas = AntennasConfig(
            frequency_mhz=self._shared_frequency_value_or_none(),
            pattern_wavelength_cm=self.pattern_wavelength_spin.value_or_none(),
            derive_pattern_wavelength_from_frequency=bool(
                self.derive_pattern_wavelength_checkbox.isChecked()
            ),
            antenna_model=selected_model,
            rec12=AntennaRec12Config(
                gm_dbi=self.rec12_gm_spin.value_or_none(),
                diameter_m=self.rec12_diameter_spin.value_or_none(),
                efficiency_pct=self.rec12_efficiency_spin.value_or_none(),
                ln_db=self.rec12_ln_spin.value_or_none(),
                z=self.rec12_z_spin.value_or_none(),
            ),
            rec14=AntennaRec14Config(
                gm_dbi=self.rec14_gm_spin.value_or_none(),
                lt_m=self.rec14_lt_spin.value_or_none(),
                lr_m=self.rec14_lr_spin.value_or_none(),
                l=self.rec14_l_spin.value_or_none(),
                slr_db=self.rec14_slr_spin.value_or_none(),
                far_sidelobe_start_deg=self.rec14_far_start_spin.value_or_none(),
                far_sidelobe_level_dbi=self.rec14_far_level_spin.value_or_none(),
            ),
            m2101=AntennaM2101Config(
                g_emax_dbi=self.m2101_g_emax_spin.value_or_none(),
                a_m_db=self.m2101_a_m_spin.value_or_none(),
                sla_nu_db=self.m2101_sla_nu_spin.value_or_none(),
                phi_3db_deg=self.m2101_phi_3db_spin.value_or_none(),
                theta_3db_deg=self.m2101_theta_3db_spin.value_or_none(),
                d_h=self.m2101_d_h_spin.value_or_none(),
                d_v=self.m2101_d_v_spin.value_or_none(),
                n_h=self.m2101_n_h_spin.value_or_none(),
                n_v=self.m2101_n_v_spin.value_or_none(),
            ),
            isotropic=AntennaIsotropicConfig(
                uemr_mode=bool(self.isotropic_uemr_checkbox.isChecked()),
            ),
            ras=RasAntennaConfig(
                antenna_diameter_m=self.antenna_spin.value_or_none(),
                grx_max_dbi=self.ras_grx_max_spin.value_or_none(),
                frequency_mhz=self.ras_frequency_spin.value_or_none(),
                operational_elevation_min_deg=self.ras_oper_min_spin.value_or_none(),
                operational_elevation_max_deg=self.ras_oper_max_spin.value_or_none(),
                target_pfd_dbw_m2_mhz=None,
            ),
        )
        has_explicit_rf_or_geometry = any(
            value is not None
            for value in (
                antennas.frequency_mhz,
                antennas.pattern_wavelength_cm,
                antennas.rec12.gm_dbi,
                antennas.rec12.ln_db,
                antennas.rec12.z,
                antennas.rec14.gm_dbi,
                antennas.rec14.lt_m,
                antennas.rec14.lr_m,
                antennas.rec14.l,
                antennas.rec14.slr_db,
                antennas.rec14.far_sidelobe_start_deg,
                antennas.rec14.far_sidelobe_level_dbi,
                antennas.ras.antenna_diameter_m,
                antennas.ras.operational_elevation_min_deg,
                antennas.ras.operational_elevation_max_deg,
            )
        ) or bool(antennas.derive_pattern_wavelength_from_frequency)
        if not has_explicit_rf_or_geometry:
            antennas.antenna_model = None
        return antennas if _has_any_antenna_value(antennas) else None

