    def _current_explicit_spectrum_config(self) -> SpectrumConfig:
        reuse_factor = (
            None
            if self.spectrum_reuse_factor_combo.currentData() in {None, ""}
            else int(self.spectrum_reuse_factor_combo.currentData())
        )
        tx_reference_mode = (
            None
            if self.spectrum_tx_reference_combo.currentData() in {None, ""}
            else str(self.spectrum_tx_reference_combo.currentData())
        )
        partial_plan = _partial_spectrum_band_plan(
            self._current_service_config(),
            SpectrumConfig(
                service_band_start_mhz=self.spectrum_service_band_start_edit.value_or_none(),
                service_band_stop_mhz=self.spectrum_service_band_stop_edit.value_or_none(),
                reuse_factor=reuse_factor,
                disabled_channel_indices=self._spectrum_disabled_channel_indices,
                ras_anchor_reuse_slot=None,
                multi_group_power_policy=None,
                split_total_group_denominator_mode=None,
                unwanted_emission_mask_preset=None,
                custom_mask_points=None,
                spectral_integration_cutoff_basis=None,
                spectral_integration_cutoff_percent=None,
                tx_reference_mode=tx_reference_mode,
                tx_reference_point_count=(
                    None
                    if tx_reference_mode is None
                    else (
                        1
                        if self.spectrum_tx_reference_combo.currentData() != "n_point"
                        else int(self.spectrum_tx_reference_points_spin.value())
                    )
                ),
            ),
        )
        return SpectrumConfig(
            service_band_start_mhz=self.spectrum_service_band_start_edit.value_or_none(),
            service_band_stop_mhz=self.spectrum_service_band_stop_edit.value_or_none(),
            reuse_factor=reuse_factor,
            disabled_channel_indices=_sanitize_disabled_channel_indices(
                self._spectrum_disabled_channel_indices,
                full_channel_count=(
                    None
                    if partial_plan is None
                    else int(partial_plan.get("full_channel_count", 0))
                ),
            ),
            ras_anchor_reuse_slot=(
                None
                if reuse_factor is None
                else int(self.spectrum_anchor_slot_spin.currentData() or 0)
            ),
            multi_group_power_policy=(
                None
                if self.spectrum_power_policy_combo.currentData() in {None, ""}
                else str(self.spectrum_power_policy_combo.currentData())
            ),
            split_total_group_denominator_mode=(
                None
                if self.spectrum_split_denominator_combo.currentData() in {None, ""}
                else str(self.spectrum_split_denominator_combo.currentData())
            ),
            unwanted_emission_mask_preset=(
                None
                if self.spectrum_mask_preset_combo.currentData() in {None, ""}
                else str(self.spectrum_mask_preset_combo.currentData())
            ),
            custom_mask_points=getattr(self, "_spectrum_custom_mask_points", None),
            spectral_integration_cutoff_basis=(
                None
                if self.spectrum_cutoff_basis_combo.currentData() in {None, ""}
                else str(self.spectrum_cutoff_basis_combo.currentData())
            ),
            spectral_integration_cutoff_percent=self.spectrum_cutoff_percent_edit.value_or_none(),
            tx_reference_mode=tx_reference_mode,
            tx_reference_point_count=(
                None
                if tx_reference_mode is None
                else (
                    1
                    if self.spectrum_tx_reference_combo.currentData() != "n_point"
                    else int(self.spectrum_tx_reference_points_spin.value())
                )
            ),
        )

    def _current_spectrum_config(self) -> SpectrumConfig:
        spectrum = self._current_explicit_spectrum_config()
        service_cfg = self._current_service_config()
        antennas_cfg = self._current_antennas_form_config()
        if (
            not _has_any_spectrum_value(spectrum)
            and service_cfg.bandwidth_mhz is not None
        ):
            return _legacy_overlap_spectrum_config(service_cfg, antennas_cfg)
        return spectrum

    def _current_explicit_spectrum_plan(self) -> dict[str, Any]:
        spectrum_cfg = self._current_explicit_spectrum_config()
        if not self._workflow_has_explicit_spectrum_inputs():
            raise ValueError("Enter Spectrum & Reuse settings first.")
        return _normalize_spectrum_config(
            self._current_service_config(),
            spectrum_cfg,
            self._current_ras_station_config(),
        )

    def _workflow_has_explicit_spectrum_inputs(self) -> bool:
        return _has_any_spectrum_value(self._current_explicit_spectrum_config())

