        self.pattern_wavelength_spin.set_value(pattern_value)
        combo_index = self.antenna_model_combo.findData(config.antenna_model)
        self.antenna_model_combo.setCurrentIndex(combo_index if combo_index >= 0 else 0)
        self.rec12_gm_spin.set_value(config.rec12.gm_dbi)
        self.rec12_diameter_spin.set_value(config.rec12.diameter_m)
        self.rec12_efficiency_spin.set_value(config.rec12.efficiency_pct)
        if config.rec12.diameter_m is None and config.rec12.gm_dbi is not None:
            self._update_rec12_diameter_from_gm()
