        self.rec12_z_spin.set_value(config.rec12.z)
        self.rec14_gm_spin.set_value(config.rec14.gm_dbi)
        self.rec14_lt_spin.set_value(config.rec14.lt_m)
        self.rec14_lr_spin.set_value(config.rec14.lr_m)
        self.rec14_l_spin.set_value(config.rec14.l)
        self.rec14_slr_spin.set_value(config.rec14.slr_db)
        self.rec14_far_start_spin.set_value(config.rec14.far_sidelobe_start_deg)
        self.rec14_far_level_spin.set_value(config.rec14.far_sidelobe_level_dbi)
        self.m2101_g_emax_spin.set_value(config.m2101.g_emax_dbi)
        self.m2101_a_m_spin.set_value(config.m2101.a_m_db)
        self.m2101_sla_nu_spin.set_value(config.m2101.sla_nu_db)
        self.m2101_phi_3db_spin.set_value(config.m2101.phi_3db_deg)
        self.m2101_theta_3db_spin.set_value(config.m2101.theta_3db_deg)
        self.m2101_d_h_spin.set_value(config.m2101.d_h)
        self.m2101_d_v_spin.set_value(config.m2101.d_v)
        self.m2101_n_h_spin.set_value(config.m2101.n_h)
        self.m2101_n_v_spin.set_value(config.m2101.n_v)
        self.isotropic_uemr_checkbox.setChecked(bool(config.isotropic.uemr_mode))
        self.antenna_spin.set_value(config.ras.antenna_diameter_m)
        if config.ras.grx_max_dbi is not None:
            self.ras_grx_max_spin.set_value(config.ras.grx_max_dbi)
        else:
            self._update_ras_grx_from_diameter()
        self.ras_frequency_spin.set_value(config.ras.frequency_mhz)
        self.ras_oper_min_spin.set_value(config.ras.operational_elevation_min_deg)
        self.ras_oper_max_spin.set_value(config.ras.operational_elevation_max_deg)
        self._sync_rf_panel()

