            QtCore.QSignalBlocker(self.rec14_lr_spin),
            QtCore.QSignalBlocker(self.rec14_l_spin),
            QtCore.QSignalBlocker(self.rec14_slr_spin),
            QtCore.QSignalBlocker(self.rec14_far_start_spin),
