    def _load_service_widgets(self, service: ServiceConfig) -> None:
        self.service_nco_edit.set_value(service.nco)
        self.service_nbeam_edit.set_value(service.nbeam)
        service_strategy_idx = self.service_selection_combo.findData(service.selection_strategy)
        if service_strategy_idx >= 0:
            self.service_selection_combo.setCurrentIndex(service_strategy_idx)
        else:
            self._set_combo_to_data(self.service_selection_combo, None)
        self.service_cell_activity_edit.set_value(
            None if service.cell_activity_factor is None else float(service.cell_activity_factor) * 100.0
        )
        self._set_combo_to_data(
            self.service_cell_activity_mode_combo,
            service.cell_activity_mode or _DEFAULT_SERVICE_CELL_ACTIVITY_MODE,
        )
        self.service_cell_seed_edit.set_value(service.cell_activity_seed_base)
        self.service_bandwidth_edit.set_value(service.bandwidth_mhz)
        self._set_combo_to_data(
            self.service_power_quantity_combo,
            service.power_input_quantity or _DEFAULT_SERVICE_POWER_INPUT_QUANTITY,
        )
        self._set_combo_to_data(
            self.service_power_basis_combo,
            service.power_input_basis or _DEFAULT_SERVICE_POWER_INPUT_BASIS,
        )
        self.target_pfd_edit.set_value(service.target_pfd_dbw_m2_mhz)
        self.target_pfd_channel_edit.set_value(service.target_pfd_dbw_m2_channel)
        self.satellite_ptx_mhz_edit.set_value(service.satellite_ptx_dbw_mhz)
        self.satellite_ptx_channel_edit.set_value(service.satellite_ptx_dbw_channel)
        self.satellite_eirp_mhz_edit.set_value(service.satellite_eirp_dbw_mhz)
        self.satellite_eirp_channel_edit.set_value(service.satellite_eirp_dbw_channel)
        var_idx = self.service_power_variation_combo.findData(str(service.power_variation_mode or "fixed"))
        if var_idx >= 0:
            self.service_power_variation_combo.setCurrentIndex(var_idx)
        self.service_power_range_min_edit.set_value(service.power_range_min_db)
        self.service_power_range_max_edit.set_value(service.power_range_max_db)
        # Surface-PFD cap
        self.max_surface_pfd_enable_check.setChecked(bool(service.max_surface_pfd_enabled))
        self.max_surface_pfd_mhz_edit.set_value(service.max_surface_pfd_dbw_m2_mhz)
        self.max_surface_pfd_channel_edit.set_value(service.max_surface_pfd_dbw_m2_channel)
        cap_mode_idx = self.surface_pfd_cap_mode_combo.findData(
            str(service.surface_pfd_cap_mode or "per_beam")
        )
        if cap_mode_idx >= 0:
            self.surface_pfd_cap_mode_combo.setCurrentIndex(cap_mode_idx)
        self._sync_service_power_controls()
        self._sync_surface_pfd_cap_controls()

    def _load_spectrum_widgets(self, spectrum: SpectrumConfig) -> None:
        self._spectrum_disabled_channel_indices = (
            None
            if spectrum.disabled_channel_indices is None or spectrum.disabled_channel_indices == []
            else [int(value) for value in spectrum.disabled_channel_indices]
        )
        self.spectrum_service_band_start_edit.set_value(spectrum.service_band_start_mhz)
        self.spectrum_service_band_stop_edit.set_value(spectrum.service_band_stop_mhz)
        self._set_combo_to_data(self.spectrum_reuse_factor_combo, spectrum.reuse_factor)
        reuse_factor = 1 if spectrum.reuse_factor is None else int(spectrum.reuse_factor)
        self._rebuild_anchor_slot_items(reuse_factor=max(1, reuse_factor))
        anchor_idx = self.spectrum_anchor_slot_spin.findData(
            0 if spectrum.ras_anchor_reuse_slot is None else int(spectrum.ras_anchor_reuse_slot)
        )
        if anchor_idx >= 0:
            self.spectrum_anchor_slot_spin.setCurrentIndex(anchor_idx)
        self._set_combo_to_data(
            self.spectrum_power_policy_combo,
            spectrum.multi_group_power_policy,
        )
        self._set_combo_to_data(
            self.spectrum_split_denominator_combo,
            spectrum.split_total_group_denominator_mode,
        )
        self._set_combo_to_data(
            self.spectrum_mask_preset_combo,
            spectrum.unwanted_emission_mask_preset,
        )
        self._set_combo_to_data(
            self.spectrum_cutoff_basis_combo,
            spectrum.spectral_integration_cutoff_basis,
        )
        self.spectrum_cutoff_percent_edit.set_value(
            spectrum.spectral_integration_cutoff_percent
        )
        self._set_combo_to_data(
            self.spectrum_tx_reference_combo,
            spectrum.tx_reference_mode,
        )
        self.spectrum_tx_reference_points_spin.setValue(
            int(spectrum.tx_reference_point_count or 1)
        )
        self._spectrum_custom_mask_points = (
            None
            if spectrum.custom_mask_points is None
            else [
                [float(point[0]), float(point[1])]
                for point in spectrum.custom_mask_points
            ]
        )
        self._sync_spectrum_controls()

    def _load_runtime_output_family_widgets(
        self,
        output_families: Mapping[str, Mapping[str, Any]],
    ) -> None:
        runtime_output_families = _normalize_output_families_config(output_families)
        for family_name, widgets in self.runtime_output_family_widgets.items():
            family_config = runtime_output_families.get(family_name, {})
            mode_widget = widgets.get("mode")
            if isinstance(mode_widget, QtWidgets.QComboBox):
                idx = mode_widget.findData(family_config.get("mode"))
                if idx >= 0:
                    mode_widget.setCurrentIndex(idx)
            range_widget = widgets.get("range_mode")
            if isinstance(range_widget, QtWidgets.QComboBox):
                idx = range_widget.findData(family_config.get("range_mode"))
                if idx >= 0:
                    range_widget.setCurrentIndex(idx)
            for field_name, widget in widgets.items():
                if field_name in {"mode", "range_mode"}:
                    continue
                if isinstance(widget, OptionalNumericEdit):
                    widget.set_value(family_config.get(field_name))

    def _load_runtime_widgets(self, runtime: RuntimeConfig) -> None:
        self.runtime_storage_edit.setText(runtime.storage_filename)
        self.runtime_start_edit.setDateTime(_utc_iso_text_to_qdatetime(runtime.base_start_utc_iso))
        self.runtime_end_edit.setDateTime(_utc_iso_text_to_qdatetime(runtime.base_end_utc_iso))
