    def _reset_loaded_derived_state(self) -> None:
        """Clear derived preview/analyser state after loading a new project state."""
        self._last_analyser_selected_cell_km = None
        self._last_analyser_signature = None
        self.grid_recommended_label.setText("Recommended cell spacing: --")
        self.grid_effective_label.setText("Effective cell spacing: --")
        self.grid_actual_label.setText("Actual achieved spacing: --")
        self.grid_summary_text.clear()
        self._hexgrid_request_signatures.clear()
        self._hexgrid_applied_signature = None
        self._hexgrid_completed_signature = None
        self._hexgrid_completed_commit_signature = None
        self._hexgrid_completed_overlay_signature = None
        self._hexgrid_preview_cached_result = None
        self._hexgrid_outdated = True
        self._clear_hexgrid_preview_canvas()
        self._clear_antenna_pattern_canvas()

    def _load_state_into_widgets(self, state: ScepterProjectState) -> None:
        """Load a project state into the form widgets without emitting change storms."""
        self._state_load_in_progress = True
        try:
            blockers = self._state_widget_signal_blockers()
            # Populate multi-system cache from state
            if state.systems:
                self._system_configs_cache = [
                    SatelliteSystemConfig.from_json_dict(s.to_json_dict())
                    for s in state.systems
                ]
            else:
                self._system_configs_cache = [SatelliteSystemConfig()]
            self._active_system_index = 0
            self._per_system_derived.clear()
            self._sync_system_tab_bar()
            self._update_per_system_labels()
            # Load shared fields
            self._set_ras_station_widgets(_with_loaded_ras_receiver_defaults(state.ras_station))
            self._load_runtime_widgets(state.runtime)
            # Load per-system fields from active system
            s0_load = state.active_system()
            self._belt_model.replace_belts(s0_load.belts)
            self._set_antennas_widgets(
                s0_load.satellite_antennas.to_antennas_config(ras=state.ras_antenna)
            )
            self._load_service_widgets(s0_load.service)
            self._load_spectrum_widgets(s0_load.spectrum)
            self._load_hexgrid_widgets(s0_load.hexgrid)
            self._load_grid_analysis_widgets(s0_load.grid_analysis)
            self._reset_loaded_derived_state()
            # Restore per-system derived state AFTER reset (so reset doesn't clear it)
            for _ds_idx, _ds_sys in enumerate(self._system_configs_cache):
                if _ds_sys.derived_state:
                    self._per_system_derived[_ds_idx] = dict(_ds_sys.derived_state)
            if 0 in self._per_system_derived:
                for _dk in self._PER_SYSTEM_DERIVED_KEYS:
                    _dv = self._per_system_derived[0].get(_dk)
                    if _dv is not None:
                        setattr(self, _dk, _dv)
                # Also restore the grid actual label text
                _galt = self._per_system_derived[0].get("_grid_actual_label_text")
                if _galt:
                    self.grid_actual_label.setText(str(_galt))
            # Restore output system groups from state, or generate defaults
            if state.output_system_groups:
                self._output_system_groups_cache = [
                    SystemOutputGroup.from_json_dict(g.to_json_dict())
                    for g in state.output_system_groups
                ]
            else:
                n = len(self._system_configs_cache)
                names = [s.system_name for s in self._system_configs_cache]
                self._output_system_groups_cache = _default_output_system_groups(n, names)
            self._sync_sog_widget()
            self._summary_refresh_timer.stop()
            del blockers
        finally:
            self._state_load_in_progress = False

        self._sync_runtime_controls()
        self._refresh_summary()
        self._select_simulation_page(self.ras_tab)

    def _refresh_summary(self) -> None:
        state = self.current_state()
        self._refresh_summary_lightweight(state)
        self._apply_workflow_status_payloads(
            state,
            self._simulation_page_status_payloads(state),
        )

    def _refresh_summary_lightweight(
        self,
        state: ScepterProjectState | None = None,
    ) -> None:
        state = self.current_state() if state is None else state
        self.open_viewer_button.setEnabled(self._viewer_can_launch(state))
        self.home_open_viewer_button.setEnabled(self._viewer_can_launch(state))
        has_belts = self._belt_model.rowCount() > 0
        self.duplicate_belt_button.setEnabled(has_belts)
        self.remove_belt_button.setEnabled(has_belts)
        self.remove_ras_button.setEnabled(_has_any_ras_station_value(state.ras_station))
        ras_cfg = state.ras_antenna
        self.remove_ras_antenna_button.setEnabled(
            ras_cfg is not None
            and any(
                value is not None
                for value in (
                    ras_cfg.antenna_diameter_m,
                    ras_cfg.operational_elevation_min_deg,
                    ras_cfg.operational_elevation_max_deg,
                )
            )
        )
        self._sync_runtime_controls()
        self._sync_rf_panel()
        self._sync_spectrum_controls()
        self._update_side_pane_policy()
        self._refresh_analyzer_controls()
        self._update_run_controls(state)
        self._update_antenna_plot_controls()
        self._update_grid_complexity_sections(state=state)
        self._update_spectrum_complexity_sections(state=state)
        self._update_hexgrid_complexity_sections(state=state)
        # Complexity updates above toggle visibility of Advanced/Expert
        # widgets. If UEMR is active they must stay hidden afterwards —
        # re-apply the UEMR gating to enforce that.
        if hasattr(self, "isotropic_uemr_checkbox"):
            try:
                active_cfg = state.active_system().satellite_antennas
                uemr_active = (
                    str(getattr(active_cfg, "antenna_model", "") or "") == _ANTENNA_MODEL_ISOTROPIC
                    and bool(
                        getattr(active_cfg, "isotropic", None)
                        and active_cfg.isotropic.uemr_mode
                    )
                )
            except Exception:
                uemr_active = False
            if uemr_active:
                self._apply_uemr_mode_gating(uemr_active=True)

    @QtCore.Slot()
    def _on_runtime_controls_changed(self, *_args: object) -> None:
        self._sync_service_power_controls()
        self._sync_runtime_controls()
        self._sync_spectrum_controls()
        self._on_state_changed()

    @QtCore.Slot()
    def _on_service_power_mode_changed(self, *_args: object) -> None:
        self._sync_service_power_controls()
        self._on_runtime_controls_changed()

    @QtCore.Slot()
    def _on_spectrum_controls_changed(self, *_args: object) -> None:
        if self._state_load_in_progress:
            return
        # If UEMR is active, re-apply the forced defaults so that a
        # newly-entered service band immediately updates the hidden
        # channel-bandwidth field (which the kernel still reads as the
        # active spectral slab width).
        try:
            if (
                hasattr(self, "isotropic_uemr_checkbox")
                and self.isotropic_uemr_checkbox.isChecked()
            ):
                self._apply_uemr_forced_defaults()
        except Exception:
            pass
        self._sync_spectrum_controls()
        self._on_state_changed()

    def _on_reuse_factor_changed(self, *_args: object) -> None:
        """Rebuild the RAS anchor slot dropdown when reuse factor changes.

        The rebuild + selection-restore logic lives in
        ``_rebuild_anchor_slot_items`` so this handler just triggers
        the standard spectrum-controls sync path.
        """
        # _sync_spectrum_controls (called by _on_spectrum_controls_changed)
        # already rebuilds the anchor slots — nothing extra needed here.

    def _rebuild_anchor_slot_items(self, *, reuse_factor: int) -> None:
        """Populate the RAS anchor slot combo with colour-coded slot entries.

        Preserves the current selection when possible so that switching
        reuse factors or syncing controls does not silently reset the
        user's choice.
        """
        combo = self.spectrum_anchor_slot_spin
        old_data = combo.currentData()
        blocker = QtCore.QSignalBlocker(combo)
        combo.clear()
        rf = max(1, int(reuse_factor))
        try:
            from scepter import visualise
            colors = visualise._frequency_reuse_slot_colors(rf)
        except Exception:
            colors = [None] * rf
        for slot_id in range(rf):
            # Display 1-based labels for the user
            label = f"Slot {slot_id + 1}" if rf > 1 else "Slot 1 (F1)"
            combo.addItem(label, userData=int(slot_id))
            if colors[slot_id] is not None:
                try:
                    r, g, b = colors[slot_id][:3]
                    combo.setItemData(
                        slot_id,
                        QtGui.QColor(int(r * 255), int(g * 255), int(b * 255)),
                        QtCore.Qt.DecorationRole,
                    )
                except Exception:
                    pass
        # Restore previous selection if it still exists in the new set
        if old_data is not None:
            restore_idx = combo.findData(int(old_data))
            if restore_idx >= 0:
                combo.setCurrentIndex(restore_idx)
        del blocker

    @QtCore.Slot()
    def _on_appearance_mode_changed(self, *_args: object) -> None:
        self._apply_visual_style()
        self._repolish_shell_theme_surfaces()
        self._persist_session_state()
        self._restyle_detached_preview_windows()
        self._schedule_responsive_layout_refresh()
        QtCore.QTimer.singleShot(0, self._stabilize_visible_geometry)

    def _restyle_detached_preview_windows(self) -> None:
        # Re-render the hexgrid preview from cache so map-specific colours
        # (land, ocean, coastline, cell fills) match the new theme.
        hexgrid_window = getattr(self, "_hexgrid_preview_window", None)
        if isinstance(hexgrid_window, FigureWindow) and self._hexgrid_preview_cached_result is not None:
            try:
                self._render_hexgrid_preview_result(
                    self._hexgrid_preview_cached_result,
                    cached_render=True,
                )
            except Exception:
                hexgrid_window.restyle_figure()
        elif isinstance(hexgrid_window, FigureWindow):
            hexgrid_window.restyle_figure()
        figure_windows = [
            getattr(self, "_reuse_scheme_window", None),
            getattr(self, "_ras_receiver_preview_window", None),
        ]
        for window in figure_windows:
            if isinstance(window, FigureWindow):
                window.restyle_figure()
        spectrum_window = getattr(self, "_spectrum_preview_window", None)
        if isinstance(spectrum_window, SpectrumPreviewDialog):
            spectrum_window.restyle_dialog()
        if hasattr(self, "postprocess_widget") and isinstance(self.postprocess_widget, PostprocessStudioWidget):
            self.postprocess_widget.restyle_open_figures()
        for window in list(getattr(self, "_antenna_pattern_windows", ())):
            if isinstance(window, FigureWindow):
                window.restyle_figure()

    def _repolish_shell_theme_surfaces(self) -> None:
        roots = [
            getattr(self, "workspace_nav", None),
            getattr(self, "_right_container", None),
            getattr(self, "_assistant_scroll_content", None),
            getattr(self, "postprocess_widget", None),
        ]
        assistant_scroll = getattr(self, "_assistant_scroll", None)
        if isinstance(assistant_scroll, QtWidgets.QAbstractScrollArea):
            roots.append(assistant_scroll.viewport())
        postprocess_widget = getattr(self, "postprocess_widget", None)
        if isinstance(postprocess_widget, PostprocessStudioWidget):
            roots.extend(
                [
                    getattr(postprocess_widget, "result_summary_scroll", None),
                    getattr(postprocess_widget, "recipe_controls_scroll", None),
                ]
            )
            for area in (
                getattr(postprocess_widget, "result_summary_scroll", None),
                getattr(postprocess_widget, "recipe_controls_scroll", None),
            ):
                if isinstance(area, QtWidgets.QAbstractScrollArea):
                    roots.append(area.viewport())
        seen: set[int] = set()
        for root in roots:
            if not isinstance(root, QtWidgets.QWidget):
                continue
            widgets = [root, *root.findChildren(QtWidgets.QWidget)]
            for widget in widgets:
                key = id(widget)
                if key in seen:
                    continue
                seen.add(key)
                widget.style().unpolish(widget)
                widget.style().polish(widget)
                # Force the QWidget overload; item views like QListView expose a
                # model-index update() in PySide and can reject a no-arg call.
                QtWidgets.QWidget.update(widget)
                if isinstance(widget, QtWidgets.QAbstractScrollArea):
                    viewport = widget.viewport()
                    if isinstance(viewport, QtWidgets.QWidget):
                        QtWidgets.QWidget.update(viewport)

    def _update_runtime_section_summaries(self) -> None:
        state = self.current_state()
        runtime = state.runtime
        try:
            power_input_text = _service_power_input_summary(_require_service_power_input(state))
        except ValueError:
            power_input_text = "not set"
        start_text = self.runtime_start_edit.dateTime().toString("yyyy-MM-dd HH:mm")
        end_text = self.runtime_end_edit.dateTime().toString("yyyy-MM-dd HH:mm")
        self.runtime_simulation_summary_label.setText(
            f"{start_text} to {end_text}, timestep {float(runtime.timestep_s):g} s, "
            f"{int(runtime.iteration_count)} iteration(s)."
        )
        if bool(runtime.include_atmosphere):
            self.runtime_context_summary_label.setText(
                "Atmosphere enabled with configured elevation/path bounds. "
                f"Target altitude {float(runtime.target_alt_km):g} km. "
                f"Service power input {power_input_text}."
            )
        else:
            self.runtime_context_summary_label.setText(
                "Atmosphere disabled for a faster baseline run. "
                f"Target altitude {float(runtime.target_alt_km):g} km, "
                f"service power input {power_input_text}."
            )
        self.runtime_memory_summary_label.setText(
            f"{float(runtime.host_memory_budget_gb):g} GB host, {float(runtime.gpu_memory_budget_gb):g} GB GPU, "
            f"mode={runtime.memory_budget_mode}, headroom={runtime.memory_headroom_profile}, "
            f"target={runtime.scheduler_target_profile}."
        )
        pattern_mode = str(getattr(runtime, "gpu_pattern_eval_mode", "lut"))
        precision_prof = str(getattr(runtime, "gpu_precision_profile", "float32"))
        self.runtime_gpu_summary_label.setText(
            f"method={runtime.gpu_method}, precision={precision_prof}, "
            f"output={runtime.gpu_output_dtype}, pattern={pattern_mode}, "
            f"on_error={runtime.gpu_on_error}."
        )
        checkpoint_text = (
            "off"
            if runtime.writer_checkpoint_interval_s is None
            else f"{float(runtime.writer_checkpoint_interval_s):g} s"
        )
        self.runtime_writer_summary_label.setText(
            f"progress={runtime.progress_desc_mode}, checkpoint={checkpoint_text}, "
            f"compression={runtime.hdf5_compression or 'off'}."
        )
        family_modes = _normalize_output_families_config(runtime.output_families)
        counts = {mode: 0 for mode in _OUTPUT_FAMILY_MODE_OPTIONS}
        for config in family_modes.values():
            counts[str(config.get('mode', 'none'))] = counts.get(str(config.get('mode', 'none')), 0) + 1
        summary_bits = [f"{mode}={counts.get(mode, 0)}" for mode in _OUTPUT_FAMILY_MODE_OPTIONS if counts.get(mode, 0)]
        self.outputs_summary_label.setText(
            "Family modes: " + (", ".join(summary_bits) if summary_bits else "none configured")
        )
        self.runtime_run_summary_label.setText(
            "Use the structured monitor below for run phases, chunk flow, checkpoints, writer timing, and the direct handoff into postprocess."
        )

    def _hexgrid_commit_signature(
        self,
        state: ScepterProjectState,
    ) -> tuple[Any, ...] | None:
        s0 = state.active_system()
        hx = s0.hexgrid
        effective_cell_km = self._effective_hexgrid_cell_size_km(state)
        if len(s0.belts) < 1 or not _has_complete_ras_station_config(state.ras_station):
            return None
        if effective_cell_km is None:
            return None
        return (
            tuple(json.dumps(belt.to_json_dict(), sort_keys=True) for belt in s0.belts),
            round(float(state.ras_station.longitude_deg), 6),
            round(float(state.ras_station.latitude_deg), 6),
            round(float(state.ras_station.elevation_m), 3),
            round(float(effective_cell_km), 6),
            str(hx.geography_mask_mode),
            None
            if hx.shoreline_buffer_km is None
            else round(float(hx.shoreline_buffer_km), 6),
            str(hx.coastline_backend),
            str(hx.ras_pointing_mode),
            str(hx.ras_exclusion_mode),
            int(hx.ras_exclusion_layers),
            None
            if hx.ras_exclusion_radius_km is None
            else round(float(hx.ras_exclusion_radius_km), 6),
            bool(hx.boresight_avoidance_enabled),
            None
            if hx.boresight_theta1_deg is None
            else round(float(hx.boresight_theta1_deg), 6),
            None
            if hx.boresight_theta2_deg is None
            else round(float(hx.boresight_theta2_deg), 6),
            str(hx.boresight_theta2_scope_mode),
            str(hx.boresight_theta2_cell_ids or "").strip(),
            int(hx.boresight_theta2_layers),
            None
            if hx.boresight_theta2_radius_km is None
            else round(float(hx.boresight_theta2_radius_km), 6),
        )

    def _hexgrid_preview_signature(
        self,
        state: ScepterProjectState,
    ) -> tuple[Any, ...] | None:
        commit_signature = self._hexgrid_commit_signature(state)
        if commit_signature is None:
            return None
        s0 = state.active_system()
        return commit_signature + (
            str(self.hexgrid_map_style_combo.currentData() or "clean"),
            str(self._selected_appearance_mode()),
            float(
                _DEFAULT_SERVICE_BANDWIDTH_MHZ
                if s0.service.bandwidth_mhz is None
                else s0.service.bandwidth_mhz
            ),
            json.dumps(s0.spectrum.to_json_dict(), sort_keys=True),
        )

    def _hexgrid_overlay_signature(
        self,
        state: ScepterProjectState,
    ) -> tuple[Any, ...] | None:
        commit_signature = self._hexgrid_commit_signature(state)
        if commit_signature is None:
            return None
        s0 = state.active_system()
        return commit_signature + (
            float(
                _DEFAULT_SERVICE_BANDWIDTH_MHZ
                if s0.service.bandwidth_mhz is None
                else s0.service.bandwidth_mhz
            ),
            json.dumps(s0.spectrum.to_json_dict(), sort_keys=True),
        )

    def _hexgrid_is_current(self, state: ScepterProjectState) -> bool:
        if not self._contour_is_current(state):
            return False
        signature = self._hexgrid_commit_signature(state)
        if signature is None:
            return False
        return signature in {
            self._hexgrid_applied_signature,
            self._hexgrid_completed_commit_signature,
        }

    def _hexgrid_visual_is_current(self, state: ScepterProjectState) -> bool:
        if not self._hexgrid_is_current(state):
            return False
        overlay_signature = self._hexgrid_overlay_signature(state)
        if overlay_signature is None:
            return False
        if self._hexgrid_completed_overlay_signature is None:
            return True
        return overlay_signature == self._hexgrid_completed_overlay_signature

    def _sync_runtime_controls(self) -> None:
        include_atmosphere = bool(self.runtime_include_atmosphere_checkbox.isChecked())
        for widget in (
            self.runtime_atm_bin_edit,
            self.runtime_atm_min_edit,
            self.runtime_atm_max_edit,
            self.runtime_atm_path_edit,
        ):
            widget.setEnabled(include_atmosphere)
            if not include_atmosphere:
                widget.setToolTip("Enabled when 'Include atmosphere' is turned on.")
            elif widget in self._help_registry:
                widget.setToolTip(self._help_registry[widget].summary)
        compression_value = self.runtime_hdf5_compression_combo.currentData()
        self.runtime_hdf5_compression_opts_spin.setEnabled(compression_value == "gzip")
        if compression_value != "gzip":
            self.runtime_hdf5_compression_opts_spin.setToolTip(
                "Compression options are only used when HDF5 compression is set to gzip."
            )
        else:
            self.runtime_hdf5_compression_opts_spin.setToolTip(
                self._help_registry.get(
                    self.runtime_hdf5_compression_opts_spin,
                    ControlHelpDefinition("", "Gzip compression level used when HDF5 compression is set to gzip."),
                ).summary
            )
        self.runtime_sat_frame_combo.setToolTip(
            "The current public workflow supports only xyz, so SAT frame remains fixed."
        )
        if hasattr(self, "runtime_expert_notice") and hasattr(self, "runtime_advanced_group"):
            expert_visible = bool(self.runtime_advanced_group.isVisible())
            self.runtime_expert_notice.setVisible(not expert_visible)
        if hasattr(self, "runtime_simulation_summary_label"):
            self._update_runtime_section_summaries()

    def _hexgrid_status_message(self, state: ScepterProjectState) -> str:
        effective_cell_km = self._effective_hexgrid_cell_size_km(state)
        if len(state.active_system().belts) < 1:
            return "Hexgrid settings require at least one valid belt."
        if not _has_complete_ras_station_config(state.ras_station):
            return "Hexgrid settings require a fully configured RAS station."
        if not self._contour_is_current(state):
            if effective_cell_km is not None:
                return (
                    f"Contour spacing is stale at {float(effective_cell_km):g} km. "
                    "Rerun the analyser or enable a valid override before applying or previewing the hexgrid."
                )
            return "Run the analyser first or enable a valid override before applying or previewing the hexgrid."
        if effective_cell_km is None:
            return "Run the analyser first or enable a cell-size override before applying or previewing the hexgrid."
        commit_signature = self._hexgrid_commit_signature(state)
        preview_signature = self._hexgrid_preview_signature(state)
        overlay_signature = self._hexgrid_overlay_signature(state)
        if commit_signature is not None and commit_signature == self._hexgrid_completed_commit_signature:
            if (
                overlay_signature is not None
                and overlay_signature != self._hexgrid_completed_overlay_signature
            ):
                return (
                    "Hexgrid geometry is current, but the reuse/spectrum overlay is stale. "
                    "Open / Refresh Preview to update the visual check."
                )
            if preview_signature is not None and preview_signature == self._hexgrid_completed_signature:
                return "Hexgrid preview is current for the active geography and boresight controls."
            return "Hexgrid settings are applied and ready. Open / Refresh Preview only if you want a visual check."
        if commit_signature is not None and commit_signature == self._hexgrid_applied_signature:
            if (
                overlay_signature is not None
                and overlay_signature != self._hexgrid_completed_overlay_signature
            ):
                return (
                    "Hexgrid geometry is applied, but the reuse/spectrum overlay is stale. "
                    "Open / Refresh Preview to refresh the visual check."
                )
            return "Hexgrid settings are applied and ready. Open / Refresh Preview only if you want a visual check."
        return "Hexgrid settings are out of date. Click Apply Hexgrid Settings or Open / Refresh Preview."

    def _mark_hexgrid_preview_stale(
        self,
        state: ScepterProjectState | None = None,
        *,
        clear_canvas: bool = True,
    ) -> None:
        state_use = self.current_state() if state is None else state
        self._hexgrid_outdated = not self._hexgrid_visual_is_current(state_use)
        if clear_canvas and self._current_path is None:
            # Keep detached preview windows alive during normal editing.
            # They remain visually useful even when outdated.
            pass
        if hasattr(self, "hexgrid_preview_status_label"):
            self.hexgrid_preview_status_label.setText(self._hexgrid_status_message(state_use))
        kind, message = self._hexgrid_notice_payload(state_use)
        self.hexgrid_notice_banner.show_message(message, kind=kind)

    def _all_systems_coverage_ready(self, state: ScepterProjectState) -> tuple[bool, str]:
        """Check contour/hexgrid readiness for every system.

        For the system whose derived state is currently loaded into the
        window variables (identified by ``state._active_index``), the live
        window state is used.  For all other systems, the per-system
        derived-state cache is consulted.
        """
        all_systems = state.systems or [state.active_system()]
        # The "live" system is the one whose derived state is currently
        # in the window variables — may differ from state._active_index
        # when _build_multi_system_run_request swaps derived state.
        live_idx = state._active_index
        for sys_idx, sys_cfg in enumerate(all_systems):
            label = sys_cfg.system_name or f"System {sys_idx + 1}"
            # UEMR systems bypass the beam library entirely — they have no
            # finite beamwidth, so contour analysis is not applicable and
            # hexgrid / boresight are not used. Skip both checks.
            if _system_is_uemr(sys_cfg):
                continue
            if sys_idx == live_idx:
                # This system's derived state is in the window variables
                contour_current = self._contour_is_current(state)
                commit_sig = self._hexgrid_commit_signature(state)
                is_current = self._hexgrid_is_current(state)
            else:
                # Peek into the cached derived state
                cached = self._per_system_derived.get(sys_idx, {})
                contour_current = bool(
                    cached.get("_last_analyser_selected_cell_km") is not None
                    and cached.get("_last_analyser_signature") is not None
                )
                ga = sys_cfg.grid_analysis
                if ga.cell_size_override_enabled and ga.cell_size_override_km is not None:
                    contour_current = True
                # Hexgrid is current if either applied or completed signature exists
                applied_sig = cached.get("_hexgrid_applied_signature")
                completed_sig = cached.get("_hexgrid_completed_commit_signature")
                commit_sig = applied_sig or completed_sig
                is_current = commit_sig is not None
            if not contour_current:
                return False, f"{label}: coverage contour analysis not done."
            if commit_sig is None or not is_current:
                return False, f"{label}: hexgrid settings not applied."
        return True, ""

    def _run_readiness_payload(self, state: ScepterProjectState) -> tuple[bool, str]:
        # --- Check ALL systems for per-system readiness ---
        all_systems = state.systems or [state.active_system()]
        for sys_idx, sys_cfg in enumerate(all_systems):
            label = sys_cfg.system_name or f"System {sys_idx + 1}"
            if len(sys_cfg.belts) < 1:
                return False, f"{label}: no belts defined."
            if not _has_valid_satellite_antenna_config(sys_cfg.satellite_antennas):
                return False, f"{label}: satellite antenna incomplete."
            if not _has_valid_service_config(sys_cfg.service, uemr_mode=_system_is_uemr(sys_cfg)):
                return False, f"{label}: service & demand incomplete."
            # UEMR systems skip the cell/reuse spectrum normalisation
            # entirely — they need only a valid service band + mask preset.
            # The full normalize call requires RAS receiver band fields
            # which are optional for UEMR (the UEMR bypass path doesn't
            # compute receiver-band overlap integrals the same way).
            if _system_is_uemr(sys_cfg):
                sp = sys_cfg.spectrum
                if (
                    sp.service_band_start_mhz is None
                    or sp.service_band_stop_mhz is None
                    or float(sp.service_band_stop_mhz) <= float(sp.service_band_start_mhz)
                ):
                    return False, (
                        f"{label}: UEMR spectrum needs a valid service band "
                        "(start < stop) on the Spectrum tab."
                    )
                if not sp.unwanted_emission_mask_preset:
                    return False, (
                        f"{label}: UEMR spectrum needs a transmit mask preset "
                        "selected on the Spectrum tab."
                    )
            else:
                try:
                    _normalize_spectrum_config(sys_cfg.service, sys_cfg.spectrum, state.ras_station)
                except TypeError:
                    return False, (
                        f"{label}: spectrum configuration incomplete. "
                        "Check that RAS receiver band start/stop and response mode are set."
                    )
                except Exception as exc:
                    return False, f"{label}: spectrum invalid ({exc})."
            # Surface-PFD cap: when the user enables the cap, we need
            # exactly one of the limit forms (per-MHz or per-channel)
            # set to a finite value, and a known cap mode.  Catch this
            # here so the run doesn't fail deep inside the power kernel
            # with a cryptic LUT / limit mismatch error.
            svc_cfg = sys_cfg.service
            if bool(getattr(svc_cfg, "max_surface_pfd_enabled", False)):
                # UEMR + cap is a semantic mismatch — block at the GUI
                # layer so the user sees a clear readiness message
                # instead of the pipeline's runtime ValueError.
                if _system_is_uemr(sys_cfg):
                    return False, (
                        f"{label}: Surface-PFD cap cannot be combined with "
                        f"UEMR mode. UEMR radiates omnidirectionally with no "
                        f"beams to cap — disable either the cap or the UEMR "
                        f"flag on this system."
                    )
                _cap_mhz = getattr(svc_cfg, "max_surface_pfd_dbw_m2_mhz", None)
                _cap_ch = getattr(svc_cfg, "max_surface_pfd_dbw_m2_channel", None)
                _cap_mhz_ok = _cap_mhz is not None and np.isfinite(float(_cap_mhz))
                _cap_ch_ok = _cap_ch is not None and np.isfinite(float(_cap_ch))
                if not (_cap_mhz_ok or _cap_ch_ok):
                    return False, (
                        f"{label}: surface-PFD cap is enabled but no limit value "
                        f"is set. Enter a PFD limit on the Service & Demand tab "
                        f"or disable the cap."
                    )
                _cap_mode = str(getattr(svc_cfg, "surface_pfd_cap_mode", "per_beam") or "per_beam")
                if _cap_mode not in {"per_beam", "per_satellite"}:
                    return False, (
                        f"{label}: surface_pfd_cap_mode must be 'per_beam' or "
                        f"'per_satellite'; got {_cap_mode!r}."
                    )
        # --- Shared checks ---
        s0 = state.active_system()
        svc = s0.service
        if not _has_complete_ras_station_config(state.ras_station):
            return False, "Run Simulation requires a fully configured RAS station."
        if (
            state.ras_station is not None
            and state.ras_station.latitude_deg is not None
            and not (-90.0 <= float(state.ras_station.latitude_deg) <= 90.0)
        ):
            return False, "RAS station latitude must be between -90 and +90 degrees."
        if (
            state.ras_station is not None
            and state.ras_station.longitude_deg is not None
            and not (-360.0 <= float(state.ras_station.longitude_deg) <= 360.0)
        ):
            return False, "RAS station longitude must be between -360 and +360 degrees."
        ras_receiver_ok, ras_receiver_msg = _validate_ras_receiver_config(state.ras_station)
        if not ras_receiver_ok:
            return False, f"Run Simulation: {ras_receiver_msg}"
        if (
            s0.satellite_antennas.frequency_mhz is not None
            and float(s0.satellite_antennas.frequency_mhz) <= 0.0
        ):
            return False, "Operating frequency must be positive."
        if not _has_valid_ras_antenna_config(state.ras_antenna):
            return False, "Run Simulation requires a valid RAS antenna diameter and elevation range."
        # Sanity check constellation size to prevent resource exhaustion
        total_sats = sum(
            int(b.num_sats_per_plane or 0) * int(b.plane_count or 0)
            for b in s0.belts
        )
        if total_sats > 500_000:
            return False, f"Constellation has {total_sats:,} satellites — maximum supported is 500,000."
        # Beam-library-specific checks apply only when the primary system
        # runs the directive pipeline. UEMR bypasses them entirely.
        if not _system_is_uemr(s0):
            if svc.nco is None or int(svc.nco) <= 0:
                return False, "Run Simulation requires Nco to be positive."
            if svc.nbeam is None or int(svc.nbeam) <= 0:
                return False, "Run Simulation requires Nbeam to be positive."
            _max_nco = 64
            try:
                from scepter.gpu_accel import GPU_LINK_SELECTION_MAX_LINKS
                _max_nco = int(GPU_LINK_SELECTION_MAX_LINKS)
            except Exception:
                pass
            if int(svc.nco) > _max_nco:
                return False, f"Run Simulation supports at most {_max_nco} serving links (Nco)."
            if str(svc.selection_strategy or "") not in {
                value for _, value in _SELECTION_STRATEGY_OPTIONS
            }:
                return False, "Run Simulation selection strategy is unsupported."
            if svc.cell_activity_factor is None or not (0.0 <= float(svc.cell_activity_factor) <= 1.0):
                return False, "Run Simulation requires cell activity in [0, 100] %."
        try:
            start_time = _parse_utc_iso_text(state.runtime.base_start_utc_iso)
            end_time = _parse_utc_iso_text(state.runtime.base_end_utc_iso)
        except ValueError as exc:
            return False, f"Run Simulation window is invalid: {exc}"
        if end_time <= start_time:
            return False, "Run Simulation requires Start UTC to be earlier than End UTC."
        if float(state.runtime.timestep_s) <= 0.0:
            return False, "Run Simulation requires a positive timestep."
        if int(state.runtime.iteration_count) <= 0:
            return False, "Run Simulation requires iteration count to be positive."
        if float(state.runtime.host_memory_budget_gb) <= 0.0:
            return False, "Run Simulation requires host memory budget to be positive."
        if float(state.runtime.gpu_memory_budget_gb) <= 0.0:
            return False, "Run Simulation requires GPU memory budget to be positive."
        if str(state.runtime.memory_budget_mode) not in set(_MEMORY_BUDGET_MODE_OPTIONS):
            return False, "Run Simulation memory budget mode is unsupported."
        if str(state.runtime.memory_headroom_profile) not in set(
            _MEMORY_HEADROOM_PROFILE_OPTIONS
        ):
            return False, "Run Simulation headroom profile is unsupported."
        if str(state.runtime.progress_desc_mode) not in set(
            _PROGRESS_DESC_MODE_OPTIONS
        ):
            return False, "Run Simulation progress detail mode is unsupported."
        try:
            _require_service_power_input(state)
        except ValueError:
            if _system_is_uemr(s0):
                return (
                    False,
                    "Run Simulation requires one finite service power "
                    "definition (Ptx or EIRP per MHz) on the Service tab.",
                )
            return (
                False,
                "Run Simulation requires a positive channel bandwidth and one finite service power definition.",
            )
        spec = s0.spectrum
        if (
            spec.service_band_start_mhz is not None
            and spec.service_band_stop_mhz is not None
            and float(spec.service_band_stop_mhz) <= float(spec.service_band_start_mhz)
        ):
            return False, "Service band stop must be greater than start."
        try:
            _normalize_spectrum_config(svc, spec, state.ras_station)
        except Exception as exc:
            return False, f"Run Simulation spectrum plan is invalid: {exc}"
        # Check coverage/hexgrid readiness for ALL systems
        coverage_ok, coverage_msg = self._all_systems_coverage_ready(state)
        if not coverage_ok:
            return False, coverage_msg
        output_families_valid, output_families_message = _validate_output_families_config(
            state.runtime.output_families
        )
        if not output_families_valid:
            return False, output_families_message
        # Validate storage filename is usable
        storage_fn = str(state.runtime.storage_filename or "").strip()
        if not storage_fn:
            return False, "Run Simulation requires a storage filename."
        try:
            storage_dir = Path(storage_fn).parent
            if str(storage_dir) not in {"", "."}:
                if not storage_dir.exists():
                    return False, f"Storage directory does not exist: {storage_dir}"
        except Exception:
            return False, f"Storage filename is invalid: {storage_fn}"
        if state.runtime.include_atmosphere:
            if float(state.runtime.atmosphere_elev_bin_deg) <= 0.0:
                return False, "Run Simulation requires a positive atmosphere elevation bin."
            if not (
                0.0 < float(state.runtime.atmosphere_elev_min_deg)
                < float(state.runtime.atmosphere_elev_max_deg)
                <= 90.0
            ):
                return False, "Run Simulation atmosphere range must satisfy 0 < min < max <= 90."
            if float(state.runtime.atmosphere_max_path_length_km) <= 0.0:
                return False, "Run Simulation requires a positive atmosphere max path."
        if (
            state.runtime.force_bulk_timesteps is not None
            and int(state.runtime.force_bulk_timesteps) < 1
        ):
            return False, "Run Simulation force bulk timesteps must be at least 1 when set."
        if str(state.runtime.gpu_method) not in {value for _, value in _GPU_METHOD_OPTIONS}:
            return False, "Run Simulation GPU method is unsupported."
        if str(state.runtime.gpu_compute_dtype) not in {
            value for _, value in _GPU_COMPUTE_DTYPE_OPTIONS
        }:
            return False, "Run Simulation GPU compute dtype is unsupported."
        if str(state.runtime.gpu_output_dtype) not in {
            value for _, value in _GPU_OUTPUT_DTYPE_OPTIONS
        }:
            return False, "Run Simulation GPU output dtype is unsupported."
        if str(state.runtime.gpu_on_error) not in {
            value for _, value in _GPU_ON_ERROR_OPTIONS
        }:
            return False, "Run Simulation GPU on-error mode is unsupported."
        if state.runtime.hdf5_compression not in {None, "lzf", "gzip"}:
            return False, "Run Simulation HDF5 compression is unsupported."
        if state.runtime.hdf5_compression == "gzip":
            if (
                state.runtime.hdf5_compression_opts is None
                or not (0 <= int(state.runtime.hdf5_compression_opts) <= 9)
            ):
                return False, "Run Simulation gzip compression level must lie in [0, 9]."
        if str(state.runtime.sat_frame) != "xyz":
            return False, "Run Simulation currently supports only sat_frame='xyz'."
        return True, "Run Simulation is ready."

    def _viewer_can_launch(self, state: ScepterProjectState | None = None) -> bool:
        del state
        return True

    def _update_run_controls(self, state: ScepterProjectState | None = None) -> None:
        state_use = self.current_state() if state is None else state
        ready, message = self._run_readiness_payload(state_use)
        self.run_simulation_button.setEnabled(ready and not self._run_in_progress)
        self.stop_simulation_button.setEnabled(bool(self._run_in_progress))
        self.force_stop_simulation_button.setEnabled(bool(self._run_in_progress))
        if self._run_in_progress:
            self.run_status_label.setText("Simulation is running...")
            self._set_persistent_status_bar_message("Running")
        elif self._run_status_override is not None:
            self.run_status_label.setText(self._run_status_override)
            if "failed" in str(self._run_status_override).lower():
                self._set_persistent_status_bar_message("Failed")
            elif "complete" in str(self._run_status_override).lower():
                self._set_persistent_status_bar_message("Completed")
            elif "stopped" in str(self._run_status_override).lower():
                self._set_persistent_status_bar_message("Stopped")
        else:
            self.run_status_label.setText(
                "Ready for review. Check the parameters and outputs below, then launch the simulation."
                if ready
                else message
            )
            self._set_persistent_status_bar_message("Ready")
        if hasattr(self, "simulation_page_list"):
            self._update_simulation_page_indicators(state_use)
        if hasattr(self, "guidance_title_label"):
            self._update_guidance_panel(state_use)

    def _sync_rf_panel(self) -> None:
        derive = bool(self.derive_pattern_wavelength_checkbox.isChecked())
        self.pattern_wavelength_spin.setEnabled(not derive)
        frequency_value = self._shared_frequency_value_or_none()
        if derive and frequency_value is not None:
            blocker = QtCore.QSignalBlocker(self.pattern_wavelength_spin)
            self.pattern_wavelength_spin.set_value(
                _pattern_wavelength_cm_from_frequency_mhz(float(frequency_value))
            )
            del blocker
        selected_model = str(self.antenna_model_combo.currentData() or _ANTENNA_MODEL_REC12)
        # S.672 uses the same parameter set as Rec 1.2 (same piecewise envelope)
        _model_page = {
            _ANTENNA_MODEL_REC12: 0, _ANTENNA_MODEL_REC14: 1,
            _ANTENNA_MODEL_M2101: 2, _ANTENNA_MODEL_S672: 0,
            _ANTENNA_MODEL_COLLAPSED: 3, _ANTENNA_MODEL_ISOTROPIC: 4,
        }
        self.rf_model_stack.setCurrentIndex(_model_page.get(selected_model, 1))
        # S.672 calls the near-in sidelobe level "Ls"; S.1528 calls it "LN"
        if hasattr(self, "_rec12_ln_label"):
            self._rec12_ln_label.setText(
                "Ls [dB]" if selected_model == _ANTENNA_MODEL_S672 else "LN [dB]"
            )
        # UEMR-mode gating: when the UEMR isotropic bypass is active, the
        # beam library is skipped so Nbeam, coverage & contours, coverage &
        # boresight, and surface-PFD cap are all inapplicable.
        self._apply_uemr_mode_gating(
            uemr_active=(
                selected_model == _ANTENNA_MODEL_ISOTROPIC
                and bool(self.isotropic_uemr_checkbox.isChecked())
            )
        )

    def _apply_uemr_mode_gating(self, *, uemr_active: bool) -> None:
        """Hide GUI sections that don't apply in UEMR mode.

        In UEMR the beam library is bypassed entirely, so Nco / Nbeam /
        selection / cell-activity controls have no effect; the coverage
        tabs run an analyser that can't produce meaningful cell sizes
        without a directive pattern; and the surface-PFD cap is blocked
        at runtime. Hide all of these (rather than just disabling) so
        users aren't confused by inapplicable controls.
        """
        # Hide per-row Service & Demand fields that don't apply. For each
        # field widget we hide (a) the inner widget, (b) its helper-button
        # container (so the "?" goes away too), and (c) call
        # ``setRowVisible`` on the form so the row label also disappears.
        for form_attr, field_attrs in (
            ("_service_form_left", ("service_nco_edit", "service_nbeam_edit", "service_selection_combo")),
            (
                "_service_form_right",
                (
                    "service_cell_activity_edit",
                    "service_cell_activity_mode_combo",
                    "service_cell_seed_edit",
                    # UEMR does not have channels — Channel bandwidth
                    # is forced to equal the service band width. Power
                    # basis is forced to per_mhz (spectral density is the
                    # only meaningful UEMR quantity), and Power variation
                    # is forced to fixed (no stochastic UEMR model). The
                    # range min/max editors are NOT listed here — they
                    # are managed by ``_sync_service_power_controls`` based
                    # on the fixed/range mode, and that path already hides
                    # them when UEMR forces fixed.
                    "service_bandwidth_edit",
                    "service_power_basis_combo",
                    "service_power_variation_combo",
                ),
            ),
        ):
            form = getattr(self, form_attr, None)
            if form is None:
                continue
            for fname in field_attrs:
                field = getattr(self, fname, None)
                if field is None:
                    continue
                container = self._help_buttons[field].parent() if field in self._help_buttons else None
                try:
                    field.setVisible(not uemr_active)
                except Exception:
                    pass
                if container is not None:
                    try:
                        container.setVisible(not uemr_active)
                    except Exception:
                        pass
                try:
                    form.setRowVisible(container or field, not uemr_active)
                except Exception:
                    pass
        # Hide both coverage tabs entirely — their analyser requires a
        # finite beamwidth and has no useful output for isotropic UEMR.
        tabs = getattr(self, "tab_widget", None) or getattr(self, "tabs", None)
        coverage_labels = {"Coverage & Contours", "Coverage & Boresight"}
        if tabs is not None:
            for tab_attr in ("grid_tab", "hexgrid_tab"):
                tab = getattr(self, tab_attr, None)
                if tab is None:
                    continue
                try:
                    idx = tabs.indexOf(tab)
                    if idx >= 0:
                        tabs.setTabVisible(idx, not uemr_active)
                except Exception:
                    try:
                        tabs.setTabEnabled(idx, not uemr_active)
                    except Exception:
                        pass
        # The sidebar is a QListWidget (self.simulation_page_list) that
        # drives tab selection; QTabWidget's tabBar is hidden. Hide the
        # two coverage entries in the sidebar rail too.
        sim_list = getattr(self, "simulation_page_list", None)
        if sim_list is not None:
            for row in range(sim_list.count()):
                item = sim_list.item(row)
                if item is None:
                    continue
                tab_idx = item.data(QtCore.Qt.UserRole)
                if tab_idx is None or tabs is None:
                    continue
                try:
                    tab_label = tabs.tabText(int(tab_idx))
                except Exception:
                    continue
                if tab_label in coverage_labels:
                    item.setHidden(uemr_active)
        # Hide the surface-PFD cap group box wholesale.
        cap_group = getattr(self, "_surface_pfd_cap_group_widget", None)
        if cap_group is not None:
            try:
                cap_group.setVisible(not uemr_active)
            except Exception:
                pass
        # Spectrum & Reuse: in UEMR mode, cell-reuse concepts do not apply
        # (no beams are assigned to cells). Keep the transmit mask / service
        # band for emission-mask shaping, but hide reuse factor, RAS
        # anchor slot, group power policy, and split-denominator rule.
        # The "Show Reuse Scheme" preview also has no meaning without beams.
        for reuse_btn_attr in ("show_reuse_scheme_button",):
            btn = getattr(self, reuse_btn_attr, None)
            if btn is not None:
                try:
                    btn.setVisible(not uemr_active)
                except Exception:
                    pass
        service_band_form = getattr(self, "_spectrum_service_band_form", None)
        if service_band_form is not None:
            for inner_attr, field_attr in (
                ("spectrum_reuse_factor_combo", "spectrum_reuse_factor_field"),
                ("spectrum_anchor_slot_spin", "spectrum_anchor_slot_field"),
                ("spectrum_power_policy_combo", "spectrum_power_policy_field"),
                ("spectrum_split_denominator_combo", "spectrum_split_denominator_field"),
            ):
                inner = getattr(self, inner_attr, None)
                container = getattr(self, field_attr, None)
                if inner is not None:
                    try:
                        inner.setVisible(not uemr_active)
                    except Exception:
                        pass
                if container is not None:
                    try:
                        container.setVisible(not uemr_active)
                    except Exception:
                        pass
                    try:
                        service_band_form.setRowVisible(container, not uemr_active)
                    except Exception:
                        pass

        # UEMR: hide the Integration cutoff basis + Integration cutoff
        # percent rows. For UEMR we force the basis to 'service_bandwidth'
        # and the cutoff to 100% because there are no channels and we
        # want to integrate the unwanted-emission mask over the full
        # service band.
        mask_form = getattr(self, "_spectrum_mask_form", None)
        if mask_form is not None:
            for inner_attr, field_attr in (
                ("spectrum_cutoff_basis_combo", "spectrum_cutoff_basis_field"),
                ("spectrum_cutoff_percent_edit", "spectrum_cutoff_percent_field"),
            ):
                inner = getattr(self, inner_attr, None)
                container = getattr(self, field_attr, None)
                if inner is not None:
                    try:
                        inner.setVisible(not uemr_active)
                    except Exception:
                        pass
                if container is not None:
                    try:
                        container.setVisible(not uemr_active)
                    except Exception:
                        pass
                    try:
                        mask_form.setRowVisible(container, not uemr_active)
                    except Exception:
                        pass

        # Restrict the Power-quantity dropdown in UEMR mode. "Target PFD"
        # has no meaning without a directive beam pointing at the surface,
        # so remove it from the combo entirely. Restore all three options
        # when UEMR is turned off. Signal-block the combo during population,
        # then call _sync_service_power_controls() AFTER so the form label
        # ("Satellite Ptx [dBW/MHz]") and hint text match the new selection.
        if hasattr(self, "service_power_quantity_combo"):
            _combo = self.service_power_quantity_combo
            _blocker = QtCore.QSignalBlocker(_combo)
            try:
                _cur_data = _combo.currentData()
                _combo.clear()
                for _label, _value in _SERVICE_POWER_INPUT_QUANTITY_OPTIONS:
                    if uemr_active and _value == "target_pfd":
                        continue
                    _combo.addItem(_label, userData=_value)
                # Restore selection where possible; in UEMR if the prior
                # selection was target_pfd, fall back to satellite_ptx.
                _desired = _cur_data
                if uemr_active and _desired == "target_pfd":
                    _desired = "satellite_ptx"
                _idx = _combo.findData(_desired)
                if _idx >= 0:
                    _combo.setCurrentIndex(_idx)
            finally:
                del _blocker
            # Sync form label + hint text to the (possibly new) selection.
            # Safe to call without the state-change cascade because we're
            # already inside the gating/refresh path.
            try:
                self._sync_service_power_controls()
            except Exception:
                pass

        # Force the hidden-field defaults when UEMR is turned on so the
        # state model always has the values the kernel expects. Signal
        # blockers keep us from firing cascading state-change events
        # that would re-trigger this helper.
        if uemr_active:
            self._apply_uemr_forced_defaults()

        # Hide reuse/leakage-preview leftover labels on the Spectrum
        # page under UEMR (they reference cell-reuse concepts). Under
        # directive mode, show them; their contents are refreshed by
        # ``_sync_spectrum_controls`` so display is always consistent.
        for leftover_attr in (
            "spectrum_zero_leftover_label",
            "spectrum_mask_summary_label",
            "spectrum_leakage_summary_label",
        ):
            widget = getattr(self, leftover_attr, None)
            if widget is not None:
                try:
                    widget.setVisible(not uemr_active)
                except Exception:
                    pass

        # Rename the sidebar rail entry AND the tab-widget tab text when
        # UEMR is active: "Spectrum & Reuse" → "Spectrum", "Service &
        # Demand" → "Service". Both the sidebar list item and the
        # underlying tab header need updating so the title shown at the
        # top of the Simulation workspace stays in sync with the sidebar.
        sim_list2 = getattr(self, "simulation_page_list", None)
        tabs2 = getattr(self, "tab_widget", None)
        if tabs2 is not None:
            # Track original labels so we can restore on toggle-off.
            orig = getattr(self, "_uemr_tab_orig_labels", None)
            if orig is None:
                orig = {}
                for tab_attr, default_label in (
                    ("spectrum_tab", "Spectrum & Reuse"),
                    ("service_tab", "Service & Demand"),
                ):
                    tab = getattr(self, tab_attr, None)
                    if tab is None:
                        continue
                    idx = tabs2.indexOf(tab)
                    if idx >= 0:
                        orig[tab_attr] = tabs2.tabText(idx) or default_label
                self._uemr_tab_orig_labels = orig
            _renames = {
                "spectrum_tab": ("Spectrum", orig.get("spectrum_tab", "Spectrum & Reuse")),
                "service_tab": ("Service", orig.get("service_tab", "Service & Demand")),
            }
            for tab_attr, (uemr_label, full_label) in _renames.items():
                tab = getattr(self, tab_attr, None)
                if tab is None:
                    continue
                idx = tabs2.indexOf(tab)
                if idx >= 0:
                    tabs2.setTabText(idx, uemr_label if uemr_active else full_label)
        if sim_list2 is not None and tabs2 is not None:
            for row in range(sim_list2.count()):
                item = sim_list2.item(row)
                if item is None:
                    continue
                tab_idx = item.data(QtCore.Qt.UserRole)
                if tab_idx is None:
                    continue
                try:
                    tab_label = tabs2.tabText(int(tab_idx))
                except Exception:
                    continue
                # Now that tab text is renamed in UEMR, match on either name.
                if tab_label in ("Spectrum & Reuse", "Spectrum"):
                    item.setText("Spectrum" if uemr_active else "Spectrum & Reuse")
                elif tab_label in ("Service & Demand", "Service"):
                    item.setText("Service" if uemr_active else "Service & Demand")

    def _apply_uemr_forced_defaults(self) -> None:
        """Force the hidden Service & Demand / Spectrum fields to the
        values the UEMR kernel expects. Safe to call repeatedly.

        Channel bandwidth auto-tracks the service band width (stop-start).
        Power basis is locked to per_mhz, Power variation to fixed. The
        spectrum-plan integration cutoff is locked to the full service
        band (basis=service_bandwidth, percent=100).
        """
        blockers: list[QtCore.QSignalBlocker] = []
        try:
            # Channel bandwidth ← service band width
            start = self.spectrum_service_band_start_edit.value_or_none()
            stop = self.spectrum_service_band_stop_edit.value_or_none()
            if (
                start is not None and stop is not None
                and float(stop) > float(start)
            ):
                width = float(stop) - float(start)
                blockers.append(QtCore.QSignalBlocker(self.service_bandwidth_edit))
                self.service_bandwidth_edit.set_value(round(width, 6))
            # Power basis ← per_mhz
            idx_pm = self.service_power_basis_combo.findData("per_mhz")
            if idx_pm >= 0 and self.service_power_basis_combo.currentIndex() != idx_pm:
                blockers.append(QtCore.QSignalBlocker(self.service_power_basis_combo))
                self.service_power_basis_combo.setCurrentIndex(idx_pm)
            # Power variation ← fixed
            idx_fixed = self.service_power_variation_combo.findData("fixed")
            if idx_fixed >= 0 and self.service_power_variation_combo.currentIndex() != idx_fixed:
                blockers.append(QtCore.QSignalBlocker(self.service_power_variation_combo))
                self.service_power_variation_combo.setCurrentIndex(idx_fixed)
            # Transmit unwanted-emission mask: the flat (rectangular)
            # preset is the correct *baseline* for UEMR because
            # internal-circuitry leakage is spatially-isotropic and
            # flat-across-band. But the user can legitimately model
            # more realistic shapes — a vendor-specific roll-off via
            # "custom", an ITU template, etc. — so we only snap the
            # combo when it's still at its "no preset chosen yet"
            # placeholder. An explicit user choice is preserved.
            current_mask = self.spectrum_mask_preset_combo.currentData()
            if current_mask in (None, ""):
                idx_flat = self.spectrum_mask_preset_combo.findData("flat")
                if idx_flat >= 0 and self.spectrum_mask_preset_combo.currentIndex() != idx_flat:
                    blockers.append(QtCore.QSignalBlocker(self.spectrum_mask_preset_combo))
                    self.spectrum_mask_preset_combo.setCurrentIndex(idx_flat)
            # Integration cutoff basis ← service_bandwidth
            idx_sb = self.spectrum_cutoff_basis_combo.findData("service_bandwidth")
            if idx_sb >= 0 and self.spectrum_cutoff_basis_combo.currentIndex() != idx_sb:
                blockers.append(QtCore.QSignalBlocker(self.spectrum_cutoff_basis_combo))
                self.spectrum_cutoff_basis_combo.setCurrentIndex(idx_sb)
            # Integration cutoff ← 50% of service bandwidth.
            # The cutoff window is [center ± cutoff_mhz] where
            # cutoff_mhz = span × percent / 100, so the TOTAL integration
            # width equals 2·cutoff. Setting percent=50 with basis=
            # service_bandwidth makes 2·cutoff == service_bandwidth,
            # i.e. the integration window exactly matches the service
            # band edges — the correct UEMR baseline.
            current_pct = self.spectrum_cutoff_percent_edit.value_or_none()
            if current_pct is None or abs(float(current_pct) - 50.0) > 1e-6:
                blockers.append(QtCore.QSignalBlocker(self.spectrum_cutoff_percent_edit))
                self.spectrum_cutoff_percent_edit.set_value(50.0)
            # Reuse factor ← 1 (UEMR has no cells; force sane default so
            # the spectrum-plan normaliser doesn't choke on None).
            idx_r1 = self.spectrum_reuse_factor_combo.findData(1)
            if idx_r1 < 0:
                idx_r1 = self.spectrum_reuse_factor_combo.findText("1")
            if idx_r1 >= 0 and self.spectrum_reuse_factor_combo.currentIndex() != idx_r1:
                blockers.append(QtCore.QSignalBlocker(self.spectrum_reuse_factor_combo))
                self.spectrum_reuse_factor_combo.setCurrentIndex(idx_r1)
            # Anchor slot ← 0
            if self.spectrum_anchor_slot_spin.count() > 0:
                idx_a0 = self.spectrum_anchor_slot_spin.findData(0)
                if idx_a0 < 0:
                    idx_a0 = 0
                if self.spectrum_anchor_slot_spin.currentIndex() != idx_a0:
                    blockers.append(QtCore.QSignalBlocker(self.spectrum_anchor_slot_spin))
                    self.spectrum_anchor_slot_spin.setCurrentIndex(idx_a0)
            # Power policy ← repeat_per_group (the simple default; reuse
            # scheme is disabled in UEMR so the policy never matters).
            idx_pp = self.spectrum_power_policy_combo.findData("repeat_per_group")
            if idx_pp >= 0 and self.spectrum_power_policy_combo.currentIndex() != idx_pp:
                blockers.append(QtCore.QSignalBlocker(self.spectrum_power_policy_combo))
                self.spectrum_power_policy_combo.setCurrentIndex(idx_pp)
            # Split-denominator mode ← configured_groups
            idx_sd = self.spectrum_split_denominator_combo.findData("configured_groups")
            if idx_sd >= 0 and self.spectrum_split_denominator_combo.currentIndex() != idx_sd:
                blockers.append(QtCore.QSignalBlocker(self.spectrum_split_denominator_combo))
                self.spectrum_split_denominator_combo.setCurrentIndex(idx_sd)
        finally:
            del blockers

    def _update_antenna_plot_controls(self) -> None:
        state = self.current_state()
        antennas_cfg = state.active_system().satellite_antennas
        enabled = _has_valid_satellite_antenna_config(antennas_cfg)
        # The main-lobe plot derives the zoom window from the half-power
        # beamwidth. Isotropic has no beamwidth, so disable that button
        # specifically while leaving the full-pattern plot available.
        is_isotropic = (
            antennas_cfg is not None
            and str(getattr(antennas_cfg, "antenna_model", "") or "") == _ANTENNA_MODEL_ISOTROPIC
        )
        self.plot_antenna_full_button.setEnabled(enabled)
        self.plot_antenna_main_button.setEnabled(enabled and not is_isotropic)
        self.plot_antenna_main_button.setToolTip(
            "Main-lobe plot is unavailable for isotropic patterns "
            "(no finite beamwidth). Use the full-pattern plot instead."
            if (enabled and is_isotropic) else ""
        )
        self.antenna_pattern_status.setText(
            "Pattern plots are ready."
            if enabled
            else "Pattern plots require a valid satellite-system antenna."
        )
        ras_enabled = _has_valid_ras_antenna_config(state.ras_antenna)
        if ras_enabled:
            # The RAS pattern depends only on the RAS station's own
            # frequency — it is a receive antenna property and has nothing
            # to do with the satellite transmit antenna.
            try:
                ras_freq = state.ras_antenna.frequency_mhz
                ras_enabled = ras_freq is not None and float(ras_freq) > 0.0
            except Exception:
                ras_enabled = False
        self.plot_ras_pattern_button.setEnabled(ras_enabled)
        self.ras_pattern_status.setText(
            "RAS antenna pattern is ready."
            if ras_enabled
            else "RAS pattern plots require a valid RAS antenna, elevation range, and a positive RAS frequency."
        )

    def _ras_notice_payload(self, state: ScepterProjectState) -> tuple[str, str]:
        if state.ras_station is None or not _has_any_ras_station_value(state.ras_station):
            return (
                "warning",
                "RAS station is not configured. Fill longitude, latitude, and elevation to place it in the viewer.",
            )
        if not _has_complete_ras_station_config(state.ras_station):
            return (
                "warning",
                "RAS station geometry is incomplete. Fill longitude, latitude, and elevation to continue.",
            )
        return ("ready", "RAS station is configured and ready for the next step.")

    def _antennas_notice_payload(self, state: ScepterProjectState) -> tuple[str, str]:
        sa = state.active_system().satellite_antennas
        if sa.frequency_mhz is None and sa.antenna_model is None:
            return (
                "warning",
                "Antennas are not configured. Preview works, but the analyser and contours need satellite antenna data.",
            )
        if not _has_valid_satellite_antenna_config(state.active_system().satellite_antennas):
            return (
                "warning",
                "Antenna data is incomplete. Fill the satellite-system antenna fields to continue.",
            )
        return ("ready", "Antenna configuration is ready for the analyser and contour tools.")

    def _hexgrid_notice_payload(self, state: ScepterProjectState) -> tuple[str, str]:
        if self._hexgrid_outdated:
            return ("warning", self._hexgrid_status_message(state))
        return ("ready", self._hexgrid_status_message(state))


    def _show_context_toast_for_current_tab(self, state: ScepterProjectState | None = None) -> None:
        state_use = self.current_state() if state is None else state
        self._update_simulation_page_indicators(state_use)

    def _update_workspace_nav_toggle_button(self) -> None:
        expanded = bool(self._workspace_nav_expanded)
        icon = _build_sidebar_toggle_icon(expanded=expanded)
        self.workspace_nav_toggle_button.setIcon(icon)
        self.workspace_nav_toggle_button.setText("")
        self.workspace_nav_toggle_button.setProperty("modernToggle", True)
        self.workspace_nav_toggle_button.setToolButtonStyle(QtCore.Qt.ToolButtonIconOnly)
        self._set_control_button_metrics(self.workspace_nav_toggle_button)
        self.workspace_nav_toggle_button.setToolTip(
            "Collapse workspace navigation." if expanded else "Expand workspace navigation."
        )

    def _workspace_nav_interaction_active(self) -> bool:
        focus_widget = QtWidgets.QApplication.focusWidget()
        if focus_widget is not None and self.workspace_nav.isAncestorOf(focus_widget):
            return True
        return bool(
            self.workspace_nav.isVisible()
            and (
                self.workspace_nav.underMouse()
                or self.workspace_nav_toggle_button.underMouse()
                or self.workspace_nav_pin_button.underMouse()
            )
        )

    def _restart_workspace_nav_auto_hide_timer(self) -> None:
        if (not self._workspace_nav_expanded) or self._workspace_nav_pinned or self._workspace_nav_interaction_active():
            self._workspace_nav_auto_hide_timer.stop()
            return
        self._workspace_nav_auto_hide_timer.setInterval(_WORKSPACE_NAV_AUTO_HIDE_MS)
        self._workspace_nav_auto_hide_timer.start()

    def _collapse_workspace_nav_if_idle(self) -> None:
        if (not self._workspace_nav_expanded) or self._workspace_nav_pinned:
            return
        if self._workspace_nav_interaction_active():
            self._restart_workspace_nav_auto_hide_timer()
            return
        self._set_workspace_nav_expanded(False)

    def _apply_workspace_nav_width(self, width: int) -> None:
        width_use = max(int(width), _WORKSPACE_NAV_COLLAPSED_WIDTH)
        self._workspace_nav_current_width = width_use
        self.workspace_nav.setMinimumWidth(width_use)
        self.workspace_nav.setMaximumWidth(width_use)
        self._schedule_responsive_layout_refresh()

    def _animate_workspace_nav_to(self, width: int) -> None:
        target_width = max(int(width), _WORKSPACE_NAV_COLLAPSED_WIDTH)
        if self._workspace_nav_animation_group is not None:
            self._workspace_nav_animation_group.stop()
            self._workspace_nav_animation_group = None
        if not self._animations_enabled:
            if self._workspace_nav_width_effect is not None:
                self._workspace_nav_width_effect.setOpacity(1.0)
            self._apply_workspace_nav_width(target_width)
            return
        start_width = int(self._workspace_nav_current_width)
        expanding = target_width > start_width
        width_animation = QtCore.QVariantAnimation(self)
        width_animation.setDuration(_UI_MOTION_DURATION_MS)
        width_animation.setEasingCurve(_UI_MOTION_EASING)
        width_animation.setStartValue(start_width)
        width_animation.setEndValue(target_width)
        width_animation.valueChanged.connect(
            lambda value: self._apply_workspace_nav_width(int(float(value)))
        )
        group = QtCore.QParallelAnimationGroup(self)
        group.addAnimation(width_animation)
        if self._workspace_nav_width_effect is not None:
            start_opacity = float(self._workspace_nav_width_effect.opacity())
            target_opacity = 1.0 if expanding else 0.7
            opacity_animation = QtCore.QPropertyAnimation(
                self._workspace_nav_width_effect, b"opacity", self,
            )
            opacity_animation.setDuration(_UI_MOTION_DURATION_MS)
            opacity_animation.setEasingCurve(_UI_MOTION_EASING)
            opacity_animation.setStartValue(start_opacity)
            opacity_animation.setEndValue(target_opacity)
            group.addAnimation(opacity_animation)

        def _finish_workspace_nav_animation() -> None:
            self._workspace_nav_animation_group = None
            self._apply_workspace_nav_width(target_width)
            if self._workspace_nav_width_effect is not None:
                self._workspace_nav_width_effect.setOpacity(1.0)

        group.finished.connect(_finish_workspace_nav_animation)
        self._workspace_nav_animation_group = group
        group.start(QtCore.QAbstractAnimation.DeleteWhenStopped)

    def _set_workspace_nav_expanded(self, expanded: bool) -> None:
        self._workspace_nav_expanded = bool(expanded)
        self.workspace_nav_toggle_button.blockSignals(True)
        self.workspace_nav_toggle_button.setChecked(self._workspace_nav_expanded)
        self.workspace_nav_toggle_button.blockSignals(False)
        self._update_workspace_nav_toggle_button()
        self._refresh_workspace_nav_layout()
        self._animate_workspace_nav_to(
            _WORKSPACE_NAV_EXPANDED_WIDTH if self._workspace_nav_expanded else _WORKSPACE_NAV_COLLAPSED_WIDTH
        )
        self._restart_workspace_nav_auto_hide_timer()

    def _update_workspace_nav_policy(self) -> None:
        self._update_workspace_nav_toggle_button()
        self._refresh_workspace_nav_layout()
        self._apply_workspace_nav_width(
            _WORKSPACE_NAV_EXPANDED_WIDTH if self._workspace_nav_expanded else _WORKSPACE_NAV_COLLAPSED_WIDTH
        )
        self._restart_workspace_nav_auto_hide_timer()

    @QtCore.Slot(bool)
    def _on_workspace_nav_toggle_changed(self, checked: bool) -> None:
        self._set_workspace_nav_expanded(bool(checked))

    @QtCore.Slot(bool)
    def _on_workspace_nav_pin_changed(self, checked: bool) -> None:
        self._workspace_nav_pinned = bool(checked)
        if self._workspace_nav_pinned and (not self._workspace_nav_expanded):
            self._set_workspace_nav_expanded(True)
        self._set_pin_button_icon(
            self.workspace_nav_pin_button,
            pinned=self._workspace_nav_pinned,
            tooltip="Pin workspace navigation." if self._workspace_nav_pinned else "Allow workspace navigation to auto-collapse.",
        )
        self._update_workspace_nav_policy()

    def _update_side_pane_toggle_button(self) -> None:
        visible = bool(self._side_pane_visible)
        button = self.side_pane_toggle_button
        icon = _build_assistant_toggle_icon(visible=visible)
        button.setIcon(icon)
        button.setToolButtonStyle(QtCore.Qt.ToolButtonTextBesideIcon)
        button.setText("Assistant")
        button.setProperty("modernToggle", True)
        button.setSizePolicy(QtWidgets.QSizePolicy.Fixed, QtWidgets.QSizePolicy.Fixed)
        self._set_control_button_metrics(button, square=False)
        button.setToolTip(
            "Hide the assistant panel." if visible else "Show the assistant panel."
        )

    def _assistant_panel_interaction_active(self) -> bool:
        if self.current_workspace() != _WORKSPACE_SIMULATION:
            return False
        focus_widget = QtWidgets.QApplication.focusWidget()
        if focus_widget is not None and self._right_container.isAncestorOf(focus_widget):
            return True
        return bool(
            self._right_container.isVisible()
            and (self._right_container.underMouse() or self.side_pane_toggle_button.underMouse())
        )

    def _restart_side_pane_auto_hide_timer(self) -> None:
        if (
            self.current_workspace() != _WORKSPACE_SIMULATION
            or (not self._side_pane_visible)
            or self._side_pane_pinned
            or self._assistant_panel_interaction_active()
        ):
            self._side_pane_auto_hide_timer.stop()
            return
        self._side_pane_auto_hide_timer.setInterval(_ASSISTANT_PANEL_AUTO_HIDE_MS)
        self._side_pane_auto_hide_timer.start()

    def _hide_side_pane_if_idle(self) -> None:
        if (
            self.current_workspace() != _WORKSPACE_SIMULATION
            or (not self._side_pane_visible)
            or self._side_pane_pinned
        ):
            return
        if self._assistant_panel_interaction_active():
            self._restart_side_pane_auto_hide_timer()
            return
        self._set_side_pane_visible(False)

    def _apply_side_pane_width(self, width: int) -> None:
        width_use = max(int(width), 0)
        self._side_pane_current_width = width_use
        if width_use <= 0:
            self._right_container.setMinimumWidth(0)
            self._right_container.setMaximumWidth(0)
            self._right_container.hide()
            self._main_splitter.setSizes([1, 0])
            self._schedule_responsive_layout_refresh()
            return
        self._right_container.show()
        self._right_container.setMinimumWidth(width_use)
        self._right_container.setMaximumWidth(width_use)
        total_width = max(self._main_splitter.size().width(), 1120)
        self._main_splitter.setSizes(
            [max(total_width - width_use, _ASSISTANT_PANEL_MIN_MAIN_WIDTH), width_use]
        )
        self._schedule_responsive_layout_refresh()

    def _animate_side_pane_to(self, width: int) -> None:
        target_width = max(int(width), 0)
        if self._side_pane_animation_group is not None:
            self._side_pane_animation_group.stop()
            self._side_pane_animation_group = None
        if (not self._animations_enabled) or self.current_workspace() != _WORKSPACE_SIMULATION:
            if self._side_pane_width_effect is not None:
                self._side_pane_width_effect.setOpacity(1.0 if target_width > 0 else 0.0)
            self._apply_side_pane_width(target_width)
            return
        if target_width > 0:
            self._right_container.show()
        start_width = int(self._side_pane_current_width)
        start_opacity = (
            float(self._side_pane_width_effect.opacity())
            if self._side_pane_width_effect is not None
            else (1.0 if start_width > 0 else 0.0)
        )
        width_animation = QtCore.QVariantAnimation(self)
        width_animation.setDuration(_UI_MOTION_DURATION_MS)
        width_animation.setEasingCurve(_UI_MOTION_EASING)
        width_animation.setStartValue(start_width)
        width_animation.setEndValue(target_width)
        width_animation.valueChanged.connect(
            lambda value: self._apply_side_pane_width(int(float(value)))
        )
        opacity_animation = QtCore.QPropertyAnimation(
            self._side_pane_width_effect,
            b"opacity",
            self,
        )
        opacity_animation.setDuration(_UI_MOTION_DURATION_MS)
        opacity_animation.setEasingCurve(_UI_MOTION_EASING)
        opacity_animation.setStartValue(start_opacity)
        opacity_animation.setEndValue(1.0 if target_width > 0 else 0.0)
        group = QtCore.QParallelAnimationGroup(self)
        group.addAnimation(width_animation)
        if self._side_pane_width_effect is not None:
            group.addAnimation(opacity_animation)
        def _finish_side_pane_animation() -> None:
            self._side_pane_animation_group = None
            self._apply_side_pane_width(target_width)
            if self._side_pane_width_effect is not None:
                self._side_pane_width_effect.setOpacity(1.0 if target_width > 0 else 0.0)

        group.finished.connect(_finish_side_pane_animation)
        self._side_pane_animation_group = group
        group.start(QtCore.QAbstractAnimation.DeleteWhenStopped)

    def _set_side_pane_visible(self, visible: bool) -> None:
        self._side_pane_visible = bool(visible)
        self.side_pane_toggle_button.blockSignals(True)
        self.side_pane_toggle_button.setChecked(self._side_pane_visible)
        self.side_pane_toggle_button.blockSignals(False)
        self._update_side_pane_toggle_button()
        self._animate_side_pane_to(_RIGHT_PANE_TARGET_WIDTH if self._side_pane_visible else 0)
        self._restart_side_pane_auto_hide_timer()

    def _update_side_pane_policy(self) -> None:
        if self.current_workspace() != _WORKSPACE_SIMULATION:
            self._side_pane_auto_hide_timer.stop()
            return
        self._update_side_pane_toggle_button()
        self._apply_side_pane_width(_RIGHT_PANE_TARGET_WIDTH if self._side_pane_visible else 0)
        self._restart_side_pane_auto_hide_timer()

    @QtCore.Slot(bool)
    def _on_side_pane_toggle_changed(self, checked: bool) -> None:
        self._set_side_pane_visible(bool(checked))

    @QtCore.Slot(bool)
    def _on_side_pane_pin_changed(self, checked: bool) -> None:
        self._side_pane_pinned = bool(checked)
        if self._side_pane_pinned and (not self._side_pane_visible):
            self._set_side_pane_visible(True)
        self._set_pin_button_icon(
            self.side_pane_pin_button,
            pinned=self._side_pane_pinned,
            tooltip="Pin assistant panel." if self._side_pane_pinned else "Allow assistant panel to auto-hide.",
        )
        self._update_side_pane_policy()

    @QtCore.Slot(int)
    def _on_active_tab_changed(self, index: int) -> None:
        item = self.simulation_page_list.item(int(index))
        if item is not None and self.simulation_page_list.currentRow() != int(index):
            blocker = QtCore.QSignalBlocker(self.simulation_page_list)
            self.simulation_page_list.setCurrentRow(int(index))
            del blocker
        label = self.tab_widget.tabText(int(index))
        title, detail = _SIMULATION_PAGE_COPY.get(label, (label, label))
        self.simulation_heading_label.setText(title)
        self.simulation_subheading_label.setText(detail)
        self._update_side_pane_policy()
        self._refresh_help_mode_highlights()
        self._show_context_toast_for_current_tab()
        self._update_run_controls(self.current_state())
        if label == "Review & Run":
            self._refresh_run_summary_strip()
        self._schedule_workspace_geometry_stabilization()

    def _animate_tab_switch(self, target_index: int) -> None:
        """Cross-fade between simulation sub-tabs for a polished transition."""
        if self._tab_fade_animation is not None:
            self._tab_fade_animation.stop()
            self._tab_fade_animation = None
        # Tear down any lingering effect from a previously interrupted animation.
        if self._tab_fade_effect is not None:
            self.tab_widget.setGraphicsEffect(None)
            self._tab_fade_effect = None
        if (
            not self._animations_enabled
            or self.tab_widget.currentIndex() == target_index
        ):
            self.tab_widget.setCurrentIndex(target_index)
            return
        # Sub-tab switch: instant content swap.  The heading and sidebar
        # persist across tabs so only the page content area changes — a
        # fade animation on the whole page would flash unchanged elements.
        self._tab_pending_index = None
        self.tab_widget.setCurrentIndex(target_index)

    @QtCore.Slot(int)
    def _on_simulation_page_selected(self, row: int) -> None:
        item = self.simulation_page_list.item(int(row))
        if item is None:
            return
        tab_index = int(item.data(QtCore.Qt.UserRole))
        if self.tab_widget.currentIndex() != tab_index:
            self._animate_tab_switch(tab_index)

    def _effective_hexgrid_cell_size_km(self, state: ScepterProjectState) -> float | None:
        ga = state.active_system().grid_analysis
        if ga.cell_size_override_enabled and ga.cell_size_override_km is not None:
            return float(ga.cell_size_override_km)
        if self._last_analyser_selected_cell_km is None:
            return None
        return float(self._last_analyser_selected_cell_km)

    def _parse_theta2_cell_ids(self, text: str) -> np.ndarray:
        return _parse_theta2_cell_ids_text(text)

    def _clear_antenna_pattern_canvas(self) -> None:
        for window in self._antenna_pattern_windows:
            try:
                window.close()
            except Exception:
                pass
        self._antenna_pattern_windows = []

    @QtCore.Slot()
    def _on_hexgrid_preview_window_destroyed(self) -> None:
        self._hexgrid_preview_window = None

    @QtCore.Slot(int)
    def _on_hexgrid_cell_picked(self, cell_index: int) -> None:
        """Toggle a cell ID in the θ₂ cell-ID text field when user clicks on the hexgrid preview."""
        current_text = self.hexgrid_boresight_cell_ids_edit.text().strip()
        try:
            current_ids = set(
                int(s.strip()) for s in current_text.replace(";", ",").replace(" ", ",").split(",")
                if s.strip() and s.strip().lstrip("-").isdigit()
            )
        except ValueError:
            current_ids = set()
        # Toggle: add if not present, remove if already present
        if cell_index in current_ids:
            current_ids.discard(cell_index)
        else:
            current_ids.add(cell_index)
        self.hexgrid_boresight_cell_ids_edit.setText(
            ", ".join(str(i) for i in sorted(current_ids))
        )
        # Switch scope to cell_ids mode so the picked cells are used
        scope_idx = self.hexgrid_boresight_scope_combo.findData("cell_ids")
        if scope_idx >= 0:
            self.hexgrid_boresight_scope_combo.setCurrentIndex(scope_idx)
        # Highlight the selected cells on the hexgrid preview map
        self._update_hexgrid_pick_highlights(current_ids)

    def _update_hexgrid_pick_highlights(self, selected_ids: set[int]) -> None:
        """Draw/update magenta markers on the hexgrid preview for picked θ₂ cells."""
        window = self._hexgrid_preview_window
        if window is None or window._cell_pick_lons is None:
            return
        fig = window._figure
        if fig is None or not fig.axes:
            return
        ax = fig.axes[0]
        # Remove previous pick markers
        for artist in list(ax.collections):
            if getattr(artist, "_theta2_pick_marker", False):
                artist.remove()
        if selected_ids:
            lons = window._cell_pick_lons
            lats = window._cell_pick_lats
            sel = sorted(i for i in selected_ids if 0 <= i < len(lons))
            if sel:
                scatter = ax.scatter(
                    lons[sel], lats[sel],
                    s=60, c="none", edgecolors="#e879f9", linewidths=2.0,
                    marker="h", zorder=50,
                )
                scatter._theta2_pick_marker = True
        if window._canvas is not None:
            window._canvas.draw_idle()

    def _clear_hexgrid_preview_canvas(self) -> None:
        if self._hexgrid_preview_window is not None:
            try:
                self._hexgrid_preview_window.close()
            except Exception:
                pass
            self._hexgrid_preview_window = None

    def _can_refresh_hexgrid_preview_from_cache(
        self,
        state: ScepterProjectState,
    ) -> bool:
        commit_signature = self._hexgrid_commit_signature(state)
        return bool(
            self._hexgrid_preview_cached_result is not None
            and commit_signature is not None
            and commit_signature == self._hexgrid_completed_commit_signature
        )

    def _render_hexgrid_preview_from_cache(
        self,
        state: ScepterProjectState,
    ) -> bool:
        if not self._can_refresh_hexgrid_preview_from_cache(state):
            return False
        preview_signature = self._hexgrid_preview_signature(state)
        commit_signature = self._hexgrid_commit_signature(state)
        overlay_signature = self._hexgrid_overlay_signature(state)
        if preview_signature is None or commit_signature is None or self._hexgrid_preview_cached_result is None:
            return False
        cached_result = self._hexgrid_preview_cached_result
        reuse_plan = None
        try:
            reuse_plan = self._resolve_frequency_reuse_plan_for_grid(
                state,
                cached_result.prepared_grid,
            )
        except Exception:
            reuse_plan = None
        started_s = perf_counter()
        self.hexgrid_preview_status_label.setText("Refreshing preview from cached geometry...")
        self._render_hexgrid_preview_result(
            HexgridPreviewComputation(
                prepared_grid=cached_result.prepared_grid,
                boresight_ids=np.asarray(cached_result.boresight_ids, dtype=np.int32),
                reuse_plan=reuse_plan,
                preview_notes=list(cached_result.preview_notes),
                effective_cell_km=float(cached_result.effective_cell_km),
            ),
            cached_render=True,
        )
        elapsed_s = max(perf_counter() - started_s, 0.0)
        self._hexgrid_completed_signature = preview_signature
        self._hexgrid_completed_commit_signature = commit_signature
        self._hexgrid_completed_overlay_signature = overlay_signature
        self._hexgrid_outdated = False
        self.hexgrid_preview_status_label.setText(
            f"Preview ready in {elapsed_s:.2f} s (cached render)."
        )
        self._update_simulation_page_indicators(state)
        self._update_guidance_panel(state)
        return True

    @QtCore.Slot()
    def _on_hexgrid_controls_changed(self) -> None:
        style_only_change = self.sender() is getattr(self, "hexgrid_map_style_combo", None)
        self._update_boresight_scope_field_visibility()
        self._mark_hexgrid_preview_stale(clear_canvas=False)
        self._on_state_changed()
        if self._hexgrid_preview_window is not None:
            self._schedule_hexgrid_preview_refresh(immediate=bool(style_only_change))

    def _on_radio_horizon_toggled(self, checked: bool) -> None:
        """Show/hide the TEC input row when radio horizon is toggled."""
        self.runtime_radio_horizon_tec_edit.setEnabled(checked)
        self._runtime_tec_label.setVisible(checked)
        self._runtime_tec_container.setVisible(checked)

    def _refresh_run_summary_strip(self) -> None:
        """Update the pre-run summary with key parameters at a glance."""
        try:
            state = self.current_state()
            rt = state.runtime
            # Time window
            start = str(rt.base_start_utc_iso).replace("T", " ").replace("Z", "")
            end = str(rt.base_end_utc_iso).replace("T", " ").replace("Z", "")
            # Duration
            from datetime import datetime, timezone
            try:
                t0 = datetime.fromisoformat(str(rt.base_start_utc_iso).replace("Z", "+00:00"))
                t1 = datetime.fromisoformat(str(rt.base_end_utc_iso).replace("Z", "+00:00"))
                duration_s = (t1 - t0).total_seconds()
                if duration_s >= 3600:
                    dur_text = f"{duration_s / 3600:.1f}h"
                elif duration_s >= 60:
                    dur_text = f"{duration_s / 60:.0f}min"
                else:
                    dur_text = f"{duration_s:.0f}s"
            except Exception:
                dur_text = "?"
                duration_s = 0
            timestep = float(rt.timestep_s)
            total_steps = int(duration_s / timestep) if timestep > 0 and duration_s > 0 else 0
            n_iter = int(rt.iteration_count)
            n_systems = len(state.systems)
            total_sats = sum(
                sum(int(b.num_sats_per_plane or 0) * int(b.plane_count or 0) for b in s.belts)
                for s in state.systems
            )
            atmo = "yes" if rt.include_atmosphere else "no"
            radio = "yes" if getattr(rt, "use_radio_horizon", False) else "no"
            mem = f"{rt.gpu_memory_budget_gb:.0f}/{rt.host_memory_budget_gb:.0f} GB"

            lines = [
                f"<b>Window:</b> {start} \u2192 {end} ({dur_text}) "
                f"&nbsp;\u2022&nbsp; <b>Timestep:</b> {timestep:g}s "
                f"&nbsp;\u2022&nbsp; <b>Steps:</b> {total_steps:,} \u00d7 {n_iter} iter",
                f"<b>Systems:</b> {n_systems} ({total_sats:,} satellites) "
                f"&nbsp;\u2022&nbsp; <b>Atmosphere:</b> {atmo} "
                f"&nbsp;\u2022&nbsp; <b>Radio horizon:</b> {radio} "
                f"&nbsp;\u2022&nbsp; <b>Budget (GPU/RAM):</b> {mem}",
            ]
            self._run_summary_strip.setText("<br>".join(lines))
        except Exception:
            self._run_summary_strip.setText("")

    def _update_boresight_scope_field_visibility(self) -> None:
        """Show only the \u03b8\u2082 scope field relevant to the selected mode."""
        if not hasattr(self, "hexgrid_boresight_scope_combo"):
            return
        mode = str(self.hexgrid_boresight_scope_combo.currentData() or "cell_ids")
        form = self.hexgrid_boresight_scope_group.layout()
        if not isinstance(form, QtWidgets.QFormLayout):
            return
        field_visibility = {
            "cell_ids": {"hexgrid_boresight_cell_ids_edit": True, "hexgrid_boresight_layers_spin": False, "hexgrid_boresight_radius_spin": False},
            "adjacency_layers": {"hexgrid_boresight_cell_ids_edit": False, "hexgrid_boresight_layers_spin": True, "hexgrid_boresight_radius_spin": False},
            "radius_km": {"hexgrid_boresight_cell_ids_edit": False, "hexgrid_boresight_layers_spin": False, "hexgrid_boresight_radius_spin": True},
        }.get(mode, {"hexgrid_boresight_cell_ids_edit": True, "hexgrid_boresight_layers_spin": True, "hexgrid_boresight_radius_spin": True})
        for attr_name, visible in field_visibility.items():
            widget = getattr(self, attr_name, None)
            if widget is not None:
                self._set_form_row_visible(form, widget, visible)
        # Also update RAS exclusion field visibility
        self._update_ras_exclusion_field_visibility()

    def _update_ras_exclusion_field_visibility(self) -> None:
        """Show only the RAS exclusion field relevant to the selected mode."""
        form = getattr(self, "_hexgrid_geography_form", None)
        if form is None or not hasattr(self, "hexgrid_ras_exclusion_mode_combo"):
            return
        mode = str(self.hexgrid_ras_exclusion_mode_combo.currentData() or "none")
        show_layers = mode == "adjacency_layers"
        show_radius = mode == "radius_km"
        self._set_form_row_visible(form, self.hexgrid_ras_exclusion_layers_spin, show_layers)
        self._set_form_row_visible(form, self.hexgrid_ras_exclusion_radius_spin, show_radius)

    @QtCore.Slot()
    def _apply_hexgrid_settings(self) -> None:
        self._commit_visible_editors()
        state = self.current_state()
        if not self._contour_is_current(state):
            self._mark_hexgrid_preview_stale(state)
            self._update_guidance_panel(state)
            self._update_run_controls(state)
            return
        commit_signature = self._hexgrid_commit_signature(state)
        if commit_signature is None:
            self._mark_hexgrid_preview_stale(state)
            self._update_guidance_panel(state)
            self._update_run_controls(state)
            return
        self._hexgrid_applied_signature = commit_signature
        self._hexgrid_outdated = False
        self.hexgrid_preview_status_label.setText("Hexgrid settings applied.")
        self._refresh_summary()

    def _schedule_hexgrid_preview_refresh(self, *, immediate: bool = False) -> None:
        if immediate:
            self._hexgrid_preview_timer.stop()
            self._refresh_hexgrid_preview()
            return
        self._hexgrid_preview_timer.start()

    def _cleanup_hexgrid_preview_worker(self) -> None:
        thread = self._hexgrid_thread
        worker = self._hexgrid_worker
        self._hexgrid_thread = None
        self._hexgrid_worker = None
        if worker is not None:
            _safe_disconnect(worker.finished, self._on_hexgrid_preview_ready)
            _safe_disconnect(worker.failed, self._on_hexgrid_preview_failed)
        _detach_managed_worker_job(thread, worker)
        _request_worker_thread_shutdown(thread, wait_ms=50)

    @QtCore.Slot(object, int)
    def _on_hexgrid_preview_ready(self, result: object, build_token: int) -> None:
        elapsed_s = None if self._hexgrid_preview_started_s is None else max(perf_counter() - self._hexgrid_preview_started_s, 0.0)
        self.hexgrid_busy_overlay.hide_busy()
        self._cleanup_hexgrid_preview_worker()
        completed_signature = self._hexgrid_request_signatures.pop(int(build_token), None)
        if int(build_token) != int(self._hexgrid_request_token):
            if self._hexgrid_pending_refresh:
                self._hexgrid_pending_refresh = False
                self._schedule_hexgrid_preview_refresh(immediate=True)
            return
        if isinstance(result, HexgridPreviewComputation):
            self._hexgrid_preview_cached_result = result
        self._render_hexgrid_preview_result(result)
        current_state = self.current_state()
        self._hexgrid_completed_signature = completed_signature
        self._hexgrid_completed_commit_signature = (
            tuple(completed_signature[:-4])
            if isinstance(completed_signature, tuple) and len(completed_signature) >= 4
            else None
        )
        self._hexgrid_completed_overlay_signature = self._hexgrid_overlay_signature(current_state)
        self._hexgrid_outdated = False
        # Update the actual cell spacing label from the prepared grid
        if isinstance(result, HexgridPreviewComputation) and result.prepared_grid is not None:
            actual_km = result.prepared_grid.get("actual_point_spacing_km")
            if actual_km is not None:
                self.grid_actual_label.setText(
                    f"Actual achieved spacing: {float(actual_km):.3f} km "
                    f"({int(result.prepared_grid.get('active_cell_count', 0))} active cells)"
                )
            else:
                self.grid_actual_label.setText("Actual achieved spacing: --")
        if elapsed_s is None:
            self.hexgrid_preview_status_label.setText("Preview ready.")
        else:
            self.hexgrid_preview_status_label.setText(f"Preview ready in {elapsed_s:.2f} s.")
        self._update_simulation_page_indicators(current_state)
        self._update_guidance_panel(self.current_state())
        if self._hexgrid_pending_refresh:
            self._hexgrid_pending_refresh = False
            self._schedule_hexgrid_preview_refresh(immediate=True)

    @QtCore.Slot(str, int)
    def _on_hexgrid_preview_failed(self, message: str, build_token: int) -> None:
        self.hexgrid_busy_overlay.hide_busy()
        self._cleanup_hexgrid_preview_worker()
        self._hexgrid_request_signatures.pop(int(build_token), None)
        if int(build_token) == int(self._hexgrid_request_token):
            self._clear_hexgrid_preview_canvas()
            self.hexgrid_preview_status_label.setText(f"Preview failed: {message}")
            self.hexgrid_notice_banner.show_message(
                f"Hexgrid preview failed: {message}",
                kind="warning",
            )
            self._update_simulation_page_indicators(self.current_state())
            self._update_guidance_panel(self.current_state())
        if self._hexgrid_pending_refresh:
            self._hexgrid_pending_refresh = False
            self._schedule_hexgrid_preview_refresh(immediate=True)

    def _compute_hexgrid_preview_result(
        self,
        state: ScepterProjectState,
        *,
        effective_cell_km: float,
    ) -> HexgridPreviewComputation:
        s0 = state.active_system()
        hx = s0.hexgrid
        constellation = build_constellation_from_state(state)
        prepared_grid = earthgrid.prepare_active_grid(
            point_spacing=effective_cell_km * u.km,
            altitudes=constellation["altitudes_q"],
            min_elevations=constellation["min_elevations_q"],
            inclinations=constellation["inclinations_q"],
            station_lat=float(state.ras_station.latitude_deg) * u.deg,
            station_lon=float(state.ras_station.longitude_deg) * u.deg,
            station_height=float(state.ras_station.elevation_m) * u.m,
            latitude_policy="any",
            geography_mask_mode=hx.geography_mask_mode,
            shoreline_buffer_km=hx.shoreline_buffer_km,
            coastline_backend=hx.coastline_backend,
            ras_exclusion_mode=hx.ras_exclusion_mode,
            ras_exclusion_layers=hx.ras_exclusion_layers,
            ras_exclusion_radius_km=hx.ras_exclusion_radius_km,
            ras_pointing_mode=hx.ras_pointing_mode,
        )
        preview_notes: list[str] = []
        boresight_ids = np.empty(0, dtype=np.int32)
        if hx.boresight_avoidance_enabled:
            try:
                boresight_ids = earthgrid.resolve_theta2_active_cell_ids(
                    prepared_grid,
                    scope_mode=hx.boresight_theta2_scope_mode,
                    explicit_ids=_parse_theta2_cell_ids_text(
                        hx.boresight_theta2_cell_ids or ""
                    ),
                    layers=hx.boresight_theta2_layers,
                    radius_km=hx.boresight_theta2_radius_km,
                )
            except Exception as exc:
                preview_notes.append(f"Boresight scope warning: {exc}")
        reuse_plan = None
        try:
            reuse_plan = self._resolve_frequency_reuse_plan_for_grid(state, prepared_grid)
        except Exception as exc:
            preview_notes.append(f"Reuse plan warning: {exc}")
        return HexgridPreviewComputation(
            prepared_grid=prepared_grid,
            boresight_ids=np.asarray(boresight_ids, dtype=np.int32),
            reuse_plan=reuse_plan,
            preview_notes=preview_notes,
            effective_cell_km=float(effective_cell_km),
        )

    @QtCore.Slot()
    def _refresh_hexgrid_preview(self) -> None:
        self._commit_visible_editors()
        state = self.current_state()
        effective_cell_km = self._effective_hexgrid_cell_size_km(state)
        request_signature = self._hexgrid_preview_signature(state)
        if len(state.active_system().belts) < 1 or not _has_complete_ras_station_config(state.ras_station):
            self._mark_hexgrid_preview_stale(state)
            return
        if not self._contour_is_current(state):
            self._mark_hexgrid_preview_stale(state)
            return
        if effective_cell_km is None:
            self._mark_hexgrid_preview_stale(state)
            return
        if self._render_hexgrid_preview_from_cache(state):
            return
        self._hexgrid_request_token += 1
        self._hexgrid_request_signatures[int(self._hexgrid_request_token)] = request_signature
        if self._hexgrid_thread is not None:
            self._hexgrid_pending_refresh = True
            self.hexgrid_preview_status_label.setText("Preview refresh queued...")
            return

        self._hexgrid_pending_refresh = False
        self._hexgrid_preview_started_s = perf_counter()
        self.hexgrid_preview_status_label.setText("Preparing grid geometry...")
        self.hexgrid_busy_overlay.show_busy(
            "Updating hexgrid preview",
            "Preparing grid geometry...",
        )
        thread = QtCore.QThread()
        worker = HexgridPreviewWorker(
            state,
            effective_cell_km=float(effective_cell_km),
            build_token=int(self._hexgrid_request_token),
        )
        worker.moveToThread(thread)
        thread.started.connect(worker._invoke_run, QtCore.Qt.QueuedConnection)
        worker.finished.connect(self._on_hexgrid_preview_ready)
        worker.failed.connect(self._on_hexgrid_preview_failed)
        worker.finished.connect(thread.quit)
        worker.failed.connect(thread.quit)
        worker.finished.connect(worker.deleteLater)
        worker.failed.connect(worker.deleteLater)
        _retain_managed_worker_job(thread, worker, label="hexgrid_preview")
        thread.finished.connect(thread.deleteLater)
        self._hexgrid_thread = thread
        self._hexgrid_worker = worker
        thread.start()

    def _render_hexgrid_preview_result(
        self,
        result: HexgridPreviewComputation,
        *,
        cached_render: bool = False,
    ) -> None:
        map_style = str(self.hexgrid_map_style_combo.currentData() or "clean")
        fig, info = visualise.plot_cell_status_map(
            result.prepared_grid["pre_ras_cell_longitudes"],
            result.prepared_grid["pre_ras_cell_latitudes"],
            active_cell_longitudes=result.prepared_grid["active_grid_longitudes"],
            active_cell_latitudes=result.prepared_grid["active_grid_latitudes"],
            switched_off_mask=result.prepared_grid["ras_exclusion_mask_pre_ras"],
            boresight_affected_cell_ids=result.boresight_ids,
            # Keep the geographic preview on the same ACTIVE-axis slot ids that
            # the run request later passes into spectrum normalization.
            active_reuse_slot_ids=(
                None
                if result.reuse_plan is None
                else result.reuse_plan.get("active_slot_ids")
            ),
            reuse_factor=(
                1
                if result.reuse_plan is None
                else int(result.reuse_plan.get("reuse_factor", 1))
            ),
            anchor_active_index=(
                None
                if result.reuse_plan is None
                else result.reuse_plan.get("anchor_active_index")
            ),
            ras_longitude=result.prepared_grid["station_lon"],
            ras_latitude=result.prepared_grid["station_lat"],
            backend="auto" if map_style in {"terrain", "relief"} else "matplotlib",
            map_style=map_style,
            point_spacing_km=result.prepared_grid.get(
                "actual_point_spacing_km",
                result.prepared_grid["point_spacing_km"],
            ),
            hex_lattice=result.reuse_plan,
            appearance_variant=self._resolved_appearance_variant(),
            return_info=True,
        )
        for axis in fig.axes:
            axis.set_aspect("equal", adjustable="box")

        actual_spacing = result.prepared_grid.get("actual_point_spacing_km")
        summary_bits = [
            f"Cell size = {result.effective_cell_km:.3f} km"
            + (f" (actual {actual_spacing:.3f} km)" if actual_spacing is not None else ""),
            f"Active = {result.prepared_grid['active_cell_count']}",
            f"RAS excluded = {result.prepared_grid['ras_excluded_cell_count']}",
            f"Boresight affected = {int(info['boresight_affected_active_count'])}",
            f"Reuse = F{1 if result.reuse_plan is None else int(result.reuse_plan.get('reuse_factor', 1))}",
            f"Style = {info.get('map_style_used', 'clean')}",
            f"Backend = {info.get('backend_used', 'matplotlib')}",
        ]
        if result.reuse_plan is not None:
            active_conflict_pairs = int(
                result.reuse_plan.get(
                    "active_adjacent_same_slot_pair_count",
                    result.reuse_plan.get("adjacent_same_slot_pair_count", 0),
                )
            )
            summary_bits.append(f"Adjacent same-slot pairs (active grid) = {active_conflict_pairs}")
        if result.preview_notes:
            summary_bits.extend(result.preview_notes)
        if cached_render:
            summary_bits.append("Render = cached geometry")

        fig.suptitle("Hexgrid Preview", fontsize=13, y=0.975)
        self._style_matplotlib_figure(fig)

        if self._hexgrid_preview_window is None:
            window = FigureWindow(
                figure=fig,
                title="Hexgrid Preview",
                summary_text=" | ".join(summary_bits),
                parent=self,
            )
            window.destroyed.connect(self._on_hexgrid_preview_window_destroyed)
            # Enable interactive θ₂ cell picking only when boresight is
            # active and scope mode is cell_ids.
            _bore_active = bool(self.hexgrid_boresight_enabled_checkbox.isChecked())
            _scope_mode = str(self.hexgrid_boresight_scope_combo.currentData() or "")
            if (
                result.prepared_grid is not None
                and _bore_active
                and _scope_mode == "cell_ids"
            ):
                window.enable_cell_picking(
                    longitudes=result.prepared_grid["active_grid_longitudes"],
                    latitudes=result.prepared_grid["active_grid_latitudes"],
                )
                window.cell_picked.connect(self._on_hexgrid_cell_picked)
            window.show()
            window.raise_()
            window.activateWindow()
            self._hexgrid_preview_window = window
            return

        self._hexgrid_preview_window.update_figure(
            figure=fig,
            title="Hexgrid Preview",
            summary_text=" | ".join(summary_bits),
        )

    def _preview_ready_hexgrid_result(self) -> HexgridPreviewComputation | None:
        state = self.current_state()
        if len(state.active_system().belts) < 1 or not _has_complete_ras_station_config(state.ras_station):
            QtWidgets.QMessageBox.warning(
                self,
                "Preview unavailable",
                "A valid RAS station and at least one belt are required first.",
            )
            return None
        effective_cell_km = self._effective_hexgrid_cell_size_km(state)
        if effective_cell_km is None:
            QtWidgets.QMessageBox.warning(
                self,
                "Preview unavailable",
                "Run the contour analyser or set a valid cell-size override first.",
            )
            return None
        if (
            self._can_refresh_hexgrid_preview_from_cache(state)
            and self._hexgrid_preview_cached_result is not None
        ):
            return self._hexgrid_preview_cached_result
        return self._compute_hexgrid_preview_result(
            state,
            effective_cell_km=float(effective_cell_km),
        )

    def _show_or_update_figure_window(
        self,
        *,
        attribute_name: str,
        figure: Figure,
        title: str,
        summary_text: str | None = None,
        activate_existing: bool = True,
    ) -> None:
        self._style_matplotlib_figure(figure)
        window = getattr(self, attribute_name, None)
        if window is None:
            window = FigureWindow(
                figure=figure,
                title=title,
                summary_text=summary_text,
                parent=self,
            )
            window.destroyed.connect(
                lambda *_args, name=attribute_name: setattr(self, name, None)
            )
            window.show()
            window.raise_()
            window.activateWindow()
            setattr(self, attribute_name, window)
            return
        window.update_figure(figure=figure, title=title, summary_text=summary_text)
        if activate_existing:
            window.show()
            window.raise_()
            window.activateWindow()

    @QtCore.Slot()
    def _show_reuse_scheme_viewer(self) -> None:
        spectrum_cfg = self._current_explicit_spectrum_config()
        if spectrum_cfg.reuse_factor is None:
            QtWidgets.QMessageBox.warning(
                self,
                "Reuse preview unavailable",
                "Choose a reuse scheme first.",
            )
            return
        figure, _info = visualise.plot_frequency_reuse_scheme(
            reuse_factor=int(spectrum_cfg.reuse_factor),
            anchor_slot=int(spectrum_cfg.ras_anchor_reuse_slot or 0),
            return_info=True,
        )
        self._show_or_update_figure_window(
            attribute_name="_reuse_scheme_window",
            figure=figure,
            title="Frequency Reuse Scheme",
        )

    @QtCore.Slot()
    def _show_spectrum_preview(self) -> None:
        try:
            spectrum_plan = self._current_explicit_spectrum_plan()
        except Exception as exc:
            _show_exception_warning(self, "Edit Spectrum unavailable", "The spectrum editor can't open with the current settings.", exc)
            return
        try:
            power_input = _normalize_service_config_power_input(self._current_service_config())
        except Exception:
            power_input = None
        window = self._spectrum_preview_window
        if not isinstance(window, SpectrumPreviewDialog):
            if window is not None:
                try:
                    window.close()
                except Exception:
                    pass
            window = SpectrumPreviewDialog(
                spectrum_plan=spectrum_plan,
                power_input=power_input,
                apply_selection_callback=self._apply_spectrum_enabled_channel_selection,
                parent=self,
                dialog_title="Edit Spectrum",
            )
            window.destroyed.connect(
                lambda *_args: setattr(self, "_spectrum_preview_window", None)
            )
            self._spectrum_preview_window = window
            window.show()
            window.raise_()
            window.activateWindow()
            return
        window.update_plan(
            spectrum_plan,
            power_input=power_input,
        )
        window.show()
        window.raise_()
        window.activateWindow()

    def _apply_spectrum_enabled_channel_selection(
        self,
        enabled_channel_indices: set[int],
    ) -> tuple[Mapping[str, Any], Mapping[str, Any] | None]:
        state = self.current_state()
        s0 = state.active_system()
        spectrum_plan = _normalize_spectrum_config(
            s0.service,
            s0.spectrum,
            state.ras_station,
        )
        all_channel_indices = _all_channel_indices_from_plan(spectrum_plan)
        self._spectrum_editor_sync_in_progress = True
        try:
            self._spectrum_disabled_channel_indices = _sanitize_disabled_channel_indices(
                [
                    int(channel_index)
                    for channel_index in sorted(all_channel_indices - set(enabled_channel_indices))
                ],
                full_channel_count=len(all_channel_indices),
            )
            self._sync_spectrum_controls()
            self._on_state_changed()
            updated_state = self.current_state()
            updated_s0 = updated_state.active_system()
            updated_plan = _normalize_spectrum_config(
                updated_s0.service,
                updated_s0.spectrum,
                updated_state.ras_station,
            )
        finally:
            self._spectrum_editor_sync_in_progress = False
        try:
            updated_power_input = _normalize_service_config_power_input(updated_s0.service)
        except Exception:
            updated_power_input = None
        return updated_plan, updated_power_input

    def _refresh_open_spectrum_editor_window(
        self,
        *,
        spectrum_plan: Mapping[str, Any] | None = None,
    ) -> None:
        if self._spectrum_editor_sync_in_progress:
            return
        window = getattr(self, "_spectrum_preview_window", None)
        if not isinstance(window, SpectrumPreviewDialog):
            return
        if spectrum_plan is None:
            try:
                spectrum_plan = self._current_explicit_spectrum_plan()
            except Exception:
                try:
                    window.close()
                except Exception:
                    pass
                return
            try:
                power_input = _normalize_service_config_power_input(self._current_service_config())
            except Exception:
                power_input = None
        else:
            try:
                power_input = _normalize_service_config_power_input(self.current_state().active_system().service)
            except Exception:
                power_input = None
        window.update_plan(spectrum_plan, power_input=power_input)

    @QtCore.Slot()
    def _open_ras_receiver_response_tool(self) -> None:
        ras_cfg = self._current_ras_station_config()
        receiver_ready, message = _validate_ras_receiver_band(ras_cfg)
        if not receiver_ready or ras_cfg is None:
            QtWidgets.QMessageBox.warning(
                self,
                "Receiver response unavailable",
                message or "Set the RAS receiver band first.",
            )
            return
        if scenario._resolve_direct_epfd_receiver_response_mode(
            ras_cfg.receiver_response_mode
        ) == "custom":
            self._edit_ras_receiver_mask_points()
            return
        self._show_ras_receiver_response_preview()

    @QtCore.Slot()
    def _show_ras_receiver_response_preview(self) -> None:
        ras_cfg = self._current_ras_station_config()
        receiver_ready, message = _validate_ras_receiver_config(ras_cfg)
        if not receiver_ready or ras_cfg is None:
            QtWidgets.QMessageBox.warning(
                self,
                "Receiver preview unavailable",
                message or "Set the RAS receiver band first.",
            )
            return
        receiver_start_mhz = float(ras_cfg.receiver_band_start_mhz)
        receiver_stop_mhz = float(ras_cfg.receiver_band_stop_mhz)
        receiver_bandwidth_mhz = receiver_stop_mhz - receiver_start_mhz
        response_mode = scenario._resolve_direct_epfd_receiver_response_mode(
            ras_cfg.receiver_response_mode
        )
        response_points = scenario._resolve_direct_epfd_receiver_response_points_mhz(
            response_mode=response_mode,
            receiver_bandwidth_mhz=receiver_bandwidth_mhz,
            custom_mask_points=ras_cfg.receiver_custom_mask_points,
        )
        x_extent_mhz = max(
            0.75 * receiver_bandwidth_mhz,
            float(np.max(np.abs(np.asarray(response_points, dtype=np.float64)[:, 0]))) * 1.08,
        )
        axis_offsets_mhz = np.linspace(-x_extent_mhz, x_extent_mhz, 801, dtype=np.float64)
        response_db = -scenario._evaluate_direct_epfd_receiver_response_attenuation_db(
            axis_offsets_mhz,
            response_mode=response_mode,
            receiver_bandwidth_mhz=receiver_bandwidth_mhz,
            response_points_mhz=response_points,
        )
        response_db[~np.isfinite(response_db)] = -140.0
        figure = Figure(figsize=(8.4, 5.4), constrained_layout=True)
        axis = figure.add_subplot(111)
        axis.axvspan(
            -0.5 * receiver_bandwidth_mhz,
            0.5 * receiver_bandwidth_mhz,
            color="#2563eb",
            alpha=0.08,
            linewidth=0.0,
        )
        axis.plot(
            axis_offsets_mhz,
            response_db,
            color="#2563eb",
            linewidth=1.8,
        )
        axis.set_title("RAS receiver response")
        axis.set_xlabel("Signed offset from receiver-band centre [MHz]")
        axis.set_ylabel("Relative response [dB]")
        axis.grid(True, alpha=0.18, linestyle=":")
        axis.set_ylim(min(-140.0, float(np.min(response_db)) * 1.05), 3.0)
        self._show_or_update_figure_window(
            attribute_name="_ras_receiver_preview_window",
            figure=figure,
            title="RAS Receiver Response",
            summary_text=(
                f"RAS receiver band: {receiver_start_mhz:.3f} to {receiver_stop_mhz:.3f} MHz. "
                "This preview is receiver-side only. Use Edit Spectrum on Spectrum & Reuse for transmit-channel selection and Tx-side overlap into the RAS receiver band."
            ),
            activate_existing=True,
        )

    @QtCore.Slot()
    def _edit_custom_mask_points(self) -> None:
        service_cfg = self._current_service_config()
        spectrum_cfg = self._current_spectrum_config()
        ras_cfg = self._current_ras_station_config()
        # In UEMR mode the "channel" concept is bypassed entirely: the
        # integration window is the service band itself (cutoff_basis =
        # ``service_bandwidth`` at 50%, see ``_apply_uemr_mode_gating``).
        # The mask editor's in-band anchors must therefore sit at the
        # service-band edges, not at some leftover channel_bandwidth
        # that the user never set.
        try:
            uemr_active = _system_is_uemr(self.current_state().active_system())
        except Exception:
            uemr_active = False
        if uemr_active:
            svc_start = spectrum_cfg.service_band_start_mhz
            svc_stop = spectrum_cfg.service_band_stop_mhz
            if (
                svc_start is not None
                and svc_stop is not None
                and float(svc_stop) > float(svc_start)
            ):
                effective_bandwidth_mhz = float(svc_stop) - float(svc_start)
            else:
                effective_bandwidth_mhz = float(_DEFAULT_SERVICE_BANDWIDTH_MHZ)
        else:
            effective_bandwidth_mhz = float(
                service_cfg.bandwidth_mhz or _DEFAULT_SERVICE_BANDWIDTH_MHZ
            )

        current_points = (
            self._spectrum_custom_mask_points
            if self._spectrum_custom_mask_points is not None
            else scenario._resolve_direct_epfd_mask_points_mhz(
                preset=_DEFAULT_SPECTRUM_MASK_PRESET,
                channel_bandwidth_mhz=effective_bandwidth_mhz,
                custom_mask_points=None,
            ).tolist()
        )

        def _preview_plan_factory(
            mask_points: list[list[float]],
        ) -> Mapping[str, Any] | None:
            spectrum_payload = spectrum_cfg.to_json_dict()
            spectrum_payload["unwanted_emission_mask_preset"] = "custom"
            spectrum_payload["custom_mask_points"] = mask_points
            spectrum_preview_cfg = SpectrumConfig.from_json_dict(spectrum_payload)
            return _normalize_spectrum_config(service_cfg, spectrum_preview_cfg, ras_cfg)

        dialog = SpectrumMaskEditorDialog(
            initial_points=current_points,
            channel_bandwidth_mhz=effective_bandwidth_mhz,
            preview_plan_factory=_preview_plan_factory,
            parent=self,
            mask_kind="tx",
            dialog_title="Custom Transmit Unwanted-Emission Mask",
        )
        if dialog.exec() != int(QtWidgets.QDialog.Accepted):
            return
        self._spectrum_custom_mask_points = dialog.selected_points()
        self._set_combo_to_data(self.spectrum_mask_preset_combo, "custom")
        self._sync_spectrum_controls()
        self._on_state_changed()

    @QtCore.Slot()
    def _edit_ras_receiver_mask_points(self) -> None:
        ras_cfg = self._current_ras_station_config()
        service_cfg = self._current_service_config()
        spectrum_cfg = self._current_spectrum_config()
        receiver_bandwidth_mhz = float(
            (
                ras_cfg.receiver_band_stop_mhz or _DEFAULT_SPECTRUM_RAS_BAND_STOP_MHZ
            )
            - (
                ras_cfg.receiver_band_start_mhz or _DEFAULT_SPECTRUM_RAS_BAND_START_MHZ
            )
        )
        current_points = (
            self._ras_receiver_custom_mask_points
            if self._ras_receiver_custom_mask_points is not None
            else scenario._resolve_direct_epfd_receiver_response_points_mhz(
                response_mode="custom",
                receiver_bandwidth_mhz=receiver_bandwidth_mhz,
                custom_mask_points=None,
            ).tolist()
        )

        def _preview_plan_factory(
            response_points: list[list[float]],
        ) -> Mapping[str, Any] | None:
            ras_payload = ras_cfg.to_json_dict()
            ras_payload["receiver_response_mode"] = "custom"
            ras_payload["receiver_custom_mask_points"] = response_points
            ras_preview_cfg = RasStationConfig.from_json_dict(ras_payload)
            return _normalize_spectrum_config(service_cfg, spectrum_cfg, ras_preview_cfg)

        dialog = SpectrumMaskEditorDialog(
            initial_points=current_points,
            channel_bandwidth_mhz=receiver_bandwidth_mhz,
            preview_plan_factory=_preview_plan_factory,
            parent=self,
            mask_kind="rx",
            dialog_title="Custom RAS Receiver Response",
        )
        if dialog.exec() != int(QtWidgets.QDialog.Accepted):
            return
        self._ras_receiver_custom_mask_points = dialog.selected_points()
        self._set_combo_to_data(self.ras_receiver_response_mode_combo, "custom")
        self._sync_spectrum_controls()
        self._on_state_changed()

    def _plot_antenna_pattern(self, *, main_lobe_only: bool) -> None:
        antennas_cfg = self.current_state().active_system().satellite_antennas
        if not _has_valid_satellite_antenna_config(antennas_cfg):
            self.antenna_pattern_status.setText(
                "Pattern plots require a valid satellite-system antenna."
            )
            return

        antenna_func, wavelength, pattern_kwargs = _satellite_antenna_pattern_spec(antennas_cfg)
        max_angle_deg = 180.0
        if main_lobe_only:
            hpbw_deg = 2.0 * _resolve_contour_half_angle_deg(antennas_cfg, "db3")
            max_angle_deg = min(max(5.0, 3.0 * hpbw_deg), 90.0)

        offset_angles = np.linspace(0.0, max_angle_deg, 721, dtype=np.float64) * u.deg
        gains_result = antenna_func(offset_angles, wavelength=wavelength, **pattern_kwargs)
        gains = gains_result[0] if isinstance(gains_result, (tuple, list)) else gains_result
        gains_dbi = (
            gains.to_value(cnv.dBi)
            if isinstance(gains, u.Quantity)
            else np.asarray(gains, dtype=float)
        )

        figure = Figure(figsize=(7.5, 5.2), constrained_layout=True)
        axis = figure.add_subplot(111)
        axis.plot(offset_angles.to_value(u.deg), gains_dbi, color="#0f766e", linewidth=1.8)
        axis.set_xlabel("Off-axis angle [deg]")
        axis.set_ylabel("Gain [dBi]")
        axis.set_title(
            "Satellite-system antenna pattern"
            + (" — main lobe" if main_lobe_only else " — full")
        )
        axis.grid(True, alpha=0.25)
        self._style_matplotlib_figure(figure)

        window = FigureWindow(
            figure=figure,
            title="Antenna Pattern — Main Lobe" if main_lobe_only else "Antenna Pattern — Full",
            summary_text=(
                f"Satellite antenna pattern preview using wavelength {float(wavelength.to_value(u.cm)):.3f} cm. "
                f"Angular range 0 to {float(max_angle_deg):.3f} deg."
            ),
            parent=self,
        )
        window.show()
        window.raise_()
        window.activateWindow()
        self._antenna_pattern_windows.append(window)

        self.antenna_pattern_status.setText(
            "Main-lobe pattern opened in a separate window."
            if main_lobe_only
            else "Full antenna pattern opened in a separate window."
        )

    @QtCore.Slot()
    def _plot_full_antenna_pattern(self) -> None:
        self._plot_antenna_pattern(main_lobe_only=False)

    @QtCore.Slot()
    def _plot_main_lobe_antenna_pattern(self) -> None:
        self._plot_antenna_pattern(main_lobe_only=True)

    @QtCore.Slot()
    def _plot_ras_antenna_pattern(self) -> None:
        state = self.current_state()
        ras_cfg = state.ras_antenna
        if not _has_valid_ras_antenna_config(ras_cfg):
            self.ras_pattern_status.setText(
                "RAS pattern plots require a valid RAS antenna diameter and operational elevation range."
            )
            return
        # The RAS pattern depends only on the RAS station's own frequency.
        wavelength_cm = 0.0
        if ras_cfg.frequency_mhz is not None and float(ras_cfg.frequency_mhz) > 0.0:
            wavelength_cm = _pattern_wavelength_cm_from_frequency_mhz(float(ras_cfg.frequency_mhz))
        if wavelength_cm <= 0.0:
            self.ras_pattern_status.setText(
                "RAS pattern plots require a positive frequency or manual pattern wavelength."
            )
            return
        diameter_m = float(ras_cfg.antenna_diameter_m)
        offset_angles = np.linspace(0.0, 180.0, 721, dtype=np.float64) * u.deg
        gains = pycraf_antenna.ras_pattern(
            offset_angles,
            diameter_m * u.m,
            (float(wavelength_cm) / 100.0) * u.m,
        )
        gains_dbi = np.asarray(gains.to_value(cnv.dB), dtype=float)

        figure = Figure(figsize=(7.5, 5.2), constrained_layout=True)
        axis = figure.add_subplot(111)
        axis.plot(offset_angles.to_value(u.deg), gains_dbi, color="#1d4ed8", linewidth=1.8)
        axis.set_xlabel("Off-axis angle [deg]")
        axis.set_ylabel("Gain [dB]")
        axis.set_title("RAS antenna pattern")
        axis.grid(True, alpha=0.25)
        self._style_matplotlib_figure(figure)

        window = FigureWindow(
            figure=figure,
            title="RAS Antenna Pattern",
            summary_text=(
                f"RAS antenna pattern preview using wavelength {float(wavelength_cm):.3f} cm "
                f"and dish diameter {diameter_m:.3f} m."
            ),
            parent=self,
        )
        window.show()
        window.raise_()
        window.activateWindow()
        self._antenna_pattern_windows.append(window)
        self.ras_pattern_status.setText("RAS antenna pattern opened in a separate window.")

    @QtCore.Slot()
    def _on_rf_frequency_changed(self) -> None:
        """Handle satellite-side frequency changes (per-system)."""
        self._sync_rf_panel()
        self._on_state_changed()

    def _on_ras_frequency_changed(self) -> None:
        """Handle RAS-side frequency changes (shared)."""
        self._update_ras_grx_from_diameter()
        self._on_state_changed()

    def _ras_wavelength_m(self) -> float | None:
        """Return the RAS-station wavelength in metres, or None if unavailable."""
        freq_mhz = self.ras_frequency_spin.value_or_none()
        if freq_mhz is None or float(freq_mhz) <= 0.0:
            return None
        return 299.792458 / float(freq_mhz)  # c [m·MHz] / f [MHz] → λ [m]

    def _update_ras_grx_from_diameter(self) -> None:
        """Compute G_rx,max from antenna diameter and update the spin."""
        if self._ras_grx_cross_updating:
            return
        diam = self.antenna_spin.value_or_none()
        wlen = self._ras_wavelength_m()
        if diam is None or wlen is None or float(diam) <= 0 or float(wlen) <= 0:
            return
        import math
        d_over_lam = float(diam) / float(wlen)
        grx_dbi = 20.0 * math.log10(d_over_lam) + 20.0 * math.log10(math.pi)
        self._ras_grx_cross_updating = True
        try:
            self.ras_grx_max_spin.set_value(round(grx_dbi, 2))
        finally:
            self._ras_grx_cross_updating = False

    def _update_ras_diameter_from_grx(self) -> None:
        """Compute antenna diameter from G_rx,max and update the spin."""
        if self._ras_grx_cross_updating:
            return
        grx_dbi = self.ras_grx_max_spin.value_or_none()
        wlen = self._ras_wavelength_m()
        if grx_dbi is None or wlen is None or float(wlen) <= 0:
            return
        import math
        # G_max = (πD/λ)²  →  D = (λ/π) × 10^(G_dBi/20)
        diam = (float(wlen) / math.pi) * (10.0 ** (float(grx_dbi) / 20.0))
        self._ras_grx_cross_updating = True
        try:
            self.antenna_spin.set_value(round(diam, 6))
        finally:
            self._ras_grx_cross_updating = False

    def _rec12_pattern_wavelength_m(self) -> float | None:
        """Return the pattern wavelength in metres for Rec 1.2 Gm ↔ D cross-update."""
        wl_cm = self.pattern_wavelength_spin.value_or_none()
        if wl_cm is not None and float(wl_cm) > 0:
            return float(wl_cm) / 100.0
        freq_mhz = self.frequency_spin.value_or_none()
        if freq_mhz is not None and float(freq_mhz) > 0:
            return 299.792458 / float(freq_mhz)
        return None

    def _update_rec12_gm_from_diameter(self) -> None:
        """Compute Gm from diameter + efficiency and update the spin."""
        if self._rec12_gm_cross_updating:
            return
        diam = self.rec12_diameter_spin.value_or_none()
        eff_pct = self.rec12_efficiency_spin.value_or_none()
        wlen = self._rec12_pattern_wavelength_m()
        if diam is None or wlen is None or float(diam) <= 0 or float(wlen) <= 0:
            return
        import math
        eta = float(eff_pct or 100.0) / 100.0
        if eta <= 0:
            return
        gm = 10.0 * math.log10(eta * (math.pi * float(diam) / float(wlen)) ** 2)
        self._rec12_gm_cross_updating = True
        try:
            self.rec12_gm_spin.set_value(round(gm, 2))
        finally:
            self._rec12_gm_cross_updating = False

    def _update_rec12_diameter_from_gm(self) -> None:
        """Compute diameter from Gm + efficiency and update the spin."""
        if self._rec12_gm_cross_updating:
            return
        gm = self.rec12_gm_spin.value_or_none()
        eff_pct = self.rec12_efficiency_spin.value_or_none()
        wlen = self._rec12_pattern_wavelength_m()
        if gm is None or wlen is None or float(wlen) <= 0:
            return
        import math
        eta = float(eff_pct or 100.0) / 100.0
        if eta <= 0:
            return
        # Gm = 10*log10(η*(πD/λ)²) → D = (λ/π) * sqrt(10^(Gm/10) / η)
        diam = (float(wlen) / math.pi) * math.sqrt(10.0 ** (float(gm) / 10.0) / eta)
        self._rec12_gm_cross_updating = True
        try:
            self.rec12_diameter_spin.set_value(round(diam, 4))
        finally:
            self._rec12_gm_cross_updating = False

    @QtCore.Slot()
    def _on_rf_pattern_source_changed(self) -> None:
        self._sync_rf_panel()
        self._on_state_changed()

    @QtCore.Slot()
    def _on_rf_model_changed(self, *args: object) -> None:
        del args
        selected = str(self.antenna_model_combo.currentData() or _ANTENNA_MODEL_REC12)
        # Auto-populate model-specific defaults for the Rec 1.2 / S.672 page
        if selected in {_ANTENNA_MODEL_S672, _ANTENNA_MODEL_REC12}:
            cfg = _default_s672_config() if selected == _ANTENNA_MODEL_S672 else _default_rec12_config()
            self.rec12_gm_spin.set_value(cfg.gm_dbi)
            self.rec12_ln_spin.set_value(cfg.ln_db)
            self.rec12_z_spin.set_value(cfg.z)
            self.rec12_diameter_spin.set_value(cfg.diameter_m)
            self.rec12_efficiency_spin.set_value(cfg.efficiency_pct)
        elif selected == _ANTENNA_MODEL_REC14:
            cfg = _default_rec14_config()
            self.rec14_gm_spin.set_value(cfg.gm_dbi)
            self.rec14_lt_spin.set_value(cfg.lt_m)
            self.rec14_lr_spin.set_value(cfg.lr_m)
            self.rec14_l_spin.set_value(cfg.l)
            self.rec14_slr_spin.set_value(cfg.slr_db)
            self.rec14_far_start_spin.set_value(cfg.far_sidelobe_start_deg)
            self.rec14_far_level_spin.set_value(cfg.far_sidelobe_level_dbi)
        elif selected == _ANTENNA_MODEL_M2101:
            cfg = _default_m2101_config()
            self.m2101_g_emax_spin.set_value(cfg.g_emax_dbi)
            self.m2101_a_m_spin.set_value(cfg.a_m_db)
            self.m2101_sla_nu_spin.set_value(cfg.sla_nu_db)
            self.m2101_phi_3db_spin.set_value(cfg.phi_3db_deg)
            self.m2101_theta_3db_spin.set_value(cfg.theta_3db_deg)
            self.m2101_d_h_spin.set_value(cfg.d_h)
            self.m2101_d_v_spin.set_value(cfg.d_v)
            self.m2101_n_h_spin.set_value(cfg.n_h)
            self.m2101_n_v_spin.set_value(cfg.n_v)
        self._sync_rf_panel()
        self._on_state_changed()

    @QtCore.Slot()
    def _on_cell_size_override_toggled(self, checked: bool) -> None:
        self.cell_size_override_spin.setEnabled(bool(checked))
        self._on_state_changed()

    @QtCore.Slot()
    def _restore_selected_model_defaults(self) -> None:
        blocker_frequency = QtCore.QSignalBlocker(self.frequency_spin)
        blocker_ras_frequency = QtCore.QSignalBlocker(self.ras_frequency_spin)
        blocker_derive = QtCore.QSignalBlocker(self.derive_pattern_wavelength_checkbox)
        blocker_wavelength = QtCore.QSignalBlocker(self.pattern_wavelength_spin)

        self._set_shared_frequency_widgets(2690.0)
        self.derive_pattern_wavelength_checkbox.setChecked(False)
        self.pattern_wavelength_spin.set_value(15.0)

        del blocker_wavelength
        del blocker_derive
        del blocker_ras_frequency
        del blocker_frequency

        model = str(self.antenna_model_combo.currentData() or _ANTENNA_MODEL_REC12)
        if model in {_ANTENNA_MODEL_REC12, _ANTENNA_MODEL_S672}:
            # S.672 uses the same parameter set as Rec 1.2.
            default_cfg = _default_rec12_config()
            self.rec12_gm_spin.set_value(default_cfg.gm_dbi)
            self.rec12_ln_spin.set_value(default_cfg.ln_db)
            self.rec12_z_spin.set_value(default_cfg.z)
        elif model == _ANTENNA_MODEL_REC14:
            default_cfg = _default_rec14_config()
            self.rec14_gm_spin.set_value(default_cfg.gm_dbi)
            self.rec14_lt_spin.set_value(default_cfg.lt_m)
            self.rec14_lr_spin.set_value(default_cfg.lr_m)
            self.rec14_l_spin.set_value(default_cfg.l)
            self.rec14_slr_spin.set_value(default_cfg.slr_db)
            self.rec14_far_start_spin.set_value(default_cfg.far_sidelobe_start_deg)
            self.rec14_far_level_spin.set_value(default_cfg.far_sidelobe_level_dbi)
        elif model == _ANTENNA_MODEL_M2101:
            m_cfg = _default_m2101_config()
            self.m2101_g_emax_spin.set_value(m_cfg.g_emax_dbi)
            self.m2101_a_m_spin.set_value(m_cfg.a_m_db)
            self.m2101_sla_nu_spin.set_value(m_cfg.sla_nu_db)
            self.m2101_phi_3db_spin.set_value(m_cfg.phi_3db_deg)
            self.m2101_theta_3db_spin.set_value(m_cfg.theta_3db_deg)
            self.m2101_d_h_spin.set_value(m_cfg.d_h)
            self.m2101_d_v_spin.set_value(m_cfg.d_v)
            self.m2101_n_h_spin.set_value(m_cfg.n_h)
            self.m2101_n_v_spin.set_value(m_cfg.n_v)
        elif model == _ANTENNA_MODEL_COLLAPSED:
            # Collapsed-beamforming has its own small set of defaults.
            self.collapsed_baseline_edit.set_value(-55.6)
            self.collapsed_eval_freq_edit.set_value(2695.0)
            self.collapsed_ref_freq_edit.set_value(2000.0)
        elif model == _ANTENNA_MODEL_ISOTROPIC:
            # Isotropic has no tunable parameters — just reset UEMR mode.
            blocker_iso = QtCore.QSignalBlocker(self.isotropic_uemr_checkbox)
            self.isotropic_uemr_checkbox.setChecked(False)
            del blocker_iso

        self._sync_rf_panel()
        self._on_state_changed()

